// server/_vercel/_messagePools.ts
function pickByDay(arr, offset = 0) {
  if (arr.length === 0) throw new Error("Empty pool");
  const day = Math.floor(Date.now() / (1e3 * 60 * 60 * 24));
  return arr[(day + offset) % arr.length];
}
