      original: "03_DeFi_Samjhein.png",
      headline: "\u{1F537} DeFi \u0915\u094B \u0938\u092E\u091D\u0947\u0902",
      caption: "\u{1F537} DeFi \u0915\u094B \u0938\u092E\u091D\u0947\u0902\n\u2726 Decentralized Finance \u2014 \u0935\u0939 \u0915\u094D\u0930\u093E\u0902\u0924\u093F \u091C\u094B \u092C\u093F\u091A\u094C\u0932\u093F\u092F\u094B\u0902 \u0915\u094B \u0916\u0924\u094D\u092E \u0915\u0930\u0924\u0940 \u0939\u0948\n\nDecentralized Finance \u2014 \u092F\u093E DeFi \u2014 \u0927\u0928 \u0915\u0947 \u0907\u0924\u093F\u0939\u093E\u0938 \u092E\u0947\u0902 \u0938\u092C\u0938\u0947 \u092C\u0921\u093C\u093E \u0914\u0930 \u092A\u0930\u093F\u0935\u0930\u094D\u0924\u0928\u0915\u093E\u0930\u0940 \u092C\u0926\u0932\u093E\u0935 \u0939\u0948\u0964 \u092C\u0902\u0926 \u0926\u0930\u0935\u093E\u091C\u094B\u0902 \u0915\u0947 \u092A\u0940\u091B\u0947 \u0915\u093E\u092E \u0915\u0930\u0928\u0947 \u0935\u093E\u0932\u0947 \u092C\u0948\u0902\u0915\u094B\u0902, \u0926\u0932\u093E\u0932\u094B\u0902 \u0914\u0930 \u0935\u093F\u0924\u094D\u0924\u0940\u092F \u0938\u0902\u0938\u094D\u0925\u093E\u0928\u094B\u0902 \u092A\u0930 \u0928\u093F\u0930\u094D\u092D\u0930 \u0930\u0939\u0928\u0947 \u0915\u0947 \u092C\u091C\u093E\u092F, DeFi \u092A\u094D\u0930\u094B\u091F\u094B\u0915\u0949\u0932 \u0935\u093F\u0924\u094D\u0924\u0940\u092F \u0932\u0947\u0928\u0926\u0947\u0928 \u0915\u094B \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924, \u092A\u093E\u0930\u0926\u0930\u094D\u0936\u0940 \u0914\u0930 \u092C\u093F\u0928\u093E \u0915\u093F\u0938\u0940 \u092A\u094D\u0930\u093E\u0927\u093F\u0915\u0930\u0923 \u0915\u0940 \u0905\u0928\u0941\u092E\u0924\u093F \u0915\u0947 \u0928\u093F\u0937\u094D\u092A\u093E\u0926\u093F\u0924 \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u092C\u094D\u0932\u0949\u0915\u091A\u0947\u0928 \u092A\u0930 Smart Contract \u0915\u093E \u0909\u092A\u092F\u094B\u0917 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 \u0907\u0938\u092E\u0947\u0902 \u0915\u094B\u0908 \u0915\u093E\u0930\u094D\u092F\u093E\u0932\u092F \u0938\u092E\u092F \u0928\u0939\u0940\u0902 \u0939\u0948, \u0915\u094B\u0908 \u0905\u0928\u0941\u092E\u094B\u0926\u0928 \u092A\u094D\u0930\u0915\u094D\u0930\u093F\u092F\u093E \u0928\u0939\u0940\u0902 \u0939\u0948, \u0914\u0930 \u0915\u094B\u0908 \u092D\u094C\u0917\u094B\u0932\u093F\u0915 \u092A\u094D\u0930\u0924\u093F\u092C\u0902\u0927 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 DeFi \u0938\u093E\u0932 \u0915\u0947 365 \u0926\u093F\u0928, 24/7 \u0915\u093E\u092E \u0915\u0930\u0924\u093E \u0939\u0948, \u0914\u0930 \u0907\u0902\u091F\u0930\u0928\u0947\u091F \u0915\u0928\u0947\u0915\u094D\u0936\u0928 \u0935 \u0915\u094D\u0930\u093F\u092A\u094D\u091F\u094B \u0935\u0949\u0932\u0947\u091F \u0935\u093E\u0932\u0947 \u0915\u093F\u0938\u0940 \u092D\u0940 \u0935\u094D\u092F\u0915\u094D\u0924\u093F \u0915\u0947 \u0932\u093F\u090F \u0938\u0941\u0932\u092D \u0939\u0948\u0964 TurboLoop \u0907\u0938 \u0915\u094D\u0930\u093E\u0902\u0924\u093F\u0915\u093E\u0930\u0940 \u0924\u0915\u0928\u0940\u0915 \u0915\u093E \u0909\u092A\u092F\u094B\u0917 \u0915\u0930\u0915\u0947 \u0906\u092A\u0915\u0947 \u0935\u0949\u0932\u0947\u091F \u092E\u0947\u0902 \u0938\u0940\u0927\u0947 \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0926\u0948\u0928\u093F\u0915 \u0930\u093F\u091F\u0930\u094D\u0928 \u092A\u094D\u0930\u0926\u093E\u0928 \u0915\u0930\u0924\u093E \u0939\u0948 \u2014 \u0915\u094B\u0908 \u092C\u093F\u091A\u094C\u0932\u093F\u092F\u093E \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u0926\u0947\u0930\u0940 \u0928\u0939\u0940\u0902, \u0914\u0930 \u0915\u093F\u0938\u0940 \u092A\u0930 \u092D\u0930\u094B\u0938\u093E \u0915\u0930\u0928\u0947 \u0915\u0940 \u0906\u0935\u0936\u094D\u092F\u0915\u0924\u093E \u0928\u0939\u0940\u0902\u0964 \u0915\u0947\u0935\u0932 \u0915\u094B\u0921 \u092C\u093F\u0932\u094D\u0915\u0941\u0932 \u0935\u0948\u0938\u0947 \u0939\u0940 \u0915\u093E\u092E \u0915\u0930\u0924\u093E \u0939\u0948 \u091C\u0948\u0938\u093E \u0932\u093F\u0916\u093E \u0917\u092F\u093E \u0939\u0948, \u091C\u094B \u092C\u094D\u0932\u0949\u0915\u091A\u0947\u0928 \u092A\u0930 \u0939\u0930 \u0915\u093F\u0938\u0940 \u0915\u0947 \u0932\u093F\u090F \u0926\u0943\u0936\u094D\u092F\u092E\u093E\u0928 \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 \u0915\u094B\u0908 \u092C\u0948\u0902\u0915 \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u092C\u093F\u091A\u094C\u0932\u093F\u092F\u093E \u0928\u0939\u0940\u0902 \u2014 Smart Contract \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u0915\u093E\u092E \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\n\u2022 \u092C\u094D\u0932\u0949\u0915\u091A\u0947\u0928 \u092A\u0930 \u092A\u093E\u0930\u0926\u0930\u094D\u0936\u0940 \u2014 \u0939\u0930 \u0932\u0947\u0928\u0926\u0947\u0928 \u0915\u094B \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u0915\u093F\u092F\u093E \u091C\u093E \u0938\u0915\u0924\u093E \u0939\u0948\n\u2022 \u0935\u093F\u0936\u094D\u0935 \u0938\u094D\u0924\u0930 \u092A\u0930 \u0938\u0941\u0932\u092D \u2014 \u0915\u094B\u0908 \u092D\u094C\u0917\u094B\u0932\u093F\u0915 \u0938\u0940\u092E\u093E \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u0915\u093E\u0930\u094D\u092F\u093E\u0932\u092F \u0938\u092E\u092F \u0928\u0939\u0940\u0902\n\u2022 \u0905\u0928\u0941\u092E\u0924\u093F \u0930\u0939\u093F\u0924 \u2014 \u0915\u093F\u0938\u0940 \u0905\u0928\u0941\u092E\u094B\u0926\u0928 \u0915\u0940 \u0906\u0935\u0936\u094D\u092F\u0915\u0924\u093E \u0928\u0939\u0940\u0902, \u0905\u092A\u0928\u093E \u0935\u0949\u0932\u0947\u091F \u0915\u0928\u0947\u0915\u094D\u091F \u0915\u0930\u0947\u0902 \u0914\u0930 \u0936\u0941\u0930\u0941\u0906\u0924 \u0915\u0930\u0947\u0902\n\u2022 24/7 \u0938\u0902\u091A\u093E\u0932\u0928 \u2014 \u092C\u094D\u0932\u0949\u0915\u091A\u0947\u0928 \u0915\u092D\u0940 \u0928\u0939\u0940\u0902 \u0938\u094B\u0924\u093E, \u0914\u0930 \u0928 \u0939\u0940 \u0906\u092A\u0915\u0940 \u0915\u092E\u093E\u0908\n\n\u{1F48E} \u0935\u093F\u0924\u094D\u0924 \u0915\u0947 \u092D\u0935\u093F\u0937\u094D\u092F \u092E\u0947\u0902 \u0906\u092A\u0915\u093E \u0938\u094D\u0935\u093E\u0917\u0924 \u0939\u0948\u0964 DeFi \u092E\u0947\u0902 \u0906\u092A\u0915\u093E \u0938\u094D\u0935\u093E\u0917\u0924 \u0939\u0948\u0964\n\n\u{1F310} turboloop.io",
