      headline: "\u{1F537} \u0935\u0949\u0932\u0947\u091F \u0938\u0947\u091F\u0905\u092A \u0917\u093E\u0907\u0921",
      caption: "\u{1F537} \u0935\u0949\u0932\u0947\u091F \u0938\u0947\u091F\u0905\u092A \u0917\u093E\u0907\u0921\n\u2726 TurboLoop \u0915\u093E \u0906\u092A\u0915\u093E \u092A\u094D\u0930\u0935\u0947\u0936 \u0926\u094D\u0935\u093E\u0930 \u2014 5 \u092E\u093F\u0928\u091F \u0938\u0947 \u0915\u092E \u0938\u092E\u092F \u092E\u0947\u0902 \u0938\u0947\u091F\u0905\u092A \u0915\u0930\u0947\u0902\n\nTurboLoop \u0915\u0947 \u0938\u093E\u0925 \u0936\u0941\u0930\u0941\u0906\u0924 \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u090F\u0915 \u0915\u094D\u0930\u093F\u092A\u094D\u091F\u094B \u0935\u0949\u0932\u0947\u091F \u0938\u0947\u091F \u0915\u0930\u0928\u093E \u0939\u094B\u0924\u093E \u0939\u0948 \u2014 \u091C\u094B \u0935\u093F\u0915\u0947\u0902\u0926\u094D\u0930\u0940\u0915\u0943\u0924 \u0926\u0941\u0928\u093F\u092F\u093E \u0915\u0947 \u0932\u093F\u090F \u0906\u092A\u0915\u093E \u0935\u094D\u092F\u0915\u094D\u0924\u093F\u0917\u0924 \u092A\u094D\u0930\u0935\u0947\u0936 \u0926\u094D\u0935\u093E\u0930 \u0939\u0948\u0964 MetaMask (\u092C\u094D\u0930\u093E\u0909\u091C\u093C\u0930 \u090F\u0915\u094D\u0938\u091F\u0947\u0902\u0936\u0928 \u092F\u093E \u092E\u094B\u092C\u093E\u0907\u0932 \u0910\u092A) \u092F\u093E Trust Wallet (\u092E\u094B\u092C\u093E\u0907\u0932) \u0921\u093E\u0909\u0928\u0932\u094B\u0921 \u0915\u0930\u0947\u0902, \u0914\u0930 \u090F\u0915 \u0928\u092F\u093E \u0935\u0949\u0932\u0947\u091F \u092C\u0928\u093E\u090F\u0902\u0964 \u0938\u092C\u0938\u0947 \u092E\u0939\u0924\u094D\u0935\u092A\u0942\u0930\u094D\u0923 \u0915\u0926\u092E: \u0905\u092A\u0928\u0947 \u0938\u0940\u0921 \u092B\u094D\u0930\u0947\u091C\u093C \u0915\u094B \u0938\u0941\u0930\u0915\u094D\u0937\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u0911\u092B\u093C\u0932\u093E\u0907\u0928 \u0938\u0939\u0947\u091C\u0947\u0902\u0964 \u092F\u0939 12 \u092F\u093E 24-\u0936\u092C\u094D\u0926\u094B\u0902 \u0915\u093E \u0935\u093E\u0915\u094D\u092F\u093E\u0902\u0936 \u0906\u092A\u0915\u0940 \u092E\u093E\u0938\u094D\u091F\u0930 \u0915\u0941\u0902\u091C\u0940 \u0939\u0948 \u2014 \u0907\u0938\u0947 \u0916\u094B \u0926\u0947\u0902, \u0914\u0930 \u0906\u092A \u0939\u092E\u0947\u0936\u093E \u0915\u0947 \u0932\u093F\u090F \u0905\u092A\u0928\u0947 \u092B\u0902\u0921 \u0924\u0915 \u092A\u0939\u0941\u0902\u091A \u0916\u094B \u0926\u0947\u0902\u0917\u0947\u0964 \u090F\u0915 \u092C\u093E\u0930 \u0906\u092A\u0915\u093E \u0935\u0949\u0932\u0947\u091F \u092C\u0928 \u091C\u093E\u0928\u0947 \u0915\u0947 \u092C\u093E\u0926, Binance Smart Chain (BSC) \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u091C\u094B\u0921\u093C\u0947\u0902\u0964 \u092B\u093F\u0930 \u0905\u092A\u0928\u0947 \u0935\u0949\u0932\u0947\u091F \u092E\u0947\u0902 \u0925\u094B\u0921\u093C\u0940 \u092E\u093E\u0924\u094D\u0930\u093E \u092E\u0947\u0902 BNB (\u0917\u0948\u0938 \u092B\u0940\u0938 \u0915\u0947 \u0932\u093F\u090F) \u0914\u0930 \u0935\u0939 USDT \u0921\u093E\u0932\u0947\u0902 \u091C\u093F\u0938\u0947 \u0906\u092A \u091C\u092E\u093E \u0915\u0930\u0928\u093E \u091A\u093E\u0939\u0924\u0947 \u0939\u0948\u0902\u0964 \u092C\u0938 \u0907\u0924\u0928\u093E \u0939\u0940\u0964 \u0915\u094B\u0908 \u092A\u0902\u091C\u0940\u0915\u0930\u0923 \u092B\u0949\u0930\u094D\u092E \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u092A\u0939\u091A\u093E\u0928 \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u092A\u094D\u0930\u0924\u0940\u0915\u094D\u0937\u093E \u0905\u0935\u0927\u093F \u0928\u0939\u0940\u0902\u0964 \u0906\u092A\u0915\u093E \u0935\u0949\u0932\u0947\u091F \u0939\u0940 \u0906\u092A\u0915\u093E \u0916\u093E\u0924\u093E \u0939\u0948, \u0906\u092A\u0915\u0940 \u092A\u0939\u091A\u093E\u0928 \u0939\u0948, \u0914\u0930 TurboLoop \u0915\u0940 \u0906\u092A\u0915\u0940 \u0915\u0941\u0902\u091C\u0940 \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 MetaMask \u092F\u093E Trust Wallet \u0921\u093E\u0909\u0928\u0932\u094B\u0921 \u0915\u0930\u0947\u0902 \u2014 \u092E\u0941\u092B\u093C\u094D\u0924, 2 \u092E\u093F\u0928\u091F \u0932\u0917\u0924\u0947 \u0939\u0948\u0902\n\u2022 \u0905\u092A\u0928\u0947 \u0938\u0940\u0921 \u092B\u094D\u0930\u0947\u091C\u093C \u0915\u094B \u0938\u0941\u0930\u0915\u094D\u0937\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u0911\u092B\u093C\u0932\u093E\u0907\u0928 \u0938\u0939\u0947\u091C\u0947\u0902 \u2014 \u092F\u0939 \u0906\u092A\u0915\u0940 \u092E\u093E\u0938\u094D\u091F\u0930 \u0915\u0941\u0902\u091C\u0940 \u0939\u0948\n\u2022 TurboLoop \u0938\u0902\u0917\u0924\u0924\u093E \u0915\u0947 \u0932\u093F\u090F \u0905\u092A\u0928\u0947 \u0935\u0949\u0932\u0947\u091F \u092E\u0947\u0902 BSC \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u091C\u094B\u0921\u093C\u0947\u0902\n\u2022 BNB (\u0917\u0948\u0938 \u092B\u0940\u0938 \u0915\u0947 \u0932\u093F\u090F) \u0914\u0930 USDT (\u091C\u092E\u093E \u0915\u0947 \u0932\u093F\u090F) \u0915\u0947 \u0938\u093E\u0925 \u092B\u0902\u0921 \u0915\u0930\u0947\u0902\n\u2022 \u0915\u094B\u0908 \u092A\u0902\u091C\u0940\u0915\u0930\u0923 \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 KYC \u0928\u0939\u0940\u0902 \u2014 \u0906\u092A\u0915\u093E \u0935\u0949\u0932\u0947\u091F \u0939\u0940 \u0906\u092A\u0915\u093E \u0916\u093E\u0924\u093E \u0939\u0948\n\n\u{1F48E} \u0906\u092A\u0915\u093E \u0935\u0949\u0932\u0947\u091F \u0906\u092A\u0915\u093E \u092A\u094D\u0930\u0935\u0947\u0936 \u0926\u094D\u0935\u093E\u0930 \u0939\u0948\u0964 \u0907\u0938\u0947 \u0938\u0947\u091F \u0915\u0930\u0947\u0902\u0964 \u0915\u092E\u093E\u0908 \u0936\u0941\u0930\u0942 \u0915\u0930\u0947\u0902\u0964\n\n\u{1F310} turboloop.io",
