      headline: "\u{1F537} \u0936\u0941\u0930\u0941\u0906\u0924 \u0915\u0930\u0947\u0902",
      caption: "\u{1F537} \u0936\u0941\u0930\u0941\u0906\u0924 \u0915\u0930\u0947\u0902\n\u2726 \u0936\u0942\u0928\u094D\u092F \u0938\u0947 \u0915\u092E\u093E\u0908 \u0924\u0915 7 \u0906\u0938\u093E\u0928 \u091A\u0930\u0923\u094B\u0902 \u092E\u0947\u0902\n\nTurboLoop \u0915\u0947 \u0938\u093E\u0925 \u0936\u0941\u0930\u0941\u0906\u0924 \u0915\u0930\u0928\u093E \u092C\u0947\u0939\u0926 \u0906\u0938\u093E\u0928 \u092C\u0928\u093E\u092F\u093E \u0917\u092F\u093E \u0939\u0948 \u2014 \u0915\u093F\u0938\u0940 \u0924\u0915\u0928\u0940\u0915\u0940 \u0935\u093F\u0936\u0947\u0937\u091C\u094D\u091E\u0924\u093E \u0915\u0940 \u0906\u0935\u0936\u094D\u092F\u0915\u0924\u093E \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u091A\u0930\u0923 1: \u090F\u0915 \u0915\u094D\u0930\u093F\u092A\u094D\u091F\u094B \u0935\u0949\u0932\u0947\u091F (MetaMask \u092F\u093E Trust Wallet) \u0938\u0947\u091F \u0915\u0930\u0947\u0902\u0964 \u091A\u0930\u0923 2: \u0915\u093F\u0938\u0940 \u090F\u0915\u094D\u0938\u091A\u0947\u0902\u091C \u092F\u093E \u091F\u0930\u094D\u092C\u094B \u092C\u093E\u092F \u0915\u0947 \u092E\u093E\u0927\u094D\u092F\u092E \u0938\u0947 BSC \u092A\u0930 USDT \u0916\u0930\u0940\u0926\u0947\u0902\u0964 \u091A\u0930\u0923 3: turboloop.io \u092A\u0930 \u091C\u093E\u090F\u0902\u0964 \u091A\u0930\u0923 4: \u090F\u0915 \u0915\u094D\u0932\u093F\u0915 \u0915\u0947 \u0938\u093E\u0925 \u0905\u092A\u0928\u093E \u0935\u0949\u0932\u0947\u091F \u0915\u0928\u0947\u0915\u094D\u091F \u0915\u0930\u0947\u0902\u0964 \u091A\u0930\u0923 5: \u0905\u092A\u0928\u093E \u0928\u093F\u0935\u0947\u0936 \u092A\u094D\u0932\u093E\u0928 \u091A\u0941\u0928\u0947\u0902 \u2014 Sprint (3%/7d), Boost (10%/14d), Power (24%/30d), \u092F\u093E Ultimate (54%/60d)\u0964 \u091A\u0930\u0923 6: \u0905\u092A\u0928\u093E USDT \u091C\u092E\u093E \u0915\u0930\u0947\u0902 (\u0928\u094D\u092F\u0942\u0928\u0924\u092E $1, \u0915\u094B\u0908 \u0905\u0927\u093F\u0915\u0924\u092E \u0938\u0940\u092E\u093E \u0928\u0939\u0940\u0902)\u0964 \u091A\u0930\u0923 7: \u0905\u092A\u0928\u0940 \u0915\u092E\u093E\u0908 \u0915\u094B \u092A\u094D\u0930\u0924\u093F\u0926\u093F\u0928 \u092C\u0922\u093C\u0924\u0947 \u0939\u0941\u090F \u0926\u0947\u0916\u0947\u0902\u0964 \u092A\u0942\u0930\u0940 \u092A\u094D\u0930\u0915\u094D\u0930\u093F\u092F\u093E \u092E\u0947\u0902 10 \u092E\u093F\u0928\u091F \u0938\u0947 \u092D\u0940 \u0915\u092E \u0938\u092E\u092F \u0932\u0917\u0924\u093E \u0939\u0948, \u0914\u0930 \u090F\u0915 \u092C\u093E\u0930 \u0906\u092A\u0915\u093E \u0921\u093F\u092A\u0949\u091C\u093F\u091F \u0938\u0915\u094D\u0930\u093F\u092F \u0939\u094B \u091C\u093E\u0928\u0947 \u092A\u0930, Smart Contract \u0938\u092C \u0915\u0941\u091B \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u0938\u0902\u092D\u093E\u0932\u0924\u093E \u0939\u0948\u0964 \u0915\u094B\u0908 \u0926\u0948\u0928\u093F\u0915 \u0932\u0949\u0917\u093F\u0928 \u0906\u0935\u0936\u094D\u092F\u0915 \u0928\u0939\u0940\u0902\u0964 \u0915\u094B\u0908 \u092E\u0948\u0928\u094D\u092F\u0941\u0905\u0932 \u0915\u094D\u0932\u0947\u092E\u093F\u0902\u0917 \u0928\u0939\u0940\u0902\u0964 \u092C\u0938 \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0926\u0948\u0928\u093F\u0915 \u0930\u093F\u091F\u0930\u094D\u0928, \u091C\u093F\u0938\u0915\u0940 \u0917\u0923\u0928\u093E \u0915\u0940 \u091C\u093E\u0924\u0940 \u0939\u0948 \u0914\u0930 \u0939\u0930 24 \u0918\u0902\u091F\u0947 \u092E\u0947\u0902 \u0906\u092A\u0915\u0947 \u092C\u0948\u0932\u0947\u0902\u0938 \u092E\u0947\u0902 \u091C\u094B\u0921\u093C \u0926\u093F\u092F\u093E \u091C\u093E\u0924\u093E \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 \u0936\u0942\u0928\u094D\u092F \u0938\u0947 \u0915\u092E\u093E\u0908 \u0924\u0915 7 \u0906\u0938\u093E\u0928 \u091A\u0930\u0923 \u2014 \u0915\u093F\u0938\u0940 \u0924\u0915\u0928\u0940\u0915\u0940 \u0935\u093F\u0936\u0947\u0937\u091C\u094D\u091E\u0924\u093E \u0915\u0940 \u0906\u0935\u0936\u094D\u092F\u0915\u0924\u093E \u0928\u0939\u0940\u0902\n\u2022 \u0928\u094D\u092F\u0942\u0928\u0924\u092E \u0921\u093F\u092A\u0949\u091C\u093F\u091F: \u0915\u0947\u0935\u0932 $1 \u2014 \u0938\u092D\u0940 \u0915\u0947 \u0932\u093F\u090F \u0938\u0941\u0932\u092D\n\u2022 4 \u092A\u094D\u0932\u093E\u0928\u094D\u0938 \u092E\u0947\u0902 \u0938\u0947 \u091A\u0941\u0928\u0947\u0902: Sprint, Boost, Power, \u092F\u093E Ultimate\n\u2022 \u0921\u093F\u092A\u0949\u091C\u093F\u091F \u0915\u0947 \u092C\u093E\u0926 Smart Contract \u0938\u092C \u0915\u0941\u091B \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u0938\u0902\u092D\u093E\u0932\u0924\u093E \u0939\u0948\n\u2022 \u092A\u0942\u0930\u0947 \u0938\u0947\u091F\u0905\u092A \u092E\u0947\u0902 10 \u092E\u093F\u0928\u091F \u0938\u0947 \u092D\u0940 \u0915\u092E \u0938\u092E\u092F \u0932\u0917\u0924\u093E \u0939\u0948\n\n\u{1F48E} \u092E\u093F\u0928\u091F\u094B\u0902 \u092E\u0947\u0902 \u0915\u092E\u093E\u0908 \u0936\u0941\u0930\u0942 \u0915\u0930\u0947\u0902\u0964 \u0932\u0942\u092A \u0906\u092A\u0915\u093E \u0907\u0902\u0924\u091C\u093E\u0930 \u0915\u0930 \u0930\u0939\u093E \u0939\u0948\u0964\n\n\u{1F310} turboloop.io",
