      original: "12_Chaar_Yojnayein.png",
      headline: "\u{1F537} \u091A\u093E\u0930 \u0928\u093F\u0935\u0947\u0936 \u092F\u094B\u091C\u0928\u093E\u090F\u0902",
      caption: "\u{1F537} \u091A\u093E\u0930 \u0928\u093F\u0935\u0947\u0936 \u092F\u094B\u091C\u0928\u093E\u090F\u0902\n\u2726 \u0924\u094D\u0935\u0930\u093F\u0924 \u0938\u094D\u092A\u094D\u0930\u093F\u0902\u091F \u0938\u0947 \u0932\u0947\u0915\u0930 \u0905\u0902\u0924\u093F\u092E \u0930\u093F\u091F\u0930\u094D\u0928 \u0924\u0915 \u2014 \u0905\u092A\u0928\u093E \u0930\u093E\u0938\u094D\u0924\u093E \u091A\u0941\u0928\u0947\u0902\n\nTurboLoop \u091A\u093E\u0930 \u0938\u093E\u0935\u0927\u093E\u0928\u0940\u092A\u0942\u0930\u094D\u0935\u0915 \u0921\u093F\u091C\u093C\u093E\u0907\u0928 \u0915\u0940 \u0917\u0908 \u0928\u093F\u0935\u0947\u0936 \u092F\u094B\u091C\u0928\u093E\u090F\u0902 \u092A\u094D\u0930\u0926\u093E\u0928 \u0915\u0930\u0924\u093E \u0939\u0948, \u091C\u093F\u0928\u092E\u0947\u0902 \u0938\u0947 \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 \u0915\u094B \u0935\u093F\u092D\u093F\u0928\u094D\u0928 \u0930\u0923\u0928\u0940\u0924\u093F\u092F\u094B\u0902 \u0914\u0930 \u0938\u092E\u092F-\u0938\u0940\u092E\u093E\u0913\u0902 \u0915\u0947 \u0932\u093F\u090F \u0915\u0948\u0932\u093F\u092C\u094D\u0930\u0947\u091F \u0915\u093F\u092F\u093E \u0917\u092F\u093E \u0939\u0948\u0964 Sprint Loop \u0915\u0947\u0935\u0932 7 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 3% \u092A\u094D\u0930\u0926\u093E\u0928 \u0915\u0930\u0924\u093E \u0939\u0948 \u2014 \u0936\u0941\u0930\u0941\u0906\u0924 \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u090F\u0915\u0926\u092E \u0938\u0939\u0940\u0964 Boost Loop \u0909\u0928 \u0932\u094B\u0917\u094B\u0902 \u0915\u0947 \u0932\u093F\u090F 14 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 10% \u0924\u0915 \u0917\u0924\u093F \u092C\u0922\u093C\u093E\u0924\u093E \u0939\u0948 \u091C\u094B \u092A\u094D\u0930\u0924\u093F\u092C\u0926\u094D\u0927 \u0939\u094B\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u0924\u0948\u092F\u093E\u0930 \u0939\u0948\u0902\u0964 Power Loop 30 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 24% \u091C\u093E\u0930\u0940 \u0915\u0930\u0924\u093E \u0939\u0948 \u2014 \u0917\u0902\u092D\u0940\u0930 \u0928\u093F\u0935\u0947\u0936\u0915\u094B\u0902 \u0915\u0947 \u0932\u093F\u090F \u0938\u092C\u0938\u0947 \u092C\u0947\u0939\u0924\u0930\u0940\u0928 \u0935\u093F\u0915\u0932\u094D\u092A\u0964 \u0914\u0930 Ultimate Loop, \u091C\u094B \u0938\u092C\u0938\u0947 \u092A\u094D\u0930\u092E\u0941\u0916 \u0939\u0948, 60 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 54% \u0915\u093E \u092D\u093E\u0930\u0940 \u0930\u093F\u091F\u0930\u094D\u0928 \u0926\u0947\u0924\u093E \u0939\u0948\u0964 \u0939\u0930 \u092F\u094B\u091C\u0928\u093E \u092C\u093F\u0928\u093E \u0915\u093F\u0938\u0940 \u0905\u0927\u093F\u0915\u0924\u092E \u0938\u0940\u092E\u093E \u0915\u0947 \u0915\u0947\u0935\u0932 $1 \u0938\u0947 \u0936\u0941\u0930\u0942 \u0939\u094B\u0924\u0940 \u0939\u0948\u0964 \u0930\u093F\u091F\u0930\u094D\u0928 \u0915\u0940 \u0917\u0923\u0928\u093E \u0914\u0930 \u0935\u093F\u0924\u0930\u0923 Smart Contract \u0926\u094D\u0935\u093E\u0930\u093E \u092A\u094D\u0930\u0924\u093F\u0926\u093F\u0928 \u0915\u093F\u092F\u093E \u091C\u093E\u0924\u093E \u0939\u0948\u0964 \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 \u091A\u0915\u094D\u0930 \u0915\u0947 \u0905\u0902\u0924 \u092E\u0947\u0902, \u0906\u092A\u0915\u0940 \u092A\u0942\u0930\u0940 \u092A\u0942\u0902\u091C\u0940 \u0906\u092A\u0915\u0947 \u0938\u0902\u091A\u093F\u0924 \u0932\u093E\u092D \u0915\u0947 \u0938\u093E\u0925 \u0935\u093E\u092A\u0938 \u0915\u0930 \u0926\u0940 \u091C\u093E\u0924\u0940 \u0939\u0948\u0964 \u091A\u093E\u0939\u0947 \u0906\u092A \u090F\u0915 \u0938\u0924\u0930\u094D\u0915 \u0936\u0941\u0930\u0941\u0906\u0924\u0940 \u0939\u094B\u0902 \u092F\u093E \u090F\u0915 \u0906\u0915\u094D\u0930\u093E\u092E\u0915 \u0932\u093E\u092D \u091A\u093E\u0939\u0928\u0947 \u0935\u093E\u0932\u0947, \u0906\u092A\u0915\u0947 \u0932\u093F\u090F \u092C\u093F\u0932\u094D\u0915\u0941\u0932 \u0938\u0939\u0940 \u090F\u0915 \u0932\u0942\u092A \u0921\u093F\u091C\u093C\u093E\u0907\u0928 \u0915\u093F\u092F\u093E \u0917\u092F\u093E \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 Sprint Loop: 7 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 3% \u0930\u093F\u091F\u0930\u094D\u0928 (~0.43% \u0926\u0948\u0928\u093F\u0915)\n\u2022 Boost Loop: 14 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 10% \u0930\u093F\u091F\u0930\u094D\u0928 (~0.71% \u0926\u0948\u0928\u093F\u0915)\n\u2022 Power Loop: 30 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 24% \u0930\u093F\u091F\u0930\u094D\u0928 (~0.8% \u0926\u0948\u0928\u093F\u0915)\n\u2022 Ultimate Loop: 60 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 54% \u0930\u093F\u091F\u0930\u094D\u0928 (~0.9% \u0926\u0948\u0928\u093F\u0915)\n\u2022 \u0938\u092D\u0940 \u092F\u094B\u091C\u0928\u093E\u090F\u0902: $1 \u0928\u094D\u092F\u0942\u0928\u0924\u092E, \u0915\u094B\u0908 \u0905\u0927\u093F\u0915\u0924\u092E \u0938\u0940\u092E\u093E \u0928\u0939\u0940\u0902, \u0926\u0948\u0928\u093F\u0915 \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0930\u093F\u091F\u0930\u094D\u0928\n\n\u{1F48E} \u091A\u093E\u0930 \u092F\u094B\u091C\u0928\u093E\u090F\u0902\u0964 \u090F\u0915 \u0932\u0915\u094D\u0937\u094D\u092F: \u0906\u092A\u0915\u0940 \u0935\u093F\u0924\u094D\u0924\u0940\u092F \u0935\u0943\u0926\u094D\u0927\u093F\u0964 \u0905\u092A\u0928\u093E \u0932\u0942\u092A \u091A\u0941\u0928\u0947\u0902\u0964\n\n\u{1F310} turboloop.io",
