      original: "14_Boost_Loop.png",
      headline: "\u{1F537} BOOST LOOP",
      caption: "\u{1F537} BOOST LOOP\n\u2726 14 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 10% \u2014 \u0905\u092A\u0928\u0940 \u0917\u094D\u0930\u094B\u0925 \u0915\u094B \u0924\u0947\u091C\u093C \u0915\u0930\u0947\u0902\n\nBoost Loop 14 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 10% \u0915\u0947 \u0915\u0941\u0932 \u0930\u093F\u091F\u0930\u094D\u0928 \u0915\u0947 \u0938\u093E\u0925 \u0906\u092A\u0915\u0940 \u0915\u092E\u093E\u0908 \u0915\u094B \u0905\u0917\u0932\u0947 \u0938\u094D\u0924\u0930 \u092A\u0930 \u0932\u0947 \u091C\u093E\u0924\u093E \u0939\u0948\u0964 \u0932\u0917\u092D\u0917 0.71% \u0926\u0948\u0928\u093F\u0915 \u0915\u0947 \u0938\u093E\u0925, \u092F\u0939 \u092A\u094D\u0932\u093E\u0928 \u0909\u0928 \u0928\u093F\u0935\u0947\u0936\u0915\u094B\u0902 \u0915\u0947 \u0932\u093F\u090F \u0921\u093F\u091C\u093C\u093E\u0907\u0928 \u0915\u093F\u092F\u093E \u0917\u092F\u093E \u0939\u0948 \u091C\u093F\u0928\u094D\u0939\u094B\u0902\u0928\u0947 Sprint \u0915\u0947 \u0938\u093E\u0925 \u0936\u0941\u0930\u0941\u0906\u0924 \u0915\u0940 \u0939\u0948 \u0914\u0930 \u0905\u092A\u0928\u0940 \u0917\u094D\u0930\u094B\u0925 \u0915\u094B \u0924\u0947\u091C\u093C \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u0924\u0948\u092F\u093E\u0930 \u0939\u0948\u0902\u0964 \u0907\u0938\u0915\u0940 \u0915\u093E\u0930\u094D\u092F\u092A\u094D\u0930\u0923\u093E\u0932\u0940 \u092C\u093F\u0932\u094D\u0915\u0941\u0932 \u0938\u092E\u093E\u0928 \u0939\u0948 \u2014 $1 \u0938\u0947 \u0921\u093F\u092A\u0949\u091C\u093F\u091F \u0915\u0930\u0947\u0902, Smart Contract \u0926\u094D\u0935\u093E\u0930\u093E \u0915\u0948\u0932\u0915\u0941\u0932\u0947\u091F \u0915\u093F\u090F \u0917\u090F \u0911\u091F\u094B\u092E\u0948\u091F\u093F\u0915 \u0926\u0948\u0928\u093F\u0915 \u0930\u093F\u091F\u0930\u094D\u0928 \u092A\u094D\u0930\u093E\u092A\u094D\u0924 \u0915\u0930\u0947\u0902, \u0914\u0930 \u0938\u093E\u0907\u0915\u093F\u0932 \u0915\u0947 \u0905\u0902\u0924 \u092E\u0947\u0902 \u0905\u092A\u0928\u093E \u092A\u0942\u0930\u093E \u0915\u0948\u092A\u093F\u091F\u0932 \u0914\u0930 \u091C\u092E\u093E \u0939\u0941\u0906 \u092F\u0940\u0932\u094D\u0921 \u092A\u094D\u0930\u093E\u092A\u094D\u0924 \u0915\u0930\u0947\u0902\u0964 14-\u0926\u093F\u0928 \u0915\u0940 \u0905\u0935\u0927\u093F \u0915\u092E\u093F\u091F\u092E\u0947\u0902\u091F \u0914\u0930 \u0930\u093F\u0935\u0949\u0930\u094D\u0921 \u0915\u0947 \u092C\u0940\u091A \u090F\u0915 \u092C\u0947\u0939\u0924\u0930\u0940\u0928 \u0938\u0902\u0924\u0941\u0932\u0928 \u092C\u0928\u093E\u0924\u0940 \u0939\u0948, \u091C\u094B \u0915\u0947\u0935\u0932 \u0926\u094B\u0917\u0941\u0928\u0947 \u0938\u092E\u092F \u092E\u0947\u0902 Sprint Loop \u0915\u0947 \u0930\u093F\u091F\u0930\u094D\u0928 \u0938\u0947 \u0924\u0940\u0928 \u0917\u0941\u0928\u093E \u0938\u0947 \u0905\u0927\u093F\u0915 \u0915\u0940 \u092A\u0947\u0936\u0915\u0936 \u0915\u0930\u0924\u0940 \u0939\u0948\u0964 \u091C\u094B \u0932\u094B\u0917 \u0930\u0940\u0907\u0928\u094D\u0935\u0947\u0938\u094D\u091F \u0915\u0930\u0928\u0947 \u0915\u0940 \u0936\u0915\u094D\u0924\u093F \u0915\u094B \u0938\u092E\u091D\u0924\u0947 \u0939\u0948\u0902, \u0909\u0928\u0915\u0947 \u0932\u093F\u090F \u092C\u093E\u0930-\u092C\u093E\u0930 \u0938\u093E\u0907\u0915\u093F\u0932 \u091A\u0932\u093E\u0928\u0947 \u092A\u0930 Boost Loop \u090F\u0915 \u0915\u0902\u092A\u093E\u0909\u0902\u0921\u093F\u0902\u0917 \u092E\u0936\u0940\u0928 \u092C\u0928 \u091C\u093E\u0924\u093E \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0939\u093E\u0907\u0932\u093E\u0907\u091F\u094D\u0938:\n\u2022 \u0915\u0941\u0932 \u0930\u093F\u091F\u0930\u094D\u0928: 14 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 10%\n\u2022 \u0926\u0948\u0928\u093F\u0915 \u092F\u0940\u0932\u094D\u0921: \u0932\u0917\u092D\u0917 0.71% \u092A\u094D\u0930\u0924\u093F\u0926\u093F\u0928\n\u2022 \u0915\u0947\u0935\u0932 2x \u0938\u092E\u092F \u092E\u0947\u0902 Sprint \u0915\u0947 \u0930\u093F\u091F\u0930\u094D\u0928 \u0915\u093E 3x \u0938\u0947 \u0905\u0927\u093F\u0915\n\u2022 \u0928\u094D\u092F\u0942\u0928\u0924\u092E \u0921\u093F\u092A\u0949\u091C\u093F\u091F: $1 \u2014 \u0915\u094B\u0908 \u0905\u0927\u093F\u0915\u0924\u092E \u0938\u0940\u092E\u093E \u0928\u0939\u0940\u0902\n\u2022 \u0938\u093E\u0907\u0915\u093F\u0932 \u0926\u0930 \u0938\u093E\u0907\u0915\u093F\u0932 \u0930\u0940\u0907\u0928\u094D\u0935\u0947\u0938\u094D\u091F \u0915\u0930\u0928\u0947 \u092A\u0930 \u0915\u0902\u092A\u093E\u0909\u0902\u0921\u093F\u0902\u0917 \u0915\u0947 \u0932\u093F\u090F \u090F\u0915\u0926\u092E \u0938\u0939\u0940\n\n\u{1F48E} \u0905\u092A\u0928\u0940 \u0917\u094D\u0930\u094B\u0925 \u0915\u094B \u0924\u0947\u091C\u093C \u0915\u0930\u0947\u0902\u0964 \u0905\u092A\u0928\u0947 \u092D\u0935\u093F\u0937\u094D\u092F \u0915\u094B \u092C\u0942\u0938\u094D\u091F \u0915\u0930\u0947\u0902\u0964 \u0932\u0942\u092A \u092E\u0947\u0902 \u092A\u094D\u0930\u0935\u0947\u0936 \u0915\u0930\u0947\u0902\u0964\n\n\u{1F310} turboloop.io",
