      original: "20_Teen_Aay_Srot.png",
      headline: "\u{1F537} \u0924\u0940\u0928 \u0906\u092F \u0938\u094D\u0930\u094B\u0924",
      caption: "\u{1F537} \u0924\u0940\u0928 \u0906\u092F \u0938\u094D\u0930\u094B\u0924\n\u2726 \u092A\u094D\u0932\u093E\u0928 \u092F\u0940\u0932\u094D\u0921 + \u0930\u0947\u092B\u0930\u0932 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 + \u0932\u0940\u0921\u0930\u0936\u093F\u092A \u092C\u094B\u0928\u0938 = \u0905\u0927\u093F\u0915\u0924\u092E \u0915\u092E\u093E\u0908\n\nTurboLoop \u0906\u092A\u0915\u094B \u0906\u092F \u0915\u0947 \u090F\u0915 \u0939\u0940 \u0938\u094D\u0930\u094B\u0924 \u0924\u0915 \u0938\u0940\u092E\u093F\u0924 \u0928\u0939\u0940\u0902 \u0930\u0916\u0924\u093E \u0939\u0948 \u2014 \u092F\u0939 \u0906\u092A\u0915\u094B \u090F\u0915 \u0938\u093E\u0925 \u0915\u093E\u092E \u0915\u0930\u0928\u0947 \u0935\u093E\u0932\u0947 \u0924\u0940\u0928 \u0936\u0915\u094D\u0924\u093F\u0936\u093E\u0932\u0940 \u0907\u0902\u091C\u0928 \u0926\u0947\u0924\u093E \u0939\u0948\u0964 \u0907\u0902\u091C\u0928 1: \u092A\u094D\u0932\u093E\u0928 \u092F\u0940\u0932\u094D\u0921 \u0906\u092A\u0915\u0947 \u091A\u0941\u0928\u0947 \u0939\u0941\u090F \u092A\u094D\u0932\u093E\u0928 \u0915\u0947 \u0906\u0927\u093E\u0930 \u092A\u0930 3% \u0938\u0947 54% \u0924\u0915 \u0930\u093F\u091F\u0930\u094D\u0928 \u0926\u0947\u0924\u093E \u0939\u0948, \u091C\u093F\u0938\u0915\u0940 \u0917\u0923\u0928\u093E \u0914\u0930 \u0935\u093F\u0924\u0930\u0923 \u092A\u094D\u0930\u0924\u093F\u0926\u093F\u0928 Smart Contract \u0926\u094D\u0935\u093E\u0930\u093E \u0915\u093F\u092F\u093E \u091C\u093E\u0924\u093E \u0939\u0948\u0964 \u0907\u0902\u091C\u0928 2: 20-\u0932\u0947\u0935\u0932 \u0930\u0947\u092B\u0930\u0932 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0906\u092A\u0915\u0947 \u092A\u0942\u0930\u0947 \u0921\u093E\u0909\u0928\u0932\u093E\u0907\u0928 \u092E\u0947\u0902 \u0938\u0902\u0926\u0930\u094D\u092D\u093F\u0924 \u091C\u092E\u093E \u0915\u093E 51% \u0935\u093F\u0924\u0930\u093F\u0924 \u0915\u0930\u0924\u093E \u0939\u0948 \u2014 \u0905\u092A\u0928\u093E \u0932\u093F\u0902\u0915 \u0938\u093E\u091D\u093E \u0915\u0930\u0947\u0902 \u0914\u0930 \u0905\u092A\u0928\u0947 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0915\u0947 \u092E\u093E\u0927\u094D\u092F\u092E \u0938\u0947 \u091C\u0941\u0921\u093C\u0928\u0947 \u0935\u093E\u0932\u0947 \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 \u0938\u0926\u0938\u094D\u092F \u0938\u0947 20 \u0938\u094D\u0924\u0930\u094B\u0902 \u0924\u0915 \u0917\u0939\u0930\u093E\u0908 \u0924\u0915 \u0915\u092E\u093E\u090F\u0902\u0964 \u0907\u0902\u091C\u0928 3: \u0932\u0940\u0921\u0930\u0936\u093F\u092A \u092C\u094B\u0928\u0938 \u0915\u092E\u094D\u092F\u0941\u0928\u093F\u091F\u0940 \u092C\u093F\u0932\u094D\u0921\u0930\u094D\u0938 \u0915\u094B \u0906\u092A\u0915\u0947 \u0930\u0948\u0902\u0915 \u0915\u0947 \u0906\u0927\u093E\u0930 \u092A\u0930 \u0905\u0924\u093F\u0930\u093F\u0915\u094D\u0924 1% \u0938\u0947 10% \u0924\u0915 \u092A\u0941\u0930\u0938\u094D\u0915\u0943\u0924 \u0915\u0930\u0924\u093E \u0939\u0948 \u2014 \u092A\u093E\u0930\u094D\u091F\u0928\u0930 \u0938\u0947 \u0932\u0947\u0915\u0930 \u0926\u093F\u0917\u094D\u0917\u091C TURBO LEGEND \u091F\u093F\u092F\u0930 \u0924\u0915\u0964 \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 \u0907\u0902\u091C\u0928 \u0938\u094D\u0935\u0924\u0902\u0924\u094D\u0930 \u0930\u0942\u092A \u0938\u0947 \u0915\u093E\u092E \u0915\u0930\u0924\u093E \u0939\u0948, \u091C\u093F\u0938\u0915\u093E \u0905\u0930\u094D\u0925 \u0939\u0948 \u0915\u093F \u0906\u092A\u0915\u0940 \u0915\u0941\u0932 \u0915\u092E\u093E\u0908 \u0924\u0940\u0928\u094B\u0902 \u0915\u093E \u092F\u094B\u0917 \u0939\u0948\u0964 \u0924\u0940\u0928\u094B\u0902 \u0915\u093E \u0928\u093F\u0930\u094D\u092E\u093E\u0923 \u0915\u0930\u0947\u0902, \u0914\u0930 \u0906\u092A TurboLoop \u0915\u0940 \u092A\u0942\u0930\u0940 \u0915\u092E\u093E\u0908 \u0915\u094D\u0937\u092E\u0924\u093E \u0915\u094B \u0905\u0928\u0932\u0949\u0915 \u0915\u0930 \u0926\u0947\u0902\u0917\u0947\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 \u0907\u0902\u091C\u0928 1: \u092A\u094D\u0932\u093E\u0928 \u092F\u0940\u0932\u094D\u0921 \u2014 \u092A\u094D\u0932\u093E\u0928 \u0915\u0947 \u0906\u0927\u093E\u0930 \u092A\u0930 3% \u0938\u0947 54%, \u0926\u0948\u0928\u093F\u0915 \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924\n\u2022 \u0907\u0902\u091C\u0928 2: \u0930\u0947\u092B\u0930\u0932 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u2014 20 \u0938\u094D\u0924\u0930\u094B\u0902 \u0924\u0915 \u0917\u0939\u0930\u093E, 51% \u0915\u0941\u0932 \u0935\u093F\u0924\u0930\u0923\n\u2022 \u0907\u0902\u091C\u0928 3: \u0932\u0940\u0921\u0930\u0936\u093F\u092A \u092C\u094B\u0928\u0938 \u2014 7 \u0930\u0948\u0902\u0915, 1% \u0938\u0947 10% \u0905\u0924\u093F\u0930\u093F\u0915\u094D\u0924 \u0915\u092E\u093E\u0908\n\u2022 \u0924\u0940\u0928\u094B\u0902 \u0907\u0902\u091C\u0928 \u090F\u0915 \u0938\u093E\u0925 \u0914\u0930 \u0938\u094D\u0935\u0924\u0902\u0924\u094D\u0930 \u0930\u0942\u092A \u0938\u0947 \u0915\u093E\u092E \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\n\u2022 \u0915\u0941\u0932 \u0915\u092E\u093E\u0908 = \u092A\u094D\u0932\u093E\u0928 \u092F\u0940\u0932\u094D\u0921 + \u0930\u0947\u092B\u0930\u0932 \u0915\u092E\u0940\u0936\u0928 + \u0932\u0940\u0921\u0930\u0936\u093F\u092A \u092C\u094B\u0928\u0938\n\n\u{1F48E} \u0924\u0940\u0928 \u0907\u0902\u091C\u0928\u0964 \u090F\u0915 \u0932\u0915\u094D\u0937\u094D\u092F: \u0906\u092A\u0915\u0940 \u0938\u0902\u092A\u0924\u094D\u0924\u093F\u0964 \u0924\u0940\u0928\u094B\u0902 \u0915\u094B \u0938\u0915\u094D\u0930\u093F\u092F \u0915\u0930\u0947\u0902\u0964\n\n\u{1F310} turboloop.io",
