      caption: "\u{1F537} 20-\u0932\u0947\u0935\u0932 \u0930\u0947\u092B\u0930\u0932 \u0928\u0947\u091F\u0935\u0930\u094D\u0915\n\u2726 \u090F\u0915 \u0932\u093F\u0902\u0915, 20 \u0932\u0947\u0935\u0932 \u0917\u0939\u0930\u093E, 51% \u0935\u093F\u0924\u0930\u0923 \u2014 \u0905\u092A\u0928\u093E \u0938\u093E\u092E\u094D\u0930\u093E\u091C\u094D\u092F \u092C\u0928\u093E\u090F\u0902\n\nTurboLoop \u0915\u093E \u0930\u0947\u092B\u0930\u0932 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u092A\u0942\u0930\u0947 DeFi \u092E\u0947\u0902 \u0938\u092C\u0938\u0947 \u0909\u0926\u093E\u0930 \u0928\u0947\u091F\u0935\u0930\u094D\u0915\u094B\u0902 \u092E\u0947\u0902 \u0938\u0947 \u090F\u0915 \u0939\u0948\u0964 \u091C\u092C \u0906\u092A \u0905\u092A\u0928\u093E \u0905\u0928\u0942\u0920\u093E \u0930\u0947\u092B\u0930\u0932 \u0932\u093F\u0902\u0915 \u0938\u093E\u091D\u093E \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0915\u094B\u0908 \u091C\u0941\u0921\u093C\u0924\u093E \u0939\u0948, \u0924\u094B \u0906\u092A \u0909\u0928\u0915\u0947 \u0921\u093F\u092A\u0949\u091C\u093F\u091F \u0915\u093E \u090F\u0915 \u092A\u094D\u0930\u0924\u093F\u0936\u0924 \u0915\u092E\u093E\u0924\u0947 \u0939\u0948\u0902 \u2014 \u0928 \u0915\u0947\u0935\u0932 \u0905\u092A\u0928\u0947 \u092A\u094D\u0930\u0924\u094D\u092F\u0915\u094D\u0937 \u0930\u0947\u092B\u0930\u0932 \u0938\u0947, \u092C\u0932\u094D\u0915\u093F \u0905\u092A\u0928\u0947 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u092E\u0947\u0902 20 \u0932\u0947\u0935\u0932 \u0917\u0939\u0930\u093E\u0908 \u0924\u0915\u0964 \u0938\u092D\u0940 20 \u0932\u0947\u0935\u0932 \u092E\u0947\u0902 \u0915\u0941\u0932 \u0935\u093F\u0924\u0930\u0923 51% \u0939\u0948, \u091C\u094B \u0907\u0938\u0947 \u0909\u0926\u094D\u092F\u094B\u0917 \u092E\u0947\u0902 \u0938\u092C\u0938\u0947 \u0905\u0927\u093F\u0915 \u0930\u0947\u092B\u0930\u0932 \u092A\u0947\u0906\u0909\u091F \u092E\u0947\u0902 \u0938\u0947 \u090F\u0915 \u092C\u0928\u093E\u0924\u093E \u0939\u0948\u0964 Level 1 (\u092A\u094D\u0930\u0924\u094D\u092F\u0915\u094D\u0937 \u0930\u0947\u092B\u0930\u0932) \u0906\u092A\u0915\u094B 12% \u0915\u092E\u093E\u0924\u093E \u0939\u0948\u0964 Level 2 8% \u0915\u092E\u093E\u0924\u093E \u0939\u0948\u0964 Level 3: 5%\u0964 Levels 4-5: \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 3%\u0964 Levels 6-10: \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 2%\u0964 Levels 11-20: \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 1%\u0964 \u091A\u094C\u0921\u093C\u093E\u0908 \u092A\u0930 \u0915\u094B\u0908 \u0938\u0940\u092E\u093E \u0928\u0939\u0940\u0902 \u0939\u0948 \u2014 \u0906\u092A \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 \u0932\u0947\u0935\u0932 \u092A\u0930 \u091C\u093F\u0924\u0928\u0947 \u091A\u093E\u0939\u0947\u0902 \u0909\u0924\u0928\u0947 \u0932\u094B\u0917\u094B\u0902 \u0915\u094B \u0930\u0947\u092B\u0930 \u0915\u0930 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964 \u092D\u0941\u0917\u0924\u093E\u0928 \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0914\u0930 \u0926\u0948\u0928\u093F\u0915 \u0939\u0948\u0902, \u091C\u093F\u0928\u094D\u0939\u0947\u0902 \u092C\u093F\u0928\u093E \u0915\u093F\u0938\u0940 \u092E\u0948\u0928\u094D\u092F\u0941\u0905\u0932 \u0915\u094D\u0932\u0947\u092E \u0915\u0947 Smart Contract \u0926\u094D\u0935\u093E\u0930\u093E \u092A\u094D\u0930\u094B\u0938\u0947\u0938 \u0915\u093F\u092F\u093E \u091C\u093E\u0924\u093E \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 Level 1: 12% (\u092A\u094D\u0930\u0924\u094D\u092F\u0915\u094D\u0937 \u0930\u0947\u092B\u0930\u0932) \u2014 \u0938\u092C\u0938\u0947 \u0905\u0927\u093F\u0915 \u0938\u093F\u0902\u0917\u0932-\u0932\u0947\u0935\u0932 \u092A\u0947\u0906\u0909\u091F\n\u2022 Levels 2-5: 8%, 5%, 3%, 3% \u2014 \u092A\u0939\u0932\u0947 5 \u0932\u0947\u0935\u0932 \u092E\u0947\u0902 \u0915\u0941\u0932 31%\n\u2022 Levels 6-10: \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 2% \u2014 \u092E\u093F\u0921-\u0921\u0947\u092A\u094D\u0925 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0938\u0947 \u0915\u0941\u0932 10%\n\u2022 Levels 11-20: \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 1% \u2014 \u0921\u0940\u092A \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0938\u0947 \u0915\u0941\u0932 10%\n\u2022 \u0915\u0941\u0932 \u092F\u094B\u0917: 20 \u0932\u0947\u0935\u0932 \u092E\u0947\u0902 51% \u0935\u093F\u0924\u0930\u0923, \u0905\u0938\u0940\u092E\u093F\u0924 \u091A\u094C\u0921\u093C\u093E\u0908\n\n\u{1F48E} \u090F\u0915 \u0932\u093F\u0902\u0915\u0964 \u092C\u0940\u0938 \u0932\u0947\u0935\u0932\u0964 \u0905\u0938\u0940\u092E\u093F\u0924 \u0915\u092E\u093E\u0908 \u0915\u0940 \u0915\u094D\u0937\u092E\u0924\u093E\u0964\n\n\u{1F310} turboloop.io",
