      headline: "\u{1F537} ZOOM PRESENTER \u092A\u094D\u0930\u094B\u0917\u094D\u0930\u093E\u092E",
      caption: "\u{1F537} ZOOM PRESENTER \u092A\u094D\u0930\u094B\u0917\u094D\u0930\u093E\u092E\n\u2726 TurboLoop \u092A\u094D\u0930\u0938\u094D\u0924\u0941\u0924 \u0915\u0930\u0947\u0902, \u0939\u0930 \u092E\u0939\u0940\u0928\u0947 $100 \u0915\u092E\u093E\u090F\u0902\n\nTurboLoop \u0915\u093E Zoom Presenter \u092A\u094D\u0930\u094B\u0917\u094D\u0930\u093E\u092E \u0909\u0924\u094D\u0938\u093E\u0939\u0940 \u0915\u092E\u094D\u092F\u0941\u0928\u093F\u091F\u0940 \u0938\u0926\u0938\u094D\u092F\u094B\u0902 \u0915\u094B \u0906\u0927\u093F\u0915\u093E\u0930\u093F\u0915 \u090F\u0902\u092C\u0947\u0938\u0921\u0930 \u092C\u0928\u0928\u0947 \u0915\u093E \u0905\u0927\u093F\u0915\u093E\u0930 \u0926\u0947\u0924\u093E \u0939\u0948\u0964 \u092A\u094D\u0930\u094B\u0917\u094D\u0930\u093E\u092E \u092E\u0947\u0902 \u0906\u0935\u0947\u0926\u0928 \u0915\u0930\u0947\u0902, \u092A\u0947\u0936\u0947\u0935\u0930 \u0930\u0942\u092A \u0938\u0947 \u0921\u093F\u091C\u093C\u093E\u0907\u0928 \u0915\u0940 \u0917\u0908 \u092A\u094D\u0930\u0947\u091C\u0947\u0902\u091F\u0947\u0936\u0928 \u0938\u093E\u092E\u0917\u094D\u0930\u0940 \u092A\u094D\u0930\u093E\u092A\u094D\u0924 \u0915\u0930\u0947\u0902, \u0914\u0930 \u0905\u092A\u0928\u0940 \u092D\u093E\u0937\u093E \u0914\u0930 \u0915\u092E\u094D\u092F\u0941\u0928\u093F\u091F\u0940 \u092E\u0947\u0902 \u0928\u090F \u0938\u0926\u0938\u094D\u092F\u094B\u0902 \u0915\u094B \u0936\u093F\u0915\u094D\u0937\u093F\u0924 \u0915\u0930\u0928\u0947 \u0914\u0930 \u091C\u094B\u0921\u093C\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u0938\u094D\u0925\u093E\u0928\u0940\u092F Zoom \u0938\u0924\u094D\u0930 \u0906\u092F\u094B\u091C\u093F\u0924 \u0915\u0930\u0947\u0902\u0964 \u0907\u0938\u0915\u0947 \u092C\u0926\u0932\u0947 \u092E\u0947\u0902, \u0906\u092A \u092A\u094D\u0930\u0924\u093F \u092E\u093E\u0939 $100 \u0915\u0940 \u0928\u093F\u0930\u0902\u0924\u0930 \u0915\u092E\u093E\u0908 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u2014 \u0909\u0928 \u0932\u094B\u0917\u094B\u0902 \u0915\u0947 \u0932\u093F\u090F \u090F\u0915 \u0935\u093F\u0936\u094D\u0935\u0938\u0928\u0940\u092F \u0906\u092F \u0938\u094D\u0930\u094B\u0924 \u091C\u094B \u0932\u094B\u0917\u094B\u0902 \u0915\u094B \u0938\u093F\u0916\u093E\u0928\u093E \u0914\u0930 \u0909\u0928\u0938\u0947 \u091C\u0941\u0921\u093C\u0928\u093E \u092A\u0938\u0902\u0926 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 \u092A\u094D\u0930\u094B\u0917\u094D\u0930\u093E\u092E \u092E\u0947\u0902 \u092E\u0941\u092B\u094D\u0924 \u092A\u094D\u0930\u0936\u093F\u0915\u094D\u0937\u0923 \u0936\u093E\u092E\u093F\u0932 \u0939\u0948 \u0924\u093E\u0915\u093F \u092F\u0939 \u0938\u0941\u0928\u093F\u0936\u094D\u091A\u093F\u0924 \u0939\u094B \u0938\u0915\u0947 \u0915\u093F \u0906\u092A \u0938\u091F\u0940\u0915 \u091C\u093E\u0928\u0915\u093E\u0930\u0940 \u0914\u0930 \u092A\u094D\u0930\u092D\u093E\u0935\u0940 \u092A\u094D\u0930\u0947\u091C\u0947\u0902\u091F\u0947\u0936\u0928 \u0915\u094C\u0936\u0932 \u0938\u0947 \u0932\u0948\u0938 \u0939\u0948\u0902\u0964 \u091A\u093E\u0939\u0947 \u0906\u092A \u0932\u093E\u0917\u094B\u0938, \u091C\u0915\u093E\u0930\u094D\u0924\u093E, \u092E\u0941\u0902\u092C\u0908 \u092F\u093E \u092E\u0947\u0915\u094D\u0938\u093F\u0915\u094B \u0938\u093F\u091F\u0940 \u092E\u0947\u0902 \u0939\u094B\u0902, \u0906\u092A \u090F\u0915 TurboLoop \u092A\u094D\u0930\u0947\u091C\u0947\u0902\u091F\u0930 \u092C\u0928 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0915\u092E\u093E\u0908 \u0915\u0930\u0924\u0947 \u0939\u0941\u090F \u0905\u092A\u0928\u0940 \u0938\u094D\u0925\u093E\u0928\u0940\u092F \u0915\u092E\u094D\u092F\u0941\u0928\u093F\u091F\u0940 \u0915\u093E \u0928\u093F\u0930\u094D\u092E\u093E\u0923 \u0915\u0930 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 Zoom Presenter \u092A\u094D\u0930\u094B\u0917\u094D\u0930\u093E\u092E \u092E\u0947\u0902 \u0906\u0935\u0947\u0926\u0928 \u0915\u0930\u0947\u0902 \u2014 \u0938\u092D\u0940 \u0938\u0926\u0938\u094D\u092F\u094B\u0902 \u0915\u0947 \u0932\u093F\u090F \u0916\u0941\u0932\u093E \u0939\u0948\n\u2022 \u0906\u0927\u093F\u0915\u093E\u0930\u093F\u0915 \u092A\u094D\u0930\u0947\u091C\u0947\u0902\u091F\u0947\u0936\u0928 \u0938\u093E\u092E\u0917\u094D\u0930\u0940 \u0914\u0930 \u092E\u0941\u092B\u094D\u0924 \u092A\u094D\u0930\u0936\u093F\u0915\u094D\u0937\u0923 \u092A\u094D\u0930\u093E\u092A\u094D\u0924 \u0915\u0930\u0947\u0902\n\u2022 \u0905\u092A\u0928\u0940 \u092D\u093E\u0937\u093E \u0914\u0930 \u0915\u092E\u094D\u092F\u0941\u0928\u093F\u091F\u0940 \u092E\u0947\u0902 \u0938\u094D\u0925\u093E\u0928\u0940\u092F Zoom \u0938\u0924\u094D\u0930 \u0906\u092F\u094B\u091C\u093F\u0924 \u0915\u0930\u0947\u0902\n\u2022 \u090F\u0915 \u0928\u093F\u0930\u0902\u0924\u0930 \u092A\u094D\u0930\u0947\u091C\u0947\u0902\u091F\u0930 \u0906\u092F \u0915\u0947 \u0930\u0942\u092A \u092E\u0947\u0902 $100/\u092E\u0939\u0940\u0928\u093E \u0915\u092E\u093E\u090F\u0902\n\u2022 \u0928\u090F \u0938\u0926\u0938\u094D\u092F\u094B\u0902 \u0915\u094B \u0936\u093F\u0915\u094D\u0937\u093F\u0924 \u0915\u0930\u0924\u0947 \u0939\u0941\u090F \u0905\u092A\u0928\u093E \u0938\u094D\u0925\u093E\u0928\u0940\u092F \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u092C\u0928\u093E\u090F\u0902\n\n\u{1F48E} \u0938\u093F\u0916\u093E\u090F\u0902\u0964 \u092A\u094D\u0930\u0947\u0930\u093F\u0924 \u0915\u0930\u0947\u0902\u0964 \u0915\u092E\u093E\u090F\u0902\u0964 \u090F\u0915 TurboLoop \u090F\u0902\u092C\u0947\u0938\u0921\u0930 \u092C\u0928\u0947\u0902\u0964\n\n\u{1F310} turboloop.io",
