      original: "31_LP_Lock.png",
      headline: "\u{1F537} LP \u0939\u092E\u0947\u0936\u093E \u0915\u0947 \u0932\u093F\u090F \u0932\u0949\u0915",
      caption: "\u{1F537} LP \u0939\u092E\u0947\u0936\u093E \u0915\u0947 \u0932\u093F\u090F \u0932\u0949\u0915\n\u2726 \u0932\u093F\u0915\u094D\u0935\u093F\u0921\u093F\u091F\u0940 \u092A\u0942\u0932 \u0938\u094D\u0925\u093E\u092F\u0940 \u0930\u0942\u092A \u0938\u0947 \u0938\u0941\u0930\u0915\u094D\u0937\u093F\u0924 \u2014 Rug Pull \u0905\u0938\u0902\u092D\u0935\n\n\u0932\u093F\u0915\u094D\u0935\u093F\u0921\u093F\u091F\u0940 \u092A\u0942\u0932 \u0915\u093F\u0938\u0940 \u092D\u0940 DeFi \u092A\u094D\u0930\u094B\u091F\u094B\u0915\u0949\u0932 \u0915\u0940 \u091C\u0940\u0935\u0928\u0930\u0947\u0916\u093E \u0939\u0948, \u0914\u0930 TurboLoop \u0928\u0947 \u0907\u0938\u0947 \u0938\u094D\u0925\u093E\u092F\u0940 \u0930\u0942\u092A \u0938\u0947 \u0932\u0949\u0915 \u0915\u0930 \u0926\u093F\u092F\u093E \u0939\u0948\u0964 \u0907\u0938\u0915\u093E \u0905\u0930\u094D\u0925 \u0939\u0948 \u0915\u093F \u092A\u094D\u0930\u094B\u091F\u094B\u0915\u0949\u0932 \u0915\u094B \u0938\u092E\u0930\u094D\u0925\u0928 \u0926\u0947\u0928\u0947 \u0935\u093E\u0932\u0940 \u0932\u093F\u0915\u094D\u0935\u093F\u0921\u093F\u091F\u0940 \u0915\u094B \u0915\u093F\u0938\u0940 \u0915\u0947 \u092D\u0940 \u0926\u094D\u0935\u093E\u0930\u093E \u0915\u092D\u0940 \u092D\u0940 \u0928\u093F\u0915\u093E\u0932\u093E, \u0938\u092E\u093E\u092A\u094D\u0924 \u092F\u093E \u0939\u0947\u0930\u092B\u0947\u0930 \u0928\u0939\u0940\u0902 \u0915\u093F\u092F\u093E \u091C\u093E \u0938\u0915\u0924\u093E \u0939\u0948\u0964 DeFi \u092E\u0947\u0902, \u0938\u092C\u0938\u0947 \u0906\u092E \u0916\u0924\u0930\u093E 'rug pull' \u0939\u0948, \u091C\u0939\u093E\u0902 \u0921\u0947\u0935\u0932\u092A\u0930\u094D\u0938 \u0932\u093F\u0915\u094D\u0935\u093F\u0921\u093F\u091F\u0940 \u092A\u0942\u0932 \u0915\u094B \u0916\u093E\u0932\u0940 \u0915\u0930 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0928\u093F\u0935\u0947\u0936\u0915\u094B\u0902 \u0915\u0947 \u092B\u0902\u0921 \u0915\u0947 \u0938\u093E\u0925 \u0917\u093E\u092F\u092C \u0939\u094B \u091C\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 LP \u0915\u094B \u0939\u092E\u0947\u0936\u093E \u0915\u0947 \u0932\u093F\u090F \u0932\u0949\u0915 \u0915\u0930\u0915\u0947, TurboLoop \u0928\u0947 \u0917\u0923\u093F\u0924\u0940\u092F \u0930\u0942\u092A \u0938\u0947 \u0907\u0938 \u0938\u0902\u092D\u093E\u0935\u0928\u093E \u0915\u094B \u0938\u092E\u093E\u092A\u094D\u0924 \u0915\u0930 \u0926\u093F\u092F\u093E \u0939\u0948\u0964 \u092F\u0939 \u0932\u0949\u0915 \u0938\u094D\u0935\u092F\u0902 Smart Contract \u0926\u094D\u0935\u093E\u0930\u093E \u0932\u093E\u0917\u0942 \u0915\u093F\u092F\u093E \u0917\u092F\u093E \u0939\u0948, \u0928 \u0915\u093F \u0915\u093F\u0938\u0940 \u0924\u0940\u0938\u0930\u0947 \u092A\u0915\u094D\u0937 \u0915\u0940 \u0938\u0947\u0935\u093E \u092F\u093E \u0935\u093E\u0926\u0947 \u0926\u094D\u0935\u093E\u0930\u093E\u0964 \u092F\u0939 BscScan \u092A\u0930 \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u092F\u094B\u0917\u094D\u092F \u0939\u0948, \u0914\u0930 \u092F\u0939 \u0938\u094D\u0925\u093E\u092F\u0940 \u0939\u0948\u0964 \u0906\u092A\u0915\u0947 \u092B\u0902\u0921 \u0915\u094B\u0921 \u0926\u094D\u0935\u093E\u0930\u093E \u0938\u0941\u0930\u0915\u094D\u0937\u093F\u0924 \u0939\u0948\u0902, \u0928 \u0915\u093F \u0915\u093F\u0938\u0940 \u0935\u094D\u092F\u0915\u094D\u0924\u093F \u092F\u093E \u091F\u0940\u092E \u092A\u0930 \u092D\u0930\u094B\u0938\u0947 \u0926\u094D\u0935\u093E\u0930\u093E\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 \u0932\u093F\u0915\u094D\u0935\u093F\u0921\u093F\u091F\u0940 \u092A\u0942\u0932 \u0938\u094D\u0925\u093E\u092F\u0940 \u0930\u0942\u092A \u0938\u0947 \u0932\u0949\u0915 \u2014 \u0915\u093F\u0938\u0940 \u0915\u0947 \u0926\u094D\u0935\u093E\u0930\u093E \u092D\u0940 \u0928\u093F\u0915\u093E\u0932\u093E \u0928\u0939\u0940\u0902 \u091C\u093E \u0938\u0915\u0924\u093E\n\u2022 \u0932\u0949\u0915 \u0915\u093F\u090F \u0917\u090F LP \u0915\u0947 \u0938\u093E\u0925 Rug Pull \u0917\u0923\u093F\u0924\u0940\u092F \u0930\u0942\u092A \u0938\u0947 \u0905\u0938\u0902\u092D\u0935 \u0939\u0948\n\u2022 Smart Contract \u0926\u094D\u0935\u093E\u0930\u093E \u0932\u093E\u0917\u0942 \u0932\u0949\u0915 \u2014 \u0915\u094B\u0908 \u0924\u0940\u0938\u0930\u0947 \u092A\u0915\u094D\u0937 \u0915\u093E \u0935\u093E\u0926\u093E \u0928\u0939\u0940\u0902\n\u2022 BscScan \u092A\u0930 \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u092F\u094B\u0917\u094D\u092F \u2014 \u0938\u094D\u0935\u092F\u0902 LP \u0932\u0949\u0915 \u0938\u094D\u0925\u093F\u0924\u093F \u0915\u0940 \u091C\u093E\u0902\u091A \u0915\u0930\u0947\u0902\n\u2022 \u092B\u0902\u0921 \u0905\u092A\u0930\u093F\u0935\u0930\u094D\u0924\u0928\u0940\u092F \u0915\u094B\u0921 \u0926\u094D\u0935\u093E\u0930\u093E \u0938\u0941\u0930\u0915\u094D\u0937\u093F\u0924 \u0939\u0948\u0902, \u092E\u093E\u0928\u0935\u0940\u092F \u0935\u093E\u0926\u094B\u0902 \u0926\u094D\u0935\u093E\u0930\u093E \u0928\u0939\u0940\u0902\n\n\u{1F48E} \u0932\u093F\u0915\u094D\u0935\u093F\u0921\u093F\u091F\u0940 \u0938\u0941\u0930\u0915\u094D\u0937\u093F\u0924 \u0939\u0948\u0964 \u0939\u092E\u0947\u0936\u093E \u0915\u0947 \u0932\u093F\u090F\u0964 \u091A\u0948\u0928 \u0938\u0947 \u0938\u094B\u090F\u0902\u0964\n\n\u{1F310} turboloop.io",
