      headline: "\u{1F537} BscScan \u092A\u0930 \u0915\u094B\u0921 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924",
      caption: "\u{1F537} BscScan \u092A\u0930 \u0915\u094B\u0921 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924\n\u2726 \u0913\u092A\u0928 \u0938\u094B\u0930\u094D\u0938, \u092A\u093E\u0930\u0926\u0930\u094D\u0936\u0940, \u0915\u093F\u0938\u0940 \u0915\u0947 \u092D\u0940 \u0926\u094D\u0935\u093E\u0930\u093E \u092A\u0922\u093C\u0928\u0947 \u092F\u094B\u0917\u094D\u092F\n\nDeFi \u092E\u0947\u0902 \u0935\u093F\u0936\u094D\u0935\u093E\u0938 \u0915\u0940 \u0906\u0927\u093E\u0930\u0936\u093F\u0932\u093E \u092A\u093E\u0930\u0926\u0930\u094D\u0936\u093F\u0924\u093E \u0939\u0948, \u0914\u0930 TurboLoop \u0907\u0938\u0947 \u092A\u0942\u0930\u0940 \u0924\u0930\u0939 \u0938\u0947 \u092A\u094D\u0930\u0926\u093E\u0928 \u0915\u0930\u0924\u093E \u0939\u0948\u0964 \u0938\u0902\u092A\u0942\u0930\u094D\u0923 Smart Contract \u0938\u094B\u0930\u094D\u0938 \u0915\u094B\u0921 BscScan \u2014 Binance Smart Chain \u0915\u0947 \u0906\u0927\u093F\u0915\u093E\u0930\u093F\u0915 \u092C\u094D\u0932\u0949\u0915 \u090F\u0915\u094D\u0938\u092A\u094D\u0932\u094B\u0930\u0930 \u2014 \u092A\u0930 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u0939\u0948\u0964 \u0907\u0938\u0915\u093E \u092E\u0924\u0932\u092C \u0939\u0948 \u0915\u093F \u0926\u0941\u0928\u093F\u092F\u093E \u092E\u0947\u0902 \u0915\u0939\u0940\u0902 \u092D\u0940, \u0915\u094B\u0908 \u092D\u0940 \u0935\u094D\u092F\u0915\u094D\u0924\u093F \u092A\u094D\u0930\u094B\u091F\u094B\u0915\u0949\u0932 \u0915\u094B \u0928\u093F\u092F\u0902\u0924\u094D\u0930\u093F\u0924 \u0915\u0930\u0928\u0947 \u0935\u093E\u0932\u0947 \u0915\u094B\u0921 \u0915\u0940 \u0939\u0930 \u092A\u0902\u0915\u094D\u0924\u093F \u0915\u094B \u092A\u0922\u093C \u0938\u0915\u0924\u093E \u0939\u0948\u0964 \u0907\u0938\u092E\u0947\u0902 \u0915\u094B\u0908 \u091B\u093F\u092A\u0947 \u0939\u0941\u090F \u092B\u093C\u0902\u0915\u094D\u0936\u0928 \u0928\u0939\u0940\u0902 \u0939\u0948\u0902, \u0915\u094B\u0908 \u0905\u0938\u094D\u092A\u0937\u094D\u091F \u0924\u0930\u094D\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948, \u0915\u094B\u0908 \u0917\u0941\u092A\u094D\u0924 \u0924\u0902\u0924\u094D\u0930 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u0906\u092A \u091C\u094B \u0926\u0947\u0916\u0924\u0947 \u0939\u0948\u0902, \u0920\u0940\u0915 \u0935\u0939\u0940 \u0928\u093F\u0937\u094D\u092A\u093E\u0926\u093F\u0924 \u0939\u094B\u0924\u093E \u0939\u0948\u0964 \u0921\u0947\u0935\u0932\u092A\u0930\u094D\u0938 \u0907\u0938\u0915\u093E \u0911\u0921\u093F\u091F \u0915\u0930 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964 \u0938\u0941\u0930\u0915\u094D\u0937\u093E \u0936\u094B\u0927\u0915\u0930\u094D\u0924\u093E \u0907\u0938\u0915\u093E \u0935\u093F\u0936\u094D\u0932\u0947\u0937\u0923 \u0915\u0930 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964 \u0909\u092A\u092F\u094B\u0917\u0915\u0930\u094D\u0924\u093E \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u0915\u0930 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902 \u0915\u093F \u0905\u0928\u0941\u092C\u0902\u0927 \u0920\u0940\u0915 \u0935\u0939\u0940 \u0915\u0930\u0924\u093E \u0939\u0948 \u091C\u094B \u0935\u0939 \u0926\u093E\u0935\u093E \u0915\u0930\u0924\u093E \u0939\u0948\u0964 \u092A\u093E\u0930\u0926\u0930\u094D\u0936\u093F\u0924\u093E \u0915\u093E \u092F\u0939 \u0938\u094D\u0924\u0930 \u092A\u093E\u0930\u0902\u092A\u0930\u093F\u0915 \u0935\u093F\u0924\u094D\u0924 \u092E\u0947\u0902 \u0905\u0938\u0902\u092D\u0935 \u0939\u0948, \u091C\u0939\u093E\u0902 \u0928\u093F\u092F\u092E \u092C\u0902\u0926 \u0926\u0930\u0935\u093E\u091C\u094B\u0902 \u0915\u0947 \u092A\u0940\u091B\u0947 \u0932\u093F\u0916\u0947 \u091C\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 TurboLoop \u092E\u0947\u0902, \u0928\u093F\u092F\u092E \u0938\u093E\u0930\u094D\u0935\u091C\u0928\u093F\u0915 \u0930\u0942\u092A \u0938\u0947 \u0932\u093F\u0916\u0947 \u091C\u093E\u0924\u0947 \u0939\u0948\u0902, \u0924\u093E\u0915\u093F \u0938\u092D\u0940 \u0926\u0947\u0916 \u0938\u0915\u0947\u0902\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 BscScan \u2014 \u0906\u0927\u093F\u0915\u093E\u0930\u093F\u0915 BSC \u090F\u0915\u094D\u0938\u092A\u094D\u0932\u094B\u0930\u0930 \u2014 \u092A\u0930 \u0938\u0902\u092A\u0942\u0930\u094D\u0923 \u0938\u094B\u0930\u094D\u0938 \u0915\u094B\u0921 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924\n\u2022 \u0913\u092A\u0928 \u0938\u094B\u0930\u094D\u0938 \u2014 \u0915\u094B\u0908 \u092D\u0940 \u0915\u094B\u0921 \u0915\u0940 \u0939\u0930 \u092A\u0902\u0915\u094D\u0924\u093F \u0915\u094B \u092A\u0922\u093C \u0938\u0915\u0924\u093E \u0939\u0948\n\u2022 \u0915\u094B\u0908 \u091B\u093F\u092A\u0947 \u0939\u0941\u090F \u092B\u093C\u0902\u0915\u094D\u0936\u0928 \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u0905\u0938\u094D\u092A\u0937\u094D\u091F \u0924\u0930\u094D\u0915 \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u0930\u0939\u0938\u094D\u092F \u0928\u0939\u0940\u0902\n\u2022 \u0921\u0947\u0935\u0932\u092A\u0930\u094D\u0938 \u0914\u0930 \u0938\u0941\u0930\u0915\u094D\u0937\u093E \u0936\u094B\u0927\u0915\u0930\u094D\u0924\u093E \u0938\u094D\u0935\u0924\u0902\u0924\u094D\u0930 \u0930\u0942\u092A \u0938\u0947 \u0915\u094B\u0921 \u0915\u093E \u0911\u0921\u093F\u091F \u0915\u0930 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\n\u2022 \u092A\u093E\u0930\u0902\u092A\u0930\u093F\u0915 \u0935\u093F\u0924\u094D\u0924 \u092E\u0947\u0902 \u0905\u0938\u0902\u092D\u0935 \u2014 TurboLoop \u092E\u093E\u0928\u0915 \u0938\u094D\u0925\u093E\u092A\u093F\u0924 \u0915\u0930\u0924\u093E \u0939\u0948\n\n\u{1F48E} \u0907\u0938\u0947 \u0938\u094D\u0935\u092F\u0902 \u092A\u0922\u093C\u0947\u0902\u0964 \u0907\u0938\u0947 \u0938\u094D\u0935\u092F\u0902 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u0915\u0930\u0947\u0902\u0964 \u0915\u094B\u0921 \u0915\u0941\u091B \u092D\u0940 \u0928\u0939\u0940\u0902 \u091B\u093F\u092A\u093E\u0924\u093E \u0939\u0948\u0964\n\n\u{1F310} turboloop.io",
