      headline: "\u{1F537} \u0930\u0947\u092B\u0930\u0932 \u0932\u0947\u0935\u0932\u094D\u0938 6-20",
      caption: "\u{1F537} \u0930\u0947\u092B\u0930\u0932 \u0932\u0947\u0935\u0932\u094D\u0938 6-20\n\u2726 \u0917\u0939\u0930\u093E\u0908 \u2014 \u091C\u0939\u093E\u0901 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0938\u093E\u092E\u094D\u0930\u093E\u091C\u094D\u092F \u092C\u0928 \u091C\u093E\u0924\u0947 \u0939\u0948\u0902\n\n\u091C\u092C\u0915\u093F \u092A\u0939\u0932\u0947 \u092A\u093E\u0901\u091A \u0932\u0947\u0935\u0932\u094D\u0938 \u0906\u092A\u0915\u0940 \u0928\u0940\u0902\u0935 \u092C\u0928\u093E\u0924\u0947 \u0939\u0948\u0902, \u0932\u0947\u0935\u0932\u094D\u0938 6 \u0938\u0947 20 \u0935\u0939 \u091C\u0917\u0939 \u0939\u0948\u0902 \u091C\u0939\u093E\u0901 \u0906\u092A\u0915\u093E \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u090F\u0915 \u0938\u093E\u092E\u094D\u0930\u093E\u091C\u094D\u092F \u092E\u0947\u0902 \u092C\u0926\u0932 \u091C\u093E\u0924\u093E \u0939\u0948\u0964 \u0932\u0947\u0935\u0932\u094D\u0938 6-10 \u092E\u0947\u0902 \u0938\u0947 \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 2% \u0935\u093F\u0924\u0930\u093F\u0924 \u0915\u0930\u0924\u093E \u0939\u0948, \u091C\u094B \u0906\u092A\u0915\u0947 \u092E\u093F\u0921-\u0921\u0947\u092A\u094D\u0925 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0938\u0947 \u0915\u0941\u0932 10% \u0939\u094B\u0924\u093E \u0939\u0948\u0964 \u0932\u0947\u0935\u0932\u094D\u0938 11-20 \u092E\u0947\u0902 \u0938\u0947 \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 1% \u0915\u093E \u092F\u094B\u0917\u0926\u093E\u0928 \u0926\u0947\u0924\u093E \u0939\u0948, \u091C\u094B \u0906\u092A\u0915\u0947 \u0938\u092C\u0938\u0947 \u0917\u0939\u0930\u0947 \u0915\u0928\u0947\u0915\u094D\u0936\u0928 \u0938\u0947 \u090F\u0915 \u0914\u0930 10% \u091C\u094B\u0921\u093C\u0924\u093E \u0939\u0948\u0964 \u0938\u0902\u092F\u0941\u0915\u094D\u0924 \u0930\u0942\u092A \u0938\u0947, \u0932\u0947\u0935\u0932\u094D\u0938 6-20 \u0915\u0941\u0932 \u0930\u0947\u092B\u0930\u0932 \u0935\u093F\u0924\u0930\u0923 \u0915\u093E 20% \u092A\u094D\u0930\u0926\u093E\u0928 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u2014 \u090F\u0915 \u0935\u093F\u0936\u093E\u0932 \u092A\u0948\u0938\u093F\u0935 \u0907\u0928\u0915\u092E \u0938\u094D\u091F\u094D\u0930\u0940\u092E \u091C\u094B \u0906\u092A\u0915\u0947 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0915\u0947 \u0917\u0939\u0930\u093E \u0939\u094B\u0928\u0947 \u0915\u0947 \u0938\u093E\u0925 \u0924\u0947\u091C\u0940 \u0938\u0947 \u092C\u0922\u093C\u0924\u0940 \u0939\u0948\u0964 \u0917\u0939\u0930\u0947 \u0930\u0947\u092B\u0930\u0932 \u0932\u0947\u0935\u0932\u094D\u0938 \u0915\u0940 \u0938\u0941\u0902\u0926\u0930\u0924\u093E \u092F\u0939 \u0939\u0948 \u0915\u093F \u0935\u0947 \u0935\u094D\u092F\u0935\u0938\u094D\u0925\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u0915\u0902\u092A\u093E\u0909\u0902\u0921 \u0939\u094B\u0924\u0947 \u0939\u0948\u0902: \u091C\u0948\u0938\u0947-\u091C\u0948\u0938\u0947 \u0906\u092A\u0915\u0947 \u0930\u0947\u092B\u0930\u0932 \u0905\u092A\u0928\u0947 \u0938\u094D\u0935\u092F\u0902 \u0915\u0947 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u092C\u0928\u093E\u0924\u0947 \u0939\u0948\u0902, \u0906\u092A\u0915\u0947 \u0917\u0939\u0930\u0947 \u0932\u0947\u0935\u0932\u094D\u0938 \u0906\u092A\u0915\u0947 \u0915\u093F\u0938\u0940 \u092D\u0940 \u0905\u0924\u093F\u0930\u093F\u0915\u094D\u0924 \u092A\u094D\u0930\u092F\u093E\u0938 \u0915\u0947 \u092C\u093F\u0928\u093E \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u092D\u0930 \u091C\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 \u092F\u0939\u0940\u0902 \u092A\u0930 \u0927\u0948\u0930\u094D\u092F\u0935\u093E\u0928 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0928\u093F\u0930\u094D\u092E\u093E\u0924\u093E \u0905\u092A\u0928\u0940 \u0915\u092E\u093E\u0908 \u0915\u094B \u0915\u0908 \u0917\u0941\u0928\u093E \u092C\u0922\u093C\u0924\u0947 \u0939\u0941\u090F \u0926\u0947\u0916\u0924\u0947 \u0939\u0948\u0902\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0906\u0915\u0930\u094D\u0937\u0923:\n\u2022 \u0932\u0947\u0935\u0932\u094D\u0938 6-10: \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 2% \u2014 \u092E\u093F\u0921-\u0921\u0947\u092A\u094D\u0925 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0938\u0947 \u0915\u0941\u0932 10%\n\u2022 \u0932\u0947\u0935\u0932\u094D\u0938 11-20: \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 1% \u2014 \u0921\u0940\u092A \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0938\u0947 \u0915\u0941\u0932 10%\n\u2022 \u0938\u0902\u092F\u0941\u0915\u094D\u0924 \u0932\u0947\u0935\u0932\u094D\u0938 6-20: 20% \u0915\u0941\u0932 \u0935\u093F\u0924\u0930\u0923\n\u2022 \u091C\u0948\u0938\u0947-\u091C\u0948\u0938\u0947 \u0906\u092A\u0915\u093E \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u092C\u0922\u093C\u0924\u093E \u0939\u0948, \u0917\u0939\u0930\u0947 \u0932\u0947\u0935\u0932\u094D\u0938 \u0935\u094D\u092F\u0935\u0938\u094D\u0925\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u092D\u0930\u0924\u0947 \u0939\u0948\u0902\n\u2022 \u0938\u092D\u0940 20 \u0932\u0947\u0935\u0932\u094D\u0938 \u0915\u093E \u0915\u0941\u0932 \u092F\u094B\u0917: 51% \u2014 DeFi \u0915\u0947 \u0938\u092C\u0938\u0947 \u090A\u0902\u091A\u0947 \u0938\u094D\u0924\u0930\u094B\u0902 \u092E\u0947\u0902 \u0938\u0947 \u090F\u0915\n\n\u{1F48E} \u0917\u0939\u0930\u093E\u0908 \u0927\u0928 \u0915\u093E \u0928\u093F\u0930\u094D\u092E\u093E\u0923 \u0915\u0930\u0924\u0940 \u0939\u0948\u0964 \u0935\u094D\u092F\u093E\u092A\u0915 \u0928\u093F\u0930\u094D\u092E\u093E\u0923 \u0915\u0930\u0947\u0902, \u0917\u0939\u0930\u093E\u0908 \u0924\u0915 \u092C\u0922\u093C\u0947\u0902, \u0939\u092E\u0947\u0936\u093E \u0915\u092E\u093E\u090F\u0902\u0964\n\n\u{1F310} turboloop.io",
