      caption: "\u{1F537} Boost Loop \u2014 \u092A\u0942\u0930\u094D\u0923 \u0935\u093F\u0935\u0930\u0923\n\u2726 \u0924\u094D\u0935\u0930\u093F\u0924 \u0935\u093F\u0915\u093E\u0938 \u2014 \u0939\u0930 \u0935\u093F\u0935\u0930\u0923 \u091C\u094B \u0906\u092A\u0915\u094B \u091C\u093E\u0928\u0928\u093E \u0906\u0935\u0936\u094D\u092F\u0915 \u0939\u0948\n\nBoost Loop \u0909\u0928 \u0928\u093F\u0935\u0947\u0936\u0915\u094B\u0902 \u0915\u0947 \u0932\u093F\u090F \u0938\u094D\u0935\u093E\u092D\u093E\u0935\u093F\u0915 \u092A\u094D\u0930\u0917\u0924\u093F \u0939\u0948 \u091C\u094B Sprint \u0938\u0947 \u0906\u0917\u0947 \u092C\u0922\u093C\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u0924\u0948\u092F\u093E\u0930 \u0939\u0948\u0902\u0964 \u092A\u0942\u0930\u094D\u0923 \u0935\u093F\u0935\u0930\u0923: \u0915\u0941\u0932 \u0930\u093F\u091F\u0930\u094D\u0928: 10%\u0964 \u0905\u0935\u0927\u093F: 14 \u0926\u093F\u0928\u0964 \u0926\u0948\u0928\u093F\u0915 \u092A\u094D\u0930\u0924\u093F\u092B\u0932: \u0932\u0917\u092D\u0917 0.71%\u0964 \u0928\u094D\u092F\u0942\u0928\u0924\u092E \u091C\u092E\u093E: $1\u0964 \u0905\u0927\u093F\u0915\u0924\u092E \u091C\u092E\u093E: \u0905\u0938\u0940\u092E\u093F\u0924\u0964 \u0930\u093F\u091F\u0930\u094D\u0928 \u0935\u093F\u0924\u0930\u0923: \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924, \u092A\u094D\u0930\u0924\u093F\u0926\u093F\u0928 \u092E\u0927\u094D\u092F\u0930\u093E\u0924\u094D\u0930\u093F UTC \u092A\u0930\u0964 \u092A\u0942\u0902\u091C\u0940: \u091A\u0915\u094D\u0930 \u0915\u0947 \u0905\u0902\u0924 \u092E\u0947\u0902 \u092A\u0942\u0930\u0940 \u0924\u0930\u0939 \u0938\u0947 \u0935\u093E\u092A\u0938\u0964 \u0907\u0928\u0915\u0947 \u0932\u093F\u090F \u0906\u0926\u0930\u094D\u0936: \u0935\u0947 \u0928\u093F\u0935\u0947\u0936\u0915 \u091C\u093F\u0928\u094D\u0939\u094B\u0902\u0928\u0947 Sprint \u0915\u093E \u092A\u0930\u0940\u0915\u094D\u0937\u0923 \u0915\u093F\u092F\u093E \u0939\u0948 \u0914\u0930 \u0909\u091A\u094D\u091A \u0930\u093F\u091F\u0930\u094D\u0928 \u091A\u093E\u0939\u0924\u0947 \u0939\u0948\u0902, \u091C\u094B 2-\u0938\u092A\u094D\u0924\u093E\u0939 \u0915\u0940 \u092A\u094D\u0930\u0924\u093F\u092C\u0926\u094D\u0927\u0924\u093E \u0915\u0947 \u0938\u093E\u0925 \u0938\u0939\u091C \u0939\u0948\u0902, \u0914\u0930 \u0915\u0902\u092A\u093E\u0909\u0902\u0921\u093F\u0902\u0917 \u0930\u0923\u0928\u0940\u0924\u093F\u0915\u093E\u0930 \u091C\u094B \u0939\u0930 14 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 \u092A\u0941\u0928\u0930\u094D\u0928\u093F\u0935\u0947\u0936 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 Boost Loop \u0915\u0947\u0935\u0932 \u0926\u094B\u0917\u0941\u0928\u0947 \u0938\u092E\u092F \u092E\u0947\u0902 Sprint \u0915\u0947 \u0930\u093F\u091F\u0930\u094D\u0928 \u0915\u093E \u0924\u0940\u0928 \u0917\u0941\u0928\u093E \u0938\u0947 \u0905\u0927\u093F\u0915 \u092A\u094D\u0930\u0926\u093E\u0928 \u0915\u0930\u0924\u093E \u0939\u0948, \u091C\u093F\u0938\u0938\u0947 \u092F\u0939 TurboLoop \u0907\u0915\u094B\u0938\u093F\u0938\u094D\u091F\u092E \u092E\u0947\u0902 \u0938\u092C\u0938\u0947 \u0915\u0941\u0936\u0932 \u0915\u0926\u092E \u092C\u0928 \u091C\u093E\u0924\u093E \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 \u0915\u0941\u0932 \u0930\u093F\u091F\u0930\u094D\u0928: 10% | \u0905\u0935\u0927\u093F: 14 \u0926\u093F\u0928 | \u0926\u0948\u0928\u093F\u0915: ~0.71%\n\u2022 \u0915\u0947\u0935\u0932 2x \u0938\u092E\u092F \u092E\u0947\u0902 Sprint \u0915\u0947 \u0930\u093F\u091F\u0930\u094D\u0928 \u0915\u093E 3x \u0938\u0947 \u0905\u0927\u093F\u0915\n\u2022 \u0928\u094D\u092F\u0942\u0928\u0924\u092E \u091C\u092E\u093E: $1 | \u0905\u0927\u093F\u0915\u0924\u092E: \u0905\u0938\u0940\u092E\u093F\u0924\n\u2022 \u0930\u093F\u091F\u0930\u094D\u0928: \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u092A\u094D\u0930\u0924\u093F\u0926\u093F\u0928 \u092E\u0927\u094D\u092F\u0930\u093E\u0924\u094D\u0930\u093F UTC \u092A\u0930\n\u2022 \u0907\u0928\u0915\u0947 \u0932\u093F\u090F \u0906\u0926\u0930\u094D\u0936: \u0935\u093F\u0915\u093E\u0938-\u0915\u0947\u0902\u0926\u094D\u0930\u093F\u0924 \u0928\u093F\u0935\u0947\u0936\u0915, 14-\u0926\u093F\u0935\u0938\u0940\u092F \u0915\u0902\u092A\u093E\u0909\u0902\u0921\u093F\u0902\u0917 \u091A\u0915\u094D\u0930\n\n\u{1F48E} \u0905\u092A\u0928\u0947 \u0935\u093F\u0915\u093E\u0938 \u0915\u094B \u0917\u0924\u093F \u0926\u0947\u0902\u0964 \u0905\u092A\u0928\u0947 \u0930\u093F\u091F\u0930\u094D\u0928 \u0915\u094B \u092C\u0922\u093C\u093E\u090F\u0902\u0964 \u0905\u092A\u0928\u093E \u0938\u094D\u0924\u0930 \u092C\u0922\u093C\u093E\u090F\u0902\u0964\n\n\u{1F310} turboloop.io",
