      headline: "\u{1F537} Power Loop \u2014 \u092A\u0942\u0930\u094D\u0923 \u0935\u093F\u0935\u0930\u0923",
      caption: "\u{1F537} Power Loop \u2014 \u092A\u0942\u0930\u094D\u0923 \u0935\u093F\u0935\u0930\u0923\n\u2726 \u0917\u0902\u092D\u0940\u0930 \u0928\u093F\u0935\u0947\u0936\u0915\u094B\u0902 \u0915\u0947 \u0932\u093F\u090F \u0917\u0902\u092D\u0940\u0930 \u0930\u093F\u091F\u0930\u094D\u0928 \u2014 \u0939\u0930 \u0935\u093F\u0935\u0930\u0923\n\nPower Loop \u0905\u0928\u0941\u092D\u0935\u0940 \u0928\u093F\u0935\u0947\u0936\u0915\u094B\u0902 \u0915\u0947 \u092C\u0940\u091A TurboLoop \u0915\u093E \u0938\u092C\u0938\u0947 \u0932\u094B\u0915\u092A\u094D\u0930\u093F\u092F \u092A\u094D\u0932\u093E\u0928 \u0939\u0948, \u0914\u0930 \u0906\u0902\u0915\u0921\u093C\u0947 \u092C\u0924\u093E\u0924\u0947 \u0939\u0948\u0902 \u0915\u093F \u0910\u0938\u093E \u0915\u094D\u092F\u094B\u0902 \u0939\u0948\u0964 \u092A\u0942\u0930\u094D\u0923 \u0935\u093F\u0935\u0930\u0923: \u0915\u0941\u0932 \u0930\u093F\u091F\u0930\u094D\u0928: 24%\u0964 \u0905\u0935\u0927\u093F: 30 \u0926\u093F\u0928\u0964 \u0926\u0948\u0928\u093F\u0915 \u092A\u094D\u0930\u0924\u093F\u092B\u0932: \u0932\u0917\u092D\u0917 0.8%\u0964 \u0928\u094D\u092F\u0942\u0928\u0924\u092E \u091C\u092E\u093E: $1\u0964 \u0905\u0927\u093F\u0915\u0924\u092E \u091C\u092E\u093E: \u0905\u0938\u0940\u092E\u093F\u0924\u0964 \u0930\u093F\u091F\u0930\u094D\u0928 \u0935\u093F\u0924\u0930\u0923: \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924, \u092A\u094D\u0930\u0924\u093F\u0926\u093F\u0928 \u092E\u0927\u094D\u092F\u0930\u093E\u0924\u094D\u0930\u093F UTC \u092A\u0930\u0964 \u092A\u0942\u0902\u091C\u0940: \u091A\u0915\u094D\u0930 \u0915\u0947 \u0905\u0902\u0924 \u092E\u0947\u0902 \u092A\u0942\u0930\u0940 \u0924\u0930\u0939 \u0938\u0947 \u0935\u093E\u092A\u0938\u0964 \u0907\u0928\u0915\u0947 \u0932\u093F\u090F \u0906\u0926\u0930\u094D\u0936: \u0917\u0902\u092D\u0940\u0930 \u0928\u093F\u0935\u0947\u0936\u0915, \u0926\u0940\u0930\u094D\u0918\u0915\u093E\u0932\u093F\u0915 \u0915\u0902\u092A\u093E\u0909\u0902\u0921\u0930, \u0914\u0930 \u0935\u0947 \u091C\u094B \u0930\u093F\u091F\u0930\u094D\u0928 \u0914\u0930 \u0905\u0935\u0927\u093F \u0915\u0947 \u092C\u0940\u091A \u0907\u0937\u094D\u091F\u0924\u092E \u0938\u0902\u0924\u0941\u0932\u0928 \u091A\u093E\u0939\u0924\u0947 \u0939\u0948\u0902\u0964 \u091C\u092C \u092E\u093E\u0938\u093F\u0915 \u0930\u0942\u092A \u0938\u0947 \u0915\u0902\u092A\u093E\u0909\u0902\u0921 \u0915\u093F\u092F\u093E \u091C\u093E\u0924\u093E \u0939\u0948, \u0924\u094B Power Loop 12 \u092E\u0939\u0940\u0928\u094B\u0902 \u092E\u0947\u0902 $1,000 \u0915\u094B $13,220+ \u092E\u0947\u0902 \u092C\u0926\u0932 \u0926\u0947\u0924\u093E \u0939\u0948 \u2014 \u091C\u094B \u0907\u0938\u0947 \u0909\u0928 \u0927\u0928 \u0928\u093F\u0930\u094D\u092E\u093E\u0924\u093E\u0913\u0902 \u0915\u0947 \u0932\u093F\u090F \u092A\u0938\u0902\u0926\u0940\u0926\u093E \u092A\u094D\u0932\u093E\u0928 \u092C\u0928\u093E\u0924\u093E \u0939\u0948 \u091C\u094B \u092A\u0941\u0928\u0930\u094D\u0928\u093F\u0935\u0947\u0936 \u0915\u0940 \u0918\u093E\u0924\u0940\u092F \u0936\u0915\u094D\u0924\u093F \u0915\u094B \u0938\u092E\u091D\u0924\u0947 \u0939\u0948\u0902\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 \u0915\u0941\u0932 \u0930\u093F\u091F\u0930\u094D\u0928: 24% | \u0905\u0935\u0927\u093F: 30 \u0926\u093F\u0928 | \u0926\u0948\u0928\u093F\u0915: ~0.8%\n\u2022 \u0905\u0928\u0941\u092D\u0935\u0940 TurboLoop \u0928\u093F\u0935\u0947\u0936\u0915\u094B\u0902 \u0915\u0947 \u092C\u0940\u091A \u0938\u092C\u0938\u0947 \u0932\u094B\u0915\u092A\u094D\u0930\u093F\u092F \u092A\u094D\u0932\u093E\u0928\n\u2022 $1,000 \u092E\u093E\u0938\u093F\u0915 \u0930\u0942\u092A \u0938\u0947 \u0915\u0902\u092A\u093E\u0909\u0902\u0921\u0947\u0921 = 12 \u092E\u0939\u0940\u0928\u094B\u0902 \u092E\u0947\u0902 $13,220+\n\u2022 \u0928\u094D\u092F\u0942\u0928\u0924\u092E \u091C\u092E\u093E: $1 | \u0905\u0927\u093F\u0915\u0924\u092E: \u0905\u0938\u0940\u092E\u093F\u0924\n\u2022 \u0907\u0928\u0915\u0947 \u0932\u093F\u090F \u0906\u0926\u0930\u094D\u0936: \u0917\u0902\u092D\u0940\u0930 \u0928\u093F\u0935\u0947\u0936\u0915, \u092E\u093E\u0938\u093F\u0915 \u0915\u0902\u092A\u093E\u0909\u0902\u0921\u093F\u0902\u0917 \u0930\u0923\u0928\u0940\u0924\u093F\n\n\u{1F48E} \u0905\u0927\u093F\u0915\u0924\u092E \u0936\u0915\u094D\u0924\u093F\u0964 \u0905\u0927\u093F\u0915\u0924\u092E \u0930\u093F\u091F\u0930\u094D\u0928\u0964 \u0928\u093F\u0935\u0947\u0936\u0915 \u0915\u0940 \u092A\u0938\u0902\u0926\u0964\n\n\u{1F310} turboloop.io",
