      headline: "\u{1F537} ULTIMATE LOOP \u2014 \u092A\u0942\u0930\u094D\u0923 \u0935\u093F\u0935\u0930\u0923",
      caption: "\u{1F537} ULTIMATE LOOP \u2014 \u092A\u0942\u0930\u094D\u0923 \u0935\u093F\u0935\u0930\u0923\n\u2726 \u092F\u0940\u0932\u094D\u0921 \u0915\u093E \u0936\u093F\u0916\u0930 \u2014 \u0939\u0930 \u0935\u0939 \u0935\u093F\u0935\u0930\u0923 \u091C\u094B \u0906\u092A\u0915\u094B \u091C\u093E\u0928\u0928\u093E \u0906\u0935\u0936\u094D\u092F\u0915 \u0939\u0948\n\nUltimate Loop TurboLoop \u0915\u0940 \u092A\u0947\u0936\u0915\u0936 \u0915\u0947 \u0936\u093F\u0916\u0930 \u092A\u0930 \u0938\u094D\u0925\u093F\u0924 \u0939\u0948 \u2014 \u0909\u0928 \u0932\u094B\u0917\u094B\u0902 \u0915\u0947 \u0932\u093F\u090F \u0909\u091A\u094D\u091A\u0924\u092E \u092F\u0940\u0932\u094D\u0921 \u092F\u094B\u091C\u0928\u093E \u091C\u094B \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 \u0928\u0939\u0940\u0902, \u092C\u0932\u094D\u0915\u093F \u092E\u0939\u0940\u0928\u094B\u0902 \u092E\u0947\u0902 \u0938\u094B\u091A\u0924\u0947 \u0939\u0948\u0902\u0964 \u092A\u0942\u0930\u094D\u0923 \u0935\u093F\u0935\u0930\u0923: \u0915\u0941\u0932 \u0930\u093F\u091F\u0930\u094D\u0928: 54%\u0964 \u0905\u0935\u0927\u093F: 60 \u0926\u093F\u0928\u0964 \u0926\u0948\u0928\u093F\u0915 \u092F\u0940\u0932\u094D\u0921: \u0932\u0917\u092D\u0917 0.9%\u0964 \u0928\u094D\u092F\u0942\u0928\u0924\u092E \u091C\u092E\u093E: $1\u0964 \u0905\u0927\u093F\u0915\u0924\u092E \u091C\u092E\u093E: \u0905\u0938\u0940\u092E\u093F\u0924\u0964 \u0930\u093F\u091F\u0930\u094D\u0928 \u0935\u093F\u0924\u0930\u0923: \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924, \u092A\u094D\u0930\u0924\u093F\u0926\u093F\u0928 \u092E\u0927\u094D\u092F\u0930\u093E\u0924\u094D\u0930\u093F UTC \u092A\u0930\u0964 \u092A\u0942\u0902\u091C\u0940: \u091A\u0915\u094D\u0930 \u0915\u0947 \u0905\u0902\u0924 \u092E\u0947\u0902 \u092A\u0942\u0930\u0940 \u0924\u0930\u0939 \u0938\u0947 \u0935\u093E\u092A\u0938\u0964 \u0907\u0928\u0915\u0947 \u0932\u093F\u090F \u0906\u0926\u0930\u094D\u0936: \u0905\u0927\u093F\u0915\u0924\u092E \u092F\u0940\u0932\u094D\u0921 \u091A\u093E\u0939\u0928\u0947 \u0935\u093E\u0932\u0947 \u0927\u0948\u0930\u094D\u092F\u0935\u093E\u0928 \u0928\u093F\u0935\u0947\u0936\u0915, \u091C\u094B 60-\u0926\u093F\u0928 \u0915\u0940 \u092A\u094D\u0930\u0924\u093F\u092C\u0926\u094D\u0927\u0924\u093E \u0915\u0947 \u0938\u093E\u0925 \u0938\u0939\u091C \u0939\u0948\u0902, \u0914\u0930 \u0930\u0923\u0928\u0940\u0924\u093F\u0915 \u092F\u094B\u091C\u0928\u093E\u0915\u093E\u0930 \u091C\u094B \u0938\u092E\u091D\u0924\u0947 \u0939\u0948\u0902 \u0915\u093F \u0909\u091A\u094D\u091A\u0924\u092E \u0930\u093F\u091F\u0930\u094D\u0928 \u0938\u092C\u0938\u0947 \u0932\u0902\u092C\u0947 \u0927\u0948\u0930\u094D\u092F \u0915\u094B \u092A\u0941\u0930\u0938\u094D\u0915\u0943\u0924 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 60 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 54% \u092A\u0930, Ultimate Loop \u0910\u0938\u0947 \u0930\u093F\u091F\u0930\u094D\u0928 \u092A\u094D\u0930\u0926\u093E\u0928 \u0915\u0930\u0924\u093E \u0939\u0948 \u091C\u093F\u0928\u0915\u0940 \u092C\u0930\u093E\u092C\u0930\u0940 \u0905\u0927\u093F\u0915\u093E\u0902\u0936 \u092A\u093E\u0930\u0902\u092A\u0930\u093F\u0915 \u0928\u093F\u0935\u0947\u0936 \u092A\u0942\u0930\u0947 \u090F\u0915 \u0935\u0930\u094D\u0937 \u092E\u0947\u0902 \u092D\u0940 \u0928\u0939\u0940\u0902 \u0915\u0930 \u0938\u0915\u0924\u0947\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0906\u0915\u0930\u094D\u0937\u0923:\n\u2022 \u0915\u0941\u0932 \u0930\u093F\u091F\u0930\u094D\u0928: 54% | \u0905\u0935\u0927\u093F: 60 \u0926\u093F\u0928 | \u0926\u0948\u0928\u093F\u0915: ~0.9%\n\u2022 TurboLoop \u0907\u0915\u094B\u0938\u093F\u0938\u094D\u091F\u092E \u092E\u0947\u0902 \u0909\u092A\u0932\u092C\u094D\u0927 \u0909\u091A\u094D\u091A\u0924\u092E \u092F\u0940\u0932\u094D\u0921\n\u2022 60 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 54% \u0905\u0927\u093F\u0915\u093E\u0902\u0936 \u0935\u093E\u0930\u094D\u0937\u093F\u0915 \u092A\u093E\u0930\u0902\u092A\u0930\u093F\u0915 \u0930\u093F\u091F\u0930\u094D\u0928 \u0938\u0947 \u092C\u0947\u0939\u0924\u0930 \u092A\u094D\u0930\u0926\u0930\u094D\u0936\u0928 \u0915\u0930\u0924\u093E \u0939\u0948\n\u2022 \u0928\u094D\u092F\u0942\u0928\u0924\u092E \u091C\u092E\u093E: $1 | \u0905\u0927\u093F\u0915\u0924\u092E: \u0905\u0938\u0940\u092E\u093F\u0924\n\u2022 \u0907\u0928\u0915\u0947 \u0932\u093F\u090F \u0906\u0926\u0930\u094D\u0936: \u0927\u0948\u0930\u094D\u092F\u0935\u093E\u0928 \u0928\u093F\u0935\u0947\u0936\u0915, \u0905\u0927\u093F\u0915\u0924\u092E \u092F\u0940\u0932\u094D\u0921 \u091A\u093E\u0939\u0928\u0947 \u0935\u093E\u0932\u0947\n\n\u{1F48E} \u0938\u0930\u094D\u0935\u0936\u094D\u0930\u0947\u0937\u094D\u0920 \u092F\u094B\u091C\u0928\u093E\u0964 \u0938\u0930\u094D\u0935\u0936\u094D\u0930\u0947\u0937\u094D\u0920 \u0930\u093F\u091F\u0930\u094D\u0928\u0964 \u0938\u0930\u094D\u0935\u0936\u094D\u0930\u0947\u0937\u094D\u0920 \u0935\u093F\u091A\u093E\u0930\u0915\u094B\u0902 \u0915\u0947 \u0932\u093F\u090F\u0964\n\n\u{1F310} turboloop.io",
