      caption: "\u{1F537} \u0911\u0921\u093F\u091F\u0947\u0921 \u0914\u0930 \u0935\u0947\u0930\u093F\u092B\u093E\u0907\u0921 \u2014 \u0935\u093F\u0938\u094D\u0924\u0943\u0924\n\u2726 \u0911\u0921\u093F\u091F \u0915\u0947 \u0905\u0902\u0926\u0930 \u2014 99% \u0938\u094D\u0915\u094B\u0930 \u0915\u093E \u0935\u093E\u0938\u094D\u0924\u0935 \u092E\u0947\u0902 \u0915\u094D\u092F\u093E \u092E\u0924\u0932\u092C \u0939\u0948\n\nTurboLoop \u0915\u093E 99% \u0911\u0921\u093F\u091F \u091F\u094D\u0930\u0938\u094D\u091F \u0938\u094D\u0915\u094B\u0930 \u0938\u093F\u0930\u094D\u092B \u090F\u0915 \u0938\u0902\u0916\u094D\u092F\u093E \u0928\u0939\u0940\u0902 \u0939\u0948 \u2014 \u092F\u0939 Smart Contract \u0915\u0947 \u0939\u0930 \u092A\u0939\u0932\u0942 \u0915\u0947 \u0935\u094D\u092F\u093E\u092A\u0915 \u0938\u0941\u0930\u0915\u094D\u0937\u093E \u092E\u0942\u0932\u094D\u092F\u093E\u0902\u0915\u0928 \u0915\u093E \u092A\u094D\u0930\u0924\u093F\u0928\u093F\u0927\u093F\u0924\u094D\u0935 \u0915\u0930\u0924\u093E \u0939\u0948\u0964 \u0938\u094D\u0935\u0924\u0902\u0924\u094D\u0930 \u0911\u0921\u093F\u091F \u0928\u0947 \u091C\u093E\u0902\u091A \u0915\u0940: \u0905\u0928\u0941\u092C\u0902\u0927 \u0924\u0930\u094D\u0915 \u0914\u0930 \u0917\u0923\u093F\u0924\u0940\u092F \u0938\u091F\u0940\u0915\u0924\u093E, \u090F\u0915\u094D\u0938\u0947\u0938 \u0915\u0902\u091F\u094D\u0930\u094B\u0932 \u0924\u0902\u0924\u094D\u0930, \u0930\u0940\u090F\u0902\u091F\u094D\u0930\u0947\u0902\u0938\u0940 \u0938\u0941\u0930\u0915\u094D\u0937\u093E, \u0913\u0935\u0930\u092B\u094D\u0932\u094B/\u0905\u0902\u0921\u0930\u092B\u094D\u0932\u094B \u0938\u0941\u0930\u0915\u094D\u0937\u093E \u0909\u092A\u093E\u092F, \u0917\u0948\u0938 \u0905\u0928\u0941\u0915\u0942\u0932\u0928, \u0914\u0930 \u0938\u0902\u092D\u093E\u0935\u093F\u0924 \u0939\u092E\u0932\u0947 \u0915\u0947 \u0935\u0948\u0915\u094D\u091F\u0930\u0964 \u092A\u0930\u093F\u0923\u093E\u092E: \u0936\u0942\u0928\u094D\u092F \u0917\u0902\u092D\u0940\u0930 \u0915\u092E\u091C\u094B\u0930\u093F\u092F\u093E\u0902, \u0936\u0942\u0928\u094D\u092F \u0909\u091A\u094D\u091A-\u091C\u094B\u0916\u093F\u092E \u0935\u093E\u0932\u0947 \u092E\u0941\u0926\u094D\u0926\u0947, \u0914\u0930 \u090F\u0915 \u0905\u0928\u0941\u092C\u0902\u0927 \u0935\u093E\u0938\u094D\u0924\u0941\u0915\u0932\u093E \u091C\u093F\u0938\u0947 BSC \u092A\u0930 \u0938\u092C\u0938\u0947 \u0938\u0941\u0930\u0915\u094D\u0937\u093F\u0924 \u092E\u093E\u0928\u093E \u0917\u092F\u093E \u0939\u0948\u0964 \u092A\u0942\u0930\u0940 \u0911\u0921\u093F\u091F \u0930\u093F\u092A\u094B\u0930\u094D\u091F \u0938\u093E\u0930\u094D\u0935\u091C\u0928\u093F\u0915 \u0930\u0942\u092A \u0938\u0947 \u0909\u092A\u0932\u092C\u094D\u0927 \u0939\u0948, \u091C\u093F\u0938\u092E\u0947\u0902 \u0915\u093F\u090F \u0917\u090F \u0939\u0930 \u092A\u0930\u0940\u0915\u094D\u0937\u0923 \u0914\u0930 \u092A\u094D\u0930\u0932\u0947\u0916\u093F\u0924 \u0939\u0930 \u0928\u093F\u0937\u094D\u0915\u0930\u094D\u0937 \u0915\u093E \u0935\u093F\u0935\u0930\u0923 \u0939\u0948\u0964 BscScan \u092A\u0930 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u0938\u094D\u0930\u094B\u0924 \u0915\u094B\u0921, \u0924\u094D\u092F\u093E\u0917 \u0915\u093F\u090F \u0917\u090F \u0938\u094D\u0935\u093E\u092E\u093F\u0924\u094D\u0935 \u0914\u0930 \u0938\u094D\u0925\u093E\u092F\u0940 \u0930\u0942\u092A \u0938\u0947 \u0932\u0949\u0915 \u0915\u093F\u090F \u0917\u090F LP \u0915\u0947 \u0938\u093E\u0925, TurboLoop \u0915\u093E \u0938\u0941\u0930\u0915\u094D\u0937\u093E \u0938\u094D\u091F\u0948\u0915 \u0935\u094D\u092F\u093E\u092A\u0915, \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u092F\u094B\u0917\u094D\u092F \u0914\u0930 \u0938\u092E\u091D\u094C\u0924\u093E \u0928 \u0915\u0930\u0928\u0947 \u0935\u093E\u0932\u093E \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 \u0935\u094D\u092F\u093E\u092A\u0915 \u0938\u094D\u0935\u0924\u0902\u0924\u094D\u0930 \u0938\u0941\u0930\u0915\u094D\u0937\u093E \u0911\u0921\u093F\u091F \u0938\u0947 99% \u091F\u094D\u0930\u0938\u094D\u091F \u0938\u094D\u0915\u094B\u0930\n\u2022 \u0936\u0942\u0928\u094D\u092F \u0917\u0902\u092D\u0940\u0930 \u0915\u092E\u091C\u094B\u0930\u093F\u092F\u093E\u0902, \u0936\u0942\u0928\u094D\u092F \u0909\u091A\u094D\u091A-\u091C\u094B\u0916\u093F\u092E \u0935\u093E\u0932\u0947 \u092E\u0941\u0926\u094D\u0926\u0947 \u092A\u093E\u090F \u0917\u090F\n\u2022 \u0911\u0921\u093F\u091F \u092E\u0947\u0902 \u0936\u093E\u092E\u093F\u0932: \u0924\u0930\u094D\u0915, \u090F\u0915\u094D\u0938\u0947\u0938 \u0915\u0902\u091F\u094D\u0930\u094B\u0932, \u0930\u0940\u090F\u0902\u091F\u094D\u0930\u0947\u0902\u0938\u0940, \u0913\u0935\u0930\u092B\u094D\u0932\u094B \u0938\u0941\u0930\u0915\u094D\u0937\u093E\n\u2022 \u092A\u0942\u0930\u0940 \u0911\u0921\u093F\u091F \u0930\u093F\u092A\u094B\u0930\u094D\u091F \u0915\u093F\u0938\u0940 \u0915\u0947 \u092D\u0940 \u0938\u092E\u0940\u0915\u094D\u0937\u093E \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u0938\u093E\u0930\u094D\u0935\u091C\u0928\u093F\u0915 \u0930\u0942\u092A \u0938\u0947 \u0909\u092A\u0932\u092C\u094D\u0927 \u0939\u0948\n\u2022 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u0915\u094B\u0921, \u0924\u094D\u092F\u093E\u0917 \u0915\u093F\u090F \u0917\u090F \u0938\u094D\u0935\u093E\u092E\u093F\u0924\u094D\u0935 \u0914\u0930 \u0932\u0949\u0915 \u0915\u093F\u090F \u0917\u090F LP \u0915\u0947 \u0938\u093E\u0925 \u0938\u0902\u092F\u0941\u0915\u094D\u0924\n\n\u{1F48E} \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924\u0964 \u0911\u0921\u093F\u091F\u0947\u0921\u0964 \u0938\u0941\u0930\u0915\u094D\u0937\u093F\u0924\u0964 \u0939\u0930 \u092A\u0930\u0924 \u0915\u0940 \u091C\u093E\u0902\u091A \u0914\u0930 \u092A\u0941\u0937\u094D\u091F\u093F \u0915\u0940 \u0917\u0908\u0964\n\n\u{1F310} turboloop.io",
