      original: "55_Ownership_Detail.png",
      headline: "\u{1F537} \u0938\u094D\u0935\u093E\u092E\u093F\u0924\u094D\u0935 \u0924\u094D\u092F\u093E\u0917 (OWNERSHIP RENOUNCED) \u2014 \u0935\u093F\u0938\u094D\u0924\u0943\u0924 \u091C\u093E\u0928\u0915\u093E\u0930\u0940",
      caption: "\u{1F537} \u0938\u094D\u0935\u093E\u092E\u093F\u0924\u094D\u0935 \u0924\u094D\u092F\u093E\u0917 (OWNERSHIP RENOUNCED) \u2014 \u0935\u093F\u0938\u094D\u0924\u0943\u0924 \u091C\u093E\u0928\u0915\u093E\u0930\u0940\n\u2726 \u0921\u0947\u0921 \u090F\u0921\u094D\u0930\u0947\u0938 \u2014 \u0906\u092A\u0915\u0940 \u0938\u0941\u0930\u0915\u094D\u0937\u093E \u0915\u0947 \u0932\u093F\u090F \u0907\u0938\u0915\u093E \u0915\u094D\u092F\u093E \u0905\u0930\u094D\u0925 \u0939\u0948\n\n\u091C\u092C TurboLoop \u0915\u093E \u0938\u094D\u0935\u093E\u092E\u093F\u0924\u094D\u0935 \u0924\u094D\u092F\u093E\u0917 \u0926\u093F\u092F\u093E \u0917\u092F\u093E, \u0924\u094B \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0915\u0947 \u090F\u0921\u092E\u093F\u0928 \u0935\u093F\u0936\u0947\u0937\u093E\u0927\u093F\u0915\u093E\u0930 \u0938\u094D\u0925\u093E\u092F\u0940 \u0930\u0942\u092A \u0938\u0947 \u0921\u0947\u0921 \u090F\u0921\u094D\u0930\u0947\u0938: 0x000...dead \u092A\u0930 \u0938\u094D\u0925\u093E\u0928\u093E\u0902\u0924\u0930\u093F\u0924 \u0915\u0930 \u0926\u093F\u090F \u0917\u090F\u0964 \u092F\u0939 \u090F\u0915\u0924\u0930\u092B\u093E, \u0905\u092A\u0930\u093F\u0935\u0930\u094D\u0924\u0928\u0940\u092F \u0915\u093E\u0930\u094D\u0930\u0935\u093E\u0908 \u0939\u0948 \u091C\u093F\u0938\u0915\u0947 \u0917\u0939\u0930\u0947 \u0938\u0941\u0930\u0915\u094D\u0937\u093E \u0928\u093F\u0939\u093F\u0924\u093E\u0930\u094D\u0925 \u0939\u0948\u0902\u0964 \u0907\u0938\u0915\u093E \u0905\u0930\u094D\u0925 \u0939\u0948: \u0915\u094B\u0908 \u092D\u0940 \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0915\u0947 \u0915\u094B\u0921 \u092F\u093E \u0932\u0949\u091C\u093F\u0915 \u0915\u094B \u0938\u0902\u0936\u094B\u0927\u093F\u0924 \u0928\u0939\u0940\u0902 \u0915\u0930 \u0938\u0915\u0924\u093E\u0964 \u0915\u094B\u0908 \u092D\u0940 \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0915\u094B \u0930\u094B\u0915 (pause) \u092F\u093E \u092B\u094D\u0930\u0940\u091C (freeze) \u0928\u0939\u0940\u0902 \u0915\u0930 \u0938\u0915\u0924\u093E\u0964 \u0915\u094B\u0908 \u092D\u0940 \u0906\u092A\u093E\u0924\u0915\u093E\u0932\u0940\u0928 \u0928\u093F\u0915\u093E\u0938\u0940 \u092B\u093C\u0902\u0915\u094D\u0936\u0928 \u0928\u0939\u0940\u0902 \u091C\u094B\u0921\u093C \u0938\u0915\u0924\u093E\u0964 \u0915\u094B\u0908 \u092D\u0940 \u0936\u0941\u0932\u094D\u0915 \u0938\u0902\u0930\u091A\u0928\u093E \u092F\u093E \u0930\u093F\u091F\u0930\u094D\u0928 \u0926\u0930\u0947\u0902 \u0928\u0939\u0940\u0902 \u092C\u0926\u0932 \u0938\u0915\u0924\u093E\u0964 \u0915\u094B\u0908 \u092D\u0940 \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0915\u094B \u0905\u092A\u0917\u094D\u0930\u0947\u0921 \u092F\u093E \u092E\u093E\u0907\u0917\u094D\u0930\u0947\u091F \u0928\u0939\u0940\u0902 \u0915\u0930 \u0938\u0915\u0924\u093E\u0964 \u0915\u094B\u0908 \u092D\u0940 \u0909\u092A\u092F\u094B\u0917\u0915\u0930\u094D\u0924\u093E \u0915\u0947 \u092B\u0902\u0921 \u0924\u0915 \u092A\u0939\u0941\u0902\u091A \u092F\u093E \u0909\u0938\u0947 \u092A\u0941\u0928\u0930\u094D\u0928\u093F\u0930\u094D\u0926\u0947\u0936\u093F\u0924 \u0928\u0939\u0940\u0902 \u0915\u0930 \u0938\u0915\u0924\u093E\u0964 \u091C\u092C \u0924\u0915 Binance Smart Chain \u092E\u094C\u091C\u0942\u0926 \u0939\u0948, \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u092C\u093F\u0932\u094D\u0915\u0941\u0932 \u0935\u0948\u0938\u0947 \u0939\u0940 \u0928\u093F\u0937\u094D\u092A\u093E\u0926\u093F\u0924 \u0939\u094B\u0917\u093E \u091C\u0948\u0938\u093E \u0932\u093F\u0916\u093E \u0917\u092F\u093E \u0939\u0948, \u092A\u0942\u0930\u0940 \u0924\u0930\u0939 \u0938\u0947 \u0938\u094D\u0935\u093E\u092F\u0924\u094D\u0924 \u0930\u0942\u092A \u0938\u0947\u0964 \u0906\u092A BscScan \u092A\u0930 \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0915\u0947 \u0913\u0928\u0930 \u090F\u0921\u094D\u0930\u0947\u0938 \u0915\u0940 \u091C\u093E\u0902\u091A \u0915\u0930\u0915\u0947 \u0938\u094D\u0935\u092F\u0902 \u0907\u0938\u0947 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u0915\u0930 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964 \u092F\u0939 \u0915\u094B\u0908 \u0935\u093E\u0926\u093E \u0928\u0939\u0940\u0902 \u0939\u0948 \u2014 \u092F\u0939 \u090F\u0915 \u0911\u0928-\u091A\u0947\u0928 \u0924\u0925\u094D\u092F \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 \u0913\u0928\u0930 \u090F\u0921\u094D\u0930\u0947\u0938: 0x000...dead \u2014 \u0938\u094D\u0925\u093E\u092F\u0940 \u0914\u0930 \u0905\u092A\u0930\u093F\u0935\u0930\u094D\u0924\u0928\u0940\u092F \u0930\u0942\u092A \u0938\u0947 \u0938\u0947\u091F\n\u2022 \u0915\u094B\u0908 \u0915\u094B\u0921 \u0938\u0902\u0936\u094B\u0927\u0928 \u0938\u0902\u092D\u0935 \u0928\u0939\u0940\u0902 \u2014 \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0905\u0902\u0924\u093F\u092E \u0939\u0948\n\u2022 \u0915\u094B\u0908 \u092A\u0949\u091C\u093C, \u092B\u093C\u094D\u0930\u0940\u091C\u093C \u092F\u093E \u0906\u092A\u093E\u0924\u0915\u093E\u0932\u0940\u0928 \u092B\u093C\u0902\u0915\u094D\u0936\u0928 \u0928\u0939\u0940\u0902 \u091C\u094B\u0921\u093C\u0947 \u091C\u093E \u0938\u0915\u0924\u0947\n\u2022 \u0915\u094B\u0908 \u0936\u0941\u0932\u094D\u0915 \u092A\u0930\u093F\u0935\u0930\u094D\u0924\u0928, \u0926\u0930 \u092A\u0930\u093F\u0935\u0930\u094D\u0924\u0928, \u092F\u093E \u0932\u0949\u091C\u093F\u0915 \u0905\u092A\u0921\u0947\u091F \u0938\u0902\u092D\u0935 \u0928\u0939\u0940\u0902\n\u2022 BscScan \u092A\u0930 \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u092F\u094B\u0917\u094D\u092F \u2014 \u0938\u094D\u0935\u092F\u0902 \u0913\u0928\u0930 \u090F\u0921\u094D\u0930\u0947\u0938 \u0915\u0940 \u091C\u093E\u0902\u091A \u0915\u0930\u0947\u0902\n\n\u{1F48E} \u0915\u094B\u0921 \u0905\u0902\u0924\u093F\u092E \u0939\u0948\u0964 \u0928\u093F\u092F\u092E \u0924\u092F \u0939\u0948\u0902\u0964 \u0939\u092E\u0947\u0936\u093E \u0915\u0947 \u0932\u093F\u090F \u0905\u092A\u0930\u093F\u0935\u0930\u094D\u0924\u0928\u0940\u092F\u0964\n\n\u{1F310} turboloop.io",
