      headline: "\u{1F537} \u0926\u0948\u0928\u093F\u0915 \u0915\u092E\u093E\u0908 \u2014 \u0935\u093F\u0938\u094D\u0924\u0943\u0924",
      caption: "\u{1F537} \u0926\u0948\u0928\u093F\u0915 \u0915\u092E\u093E\u0908 \u2014 \u0935\u093F\u0938\u094D\u0924\u0943\u0924\n\u2726 \u0906\u092A\u0915\u0947 \u0926\u0948\u0928\u093F\u0915 \u0930\u093F\u091F\u0930\u094D\u0928 \u0915\u0947 \u092A\u0940\u091B\u0947 \u0915\u0940 \u0915\u093E\u0930\u094D\u092F\u092A\u094D\u0930\u0923\u093E\u0932\u0940\n\n\u092F\u0939\u093E\u0901 \u092C\u0924\u093E\u092F\u093E \u0917\u092F\u093E \u0939\u0948 \u0915\u093F TurboLoop \u0915\u093E \u0926\u0948\u0928\u093F\u0915 \u0915\u092E\u093E\u0908 \u0924\u0902\u0924\u094D\u0930 \u0935\u093E\u0938\u094D\u0924\u0935 \u092E\u0947\u0902 \u0915\u0948\u0938\u0947 \u0915\u093E\u092E \u0915\u0930\u0924\u093E \u0939\u0948\u0964 \u0939\u0930 \u0926\u093F\u0928 \u0920\u0940\u0915 00:00 UTC \u092A\u0930, Smart Contract \u0905\u092A\u0928\u0947 \u092F\u0940\u0932\u094D\u0921 \u0915\u0948\u0932\u0915\u0941\u0932\u0947\u0936\u0928 \u092B\u093C\u0902\u0915\u094D\u0936\u0928 \u0915\u094B \u0928\u093F\u0937\u094D\u092A\u093E\u0926\u093F\u0924 \u0915\u0930\u0924\u093E \u0939\u0948\u0964 \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 \u0938\u0915\u094D\u0930\u093F\u092F \u091C\u092E\u093E \u0915\u0947 \u0932\u093F\u090F, \u092F\u0939 \u092A\u094D\u0932\u093E\u0928 \u0915\u0940 \u0926\u0930 \u0915\u0947 \u0906\u0927\u093E\u0930 \u092A\u0930 \u0926\u0948\u0928\u093F\u0915 \u0930\u093F\u091F\u0930\u094D\u0928 \u0915\u0940 \u0917\u0923\u0928\u093E \u0915\u0930\u0924\u093E \u0939\u0948: Sprint (~0.43%), Boost (~0.71%), Power (~0.8%), \u092F\u093E Ultimate (~0.9%)\u0964 \u092F\u0939 \u0917\u0923\u0928\u093E \u0915\u0940 \u0917\u0908 \u0930\u093E\u0936\u093F \u092B\u093F\u0930 \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u0906\u092A\u0915\u0947 \u0909\u092A\u0932\u092C\u094D\u0927 \u092C\u0948\u0932\u0947\u0902\u0938 \u092E\u0947\u0902 \u091C\u0941\u0921\u093C \u091C\u093E\u0924\u0940 \u0939\u0948\u0964 \u0906\u092A\u0915\u0940 \u0913\u0930 \u0938\u0947 \u0915\u093F\u0938\u0940 \u0932\u0947\u0928\u0926\u0947\u0928 \u0915\u0940 \u0906\u0935\u0936\u094D\u092F\u0915\u0924\u093E \u0928\u0939\u0940\u0902 \u0939\u0948 \u2014 \u0915\u094B\u0908 \u0917\u0948\u0938 \u0936\u0941\u0932\u094D\u0915 \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u0926\u093E\u0935\u093E \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u092D\u0940 \u0907\u0902\u091F\u0930\u0948\u0915\u094D\u0936\u0928 \u0928\u0939\u0940\u0902\u0964 \u092F\u0939 \u092A\u094D\u0930\u0915\u094D\u0930\u093F\u092F\u093E \u0939\u0930 24 \u0918\u0902\u091F\u0947 \u092E\u0947\u0902 \u0917\u0923\u093F\u0924\u0940\u092F \u0938\u091F\u0940\u0915\u0924\u093E \u0915\u0947 \u0938\u093E\u0925 \u0924\u092C \u0924\u0915 \u0926\u094B\u0939\u0930\u093E\u0908 \u091C\u093E\u0924\u0940 \u0939\u0948 \u091C\u092C \u0924\u0915 \u0915\u093F \u0906\u092A\u0915\u0947 \u092A\u094D\u0932\u093E\u0928 \u0915\u093E \u091A\u0915\u094D\u0930 \u092A\u0942\u0930\u093E \u0928\u0939\u0940\u0902 \u0939\u094B \u091C\u093E\u0924\u093E\u0964 \u0909\u0938 \u0938\u092E\u092F, \u0906\u092A\u0915\u0940 \u092A\u0942\u0930\u0940 \u092A\u0942\u0902\u091C\u0940 \u0914\u0930 \u0938\u092D\u0940 \u0938\u0902\u091A\u093F\u0924 \u0926\u0948\u0928\u093F\u0915 \u0930\u093F\u091F\u0930\u094D\u0928 \u0928\u093F\u0915\u093E\u0938\u0940 \u0915\u0947 \u0932\u093F\u090F \u0909\u092A\u0932\u092C\u094D\u0927 \u0939\u094B \u091C\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 \u0906\u092A TurboLoop \u0921\u0948\u0936\u092C\u094B\u0930\u094D\u0921 \u0915\u0947 \u092E\u093E\u0927\u094D\u092F\u092E \u0938\u0947 \u0935\u093E\u0938\u094D\u0924\u0935\u093F\u0915 \u0938\u092E\u092F \u092E\u0947\u0902 \u0939\u0930 \u0917\u0923\u0928\u093E \u0915\u094B \u091F\u094D\u0930\u0948\u0915 \u0915\u0930 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 \u0917\u0923\u0928\u093E \u091F\u094D\u0930\u093F\u0917\u0930: \u0939\u0930 24 \u0918\u0902\u091F\u0947 \u092E\u0947\u0902 \u0920\u0940\u0915 00:00 UTC\n\u2022 \u0926\u0948\u0928\u093F\u0915 \u0926\u0930\u0947\u0902: Sprint ~0.43%, Boost ~0.71%, Power ~0.8%, Ultimate ~0.9%\n\u2022 \u0930\u093F\u091F\u0930\u094D\u0928 \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u092C\u0948\u0932\u0947\u0902\u0938 \u092E\u0947\u0902 \u091C\u0941\u0921\u093C \u091C\u093E\u0924\u0947 \u0939\u0948\u0902 \u2014 \u0909\u092A\u092F\u094B\u0917\u0915\u0930\u094D\u0924\u093E \u0915\u0940 \u0915\u093F\u0938\u0940 \u0915\u093E\u0930\u094D\u0930\u0935\u093E\u0908 \u0915\u0940 \u0906\u0935\u0936\u094D\u092F\u0915\u0924\u093E \u0928\u0939\u0940\u0902\n\u2022 \u0926\u0948\u0928\u093F\u0915 \u0915\u092E\u093E\u0908 \u0915\u0947 \u0932\u093F\u090F \u0915\u094B\u0908 \u0917\u0948\u0938 \u0936\u0941\u0932\u094D\u0915 \u0928\u0939\u0940\u0902 \u2014 \u0905\u0928\u0941\u092C\u0902\u0927 \u0938\u092C \u0915\u0941\u091B \u0938\u0902\u092D\u093E\u0932\u0924\u093E \u0939\u0948\n\u2022 \u091A\u0915\u094D\u0930 \u0915\u0947 \u0905\u0902\u0924 \u092E\u0947\u0902 \u092A\u0942\u0930\u0940 \u092A\u0942\u0902\u091C\u0940 + \u0938\u0902\u091A\u093F\u0924 \u0930\u093F\u091F\u0930\u094D\u0928 \u0909\u092A\u0932\u092C\u094D\u0927\n\n\u{1F48E} \u0938\u091F\u0940\u0915\u0924\u093E\u0964 \u0938\u094D\u0935\u091A\u093E\u0932\u0928\u0964 \u0939\u0930 \u0926\u093F\u0928\u0964 \u0939\u0930 \u091A\u0915\u094D\u0930\u0964 \u092C\u093F\u0928\u093E \u0915\u093F\u0938\u0940 \u091A\u0942\u0915 \u0915\u0947\u0964\n\n\u{1F310} turboloop.io",
