      original: "02_Limaza_TurboLoop.png",
      headline: "\u{1F537} \u0627\u0644\u0631\u0643\u0627\u0626\u0632 \u0627\u0644\u0633\u062A \u0644\u0644\u062B\u0642\u0629",
      caption: "\u{1F537} \u0627\u0644\u0631\u0643\u0627\u0626\u0632 \u0627\u0644\u0633\u062A \u0644\u0644\u062B\u0642\u0629\n\u2726 \u0644\u0645\u0627\u0630\u0627 \u062A\u062A\u0641\u0631\u062F TurboLoop \u2014 \u0645\u0628\u0646\u064A\u0629 \u0639\u0644\u0649 \u0623\u0633\u0633 \u0631\u0627\u0633\u062E\u0629 \u0644\u0627 \u062A\u062A\u0632\u0639\u0632\u0639\n\n\u0641\u064A \u0645\u0634\u0647\u062F DeFi \u0627\u0644\u0645\u0644\u064A\u0621 \u0628\u0639\u0645\u0644\u064A\u0627\u062A \u0633\u062D\u0628 \u0627\u0644\u0628\u0633\u0627\u0637 \u0648\u0627\u0644\u0648\u0639\u0648\u062F \u0627\u0644\u0643\u0627\u0630\u0628\u0629\u060C \u062A\u0645\u062A \u0647\u0646\u062F\u0633\u0629 TurboLoop \u0645\u0646 \u0627\u0644\u0635\u0641\u0631 \u0628\u0633\u062A \u0631\u0643\u0627\u0626\u0632 \u0644\u0644\u062B\u0642\u0629 \u063A\u064A\u0631 \u0642\u0627\u0628\u0644\u0629 \u0644\u0644\u0645\u0633\u0627\u0648\u0645\u0629. \u062A\u0645 \u062A\u062F\u0642\u064A\u0642 \u0643\u0644 \u0633\u0637\u0631 \u0645\u0646 \u0627\u0644\u0643\u0648\u062F \u0628\u0634\u0643\u0644 \u0645\u0633\u062A\u0642\u0644 \u0645\u0639 \u062F\u0631\u062C\u0629 \u062B\u0642\u0629 99%. \u062A\u0645 \u062D\u0631\u0642 \u0645\u0641\u0627\u062A\u064A\u062D \u0627\u0644\u0625\u062F\u0627\u0631\u0629 \u0628\u0634\u0643\u0644 \u062F\u0627\u0626\u0645 \u2014 \u062A\u0645 \u0627\u0644\u062A\u0646\u0627\u0632\u0644 \u0639\u0646 \u0627\u0644\u0645\u0644\u0643\u064A\u0629 \u0644\u0644\u0639\u0646\u0648\u0627\u0646 \u0627\u0644\u0645\u064A\u062A\u060C \u0645\u0645\u0627 \u064A\u0639\u0646\u064A \u0623\u0646\u0647 \u0644\u0627 \u064A\u0645\u0643\u0646 \u0644\u0623\u064A \u0625\u0646\u0633\u0627\u0646 \u062A\u0639\u062F\u064A\u0644 \u0627\u0644\u0639\u0642\u062F \u0623\u0628\u062F\u064B\u0627. \u0645\u062C\u0645\u0639 \u0627\u0644\u0633\u064A\u0648\u0644\u0629 (LP) \u0645\u0642\u0641\u0644 \u0644\u0644\u0623\u0628\u062F\u060C \u0645\u0645\u0627 \u064A\u0642\u0636\u064A \u0639\u0644\u0649 \u0623\u064A \u0627\u062D\u062A\u0645\u0627\u0644 \u0644\u0639\u0645\u0644\u064A\u0629 \u0633\u062D\u0628 \u0627\u0644\u0628\u0633\u0627\u0637. \u0627\u0644\u0643\u0648\u062F \u0627\u0644\u0645\u0635\u062F\u0631\u064A \u062A\u0645 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646\u0647 \u0628\u0627\u0644\u0643\u0627\u0645\u0644 \u0639\u0644\u0649 BscScan \u0644\u064A\u0642\u0631\u0623\u0647 \u0648\u064A\u062F\u0642\u0642\u0647 \u0623\u064A \u0634\u062E\u0635. \u0644\u0627 \u064A\u064F\u0637\u0644\u0628 KYC \u2014 \u0645\u062D\u0641\u0638\u062A\u0643 \u0647\u064A \u0647\u0648\u064A\u062A\u0643. \u0648\u0627\u0644\u0628\u0631\u0648\u062A\u0648\u0643\u0648\u0644 \u063A\u064A\u0631 \u0627\u062D\u062A\u062C\u0627\u0632\u064A \u0628\u0646\u0633\u0628\u0629 100% \u2014 \u0644\u0627 \u062A\u062D\u062A\u0641\u0638 TurboLoop \u0628\u0623\u0645\u0648\u0627\u0644\u0643 \u0623\u0628\u062F\u064B\u0627. \u0647\u0630\u0647 \u0644\u064A\u0633\u062A \u0648\u0639\u0648\u062F\u064B\u0627 \u062A\u0633\u0648\u064A\u0642\u064A\u0629\u061B \u0625\u0646\u0647\u0627 \u062D\u0642\u0627\u0626\u0642 \u064A\u0645\u0643\u0646 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646\u0647\u0627 \u0639\u0644\u0649 \u0627\u0644\u0633\u0644\u0633\u0644\u0629.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u0645\u062F\u0642\u0642\u0629 \u0648\u0645\u0648\u062B\u0642\u0629 \u2014 \u062F\u0631\u062C\u0629 \u062B\u0642\u0629 99% \u0645\u0646 \u062A\u062F\u0642\u064A\u0642 \u0645\u0633\u062A\u0642\u0644\n\u2022 \u0627\u0644\u062A\u0646\u0627\u0632\u0644 \u0639\u0646 \u0627\u0644\u0645\u0644\u0643\u064A\u0629 \u2014 \u062A\u0645 \u062D\u0631\u0642 \u0645\u0641\u0627\u062A\u064A\u062D \u0627\u0644\u0625\u062F\u0627\u0631\u0629\u060C \u0627\u0644\u0639\u0646\u0648\u0627\u0646: 0x000...dead\n\u2022 LP \u0645\u0642\u0641\u0644 \u0644\u0644\u0623\u0628\u062F \u2014 \u0644\u0627 \u064A\u0645\u0643\u0646 \u0633\u062D\u0628 \u0627\u0644\u0628\u0633\u0627\u0637\u060C \u0627\u0644\u0633\u064A\u0648\u0644\u0629 \u0645\u0624\u0645\u0646\u0629 \u0628\u0634\u0643\u0644 \u062F\u0627\u0626\u0645\n\u2022 \u0644\u0627 \u064A\u064F\u0637\u0644\u0628 KYC \u2014 \u062E\u0635\u0648\u0635\u064A\u0629 \u062A\u0627\u0645\u0629\u060C \u0645\u062D\u0641\u0638\u062A\u0643 \u0647\u064A \u0647\u0648\u064A\u062A\u0643\n\u2022 \u0627\u0644\u0643\u0648\u062F \u062A\u0645 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646\u0647 \u0639\u0644\u0649 BscScan \u2014 \u0645\u0641\u062A\u0648\u062D \u0627\u0644\u0645\u0635\u062F\u0631\u060C \u0634\u0641\u0627\u0641\u060C \u064A\u0645\u0643\u0646 \u0644\u0623\u064A \u0634\u062E\u0635 \u0642\u0631\u0627\u0621\u062A\u0647\n\n\u{1F48E} \u0633\u062A \u0631\u0643\u0627\u0626\u0632 \u0644\u0644\u062B\u0642\u0629. \u0628\u0631\u0648\u062A\u0648\u0643\u0648\u0644 \u0648\u0627\u062D\u062F. \u0635\u0641\u0631 \u062A\u0646\u0627\u0632\u0644\u0627\u062A.\n\n\u{1F310} turboloop.io",
