      original: "04_Smart_Contract.png",
      headline: "\u{1F537} \u0645\u0627 \u0647\u0648 \u0627\u0644\u0640 Smart Contract\u061F",
      caption: "\u{1F537} \u0645\u0627 \u0647\u0648 \u0627\u0644\u0640 Smart Contract\u061F  \n\u2726 \u0643\u0648\u062F \u0630\u0627\u062A\u064A \u0627\u0644\u062A\u0646\u0641\u064A\u0630 \u064A\u062D\u0644 \u0645\u062D\u0644 \u0627\u0644\u062B\u0642\u0629 \u0628\u0627\u0644\u062A\u062D\u0642\u0642\n\n\u0627\u0644\u0640 Smart Contract \u0647\u0648 \u0628\u0631\u0646\u0627\u0645\u062C \u0630\u0627\u062A\u064A \u0627\u0644\u062A\u0646\u0641\u064A\u0630 \u064A\u062A\u0645 \u0646\u0634\u0631\u0647 \u0639\u0644\u0649 \u0627\u0644\u0628\u0644\u0648\u0643\u0634\u064A\u0646 \u0648\u064A\u0642\u0648\u0645 \u062A\u0644\u0642\u0627\u0626\u064A\u064B\u0627 \u0628\u0641\u0631\u0636 \u0627\u0644\u0642\u0648\u0627\u0639\u062F \u0627\u0644\u0645\u0643\u062A\u0648\u0628\u0629 \u0641\u064A \u0643\u0648\u062F\u0647 \u2014 \u062F\u0648\u0646 \u0623\u064A \u062A\u062F\u062E\u0644 \u0628\u0634\u0631\u064A. \u0628\u0645\u062C\u0631\u062F \u0646\u0634\u0631\u0647\u060C \u0644\u0627 \u064A\u0645\u0643\u0646 \u062A\u063A\u064A\u064A\u0631\u0647 \u0623\u0648 \u0625\u064A\u0642\u0627\u0641\u0647 \u0623\u0648 \u0627\u0644\u062A\u0644\u0627\u0639\u0628 \u0628\u0647 \u0645\u0646 \u0642\u0628\u0644 \u0623\u064A \u0634\u062E\u0635\u060C \u0628\u0645\u0627 \u0641\u064A \u0630\u0644\u0643 \u0645\u0646\u0634\u0626\u064A\u0647. \u0641\u0643\u0631 \u0641\u064A\u0647 \u0643\u0627\u062A\u0641\u0627\u0642 \u0631\u0642\u0645\u064A \u064A\u0646\u0641\u0630 \u0646\u0641\u0633\u0647: \u0625\u0630\u0627 \u062A\u062D\u0642\u0642 \u0627\u0644\u0634\u0631\u0637 A\u060C \u064A\u062D\u062F\u062B \u0627\u0644\u0625\u062C\u0631\u0627\u0621 B \u062A\u0644\u0642\u0627\u0626\u064A\u064B\u0627. \u064A\u0639\u0645\u0644 TurboLoop \u0628\u0627\u0644\u0643\u0627\u0645\u0644 \u0639\u0644\u0649 Smart Contract \u2014 \u0643\u0644 \u0625\u064A\u062F\u0627\u0639\u060C \u0643\u0644 \u062D\u0633\u0627\u0628 \u0644\u0644\u0639\u0627\u0626\u062F \u0627\u0644\u064A\u0648\u0645\u064A\u060C \u0643\u0644 \u0633\u062D\u0628 \u064A\u062A\u0645 \u0645\u0639\u0627\u0644\u062C\u062A\u0647 \u0628\u0648\u0627\u0633\u0637\u0629 \u0627\u0644\u0643\u0648\u062F\u060C \u0648\u0644\u064A\u0633 \u0627\u0644\u0623\u0634\u062E\u0627\u0635. \u062A\u0645 \u0627\u0644\u062A\u0646\u0627\u0632\u0644 \u0639\u0646 \u0645\u0644\u0643\u064A\u0629 \u0627\u0644\u0639\u0642\u062F\u060C \u0645\u0645\u0627 \u064A\u0639\u0646\u064A \u0623\u0646 \u0645\u0641\u0627\u062A\u064A\u062D \u0627\u0644\u0625\u062F\u0627\u0631\u0629 \u062A\u0645 \u062D\u0631\u0642\u0647\u0627 \u0646\u0647\u0627\u0626\u064A\u064B\u0627. \u0644\u0627 \u0623\u062D\u062F \u064A\u0645\u0643\u0646\u0647 \u062A\u063A\u064A\u064A\u0631 \u0627\u0644\u0642\u0648\u0627\u0639\u062F. \u0644\u0627 \u0623\u062D\u062F \u064A\u0645\u0643\u0646\u0647 \u0627\u0644\u0648\u0635\u0648\u0644 \u0625\u0644\u0649 \u0623\u0645\u0648\u0627\u0644\u0643. \u0627\u0644\u0643\u0648\u062F \u0647\u0648 \u0627\u0644\u0642\u0627\u0646\u0648\u0646\u060C \u0648\u064A\u0646\u0641\u0630 \u0628\u062F\u0642\u0629 \u0631\u064A\u0627\u0636\u064A\u0629 \u0643\u0644 \u064A\u0648\u0645.\n\n\u2705 \u0627\u0644\u0646\u0642\u0627\u0637 \u0627\u0644\u0631\u0626\u064A\u0633\u064A\u0629:  \n\u2022 \u0643\u0648\u062F \u0630\u0627\u062A\u064A \u0627\u0644\u062A\u0646\u0641\u064A\u0630 \u0639\u0644\u0649 \u0627\u0644\u0628\u0644\u0648\u0643\u0634\u064A\u0646 \u2014 \u0644\u0627 \u062D\u0627\u062C\u0629 \u0644\u062A\u062F\u062E\u0644 \u0628\u0634\u0631\u064A  \n\u2022 \u063A\u064A\u0631 \u0642\u0627\u0628\u0644 \u0644\u0644\u062A\u063A\u064A\u064A\u0631 \u2014 \u0628\u0645\u062C\u0631\u062F \u0646\u0634\u0631\u0647\u060C \u0644\u0627 \u064A\u0645\u0643\u0646 \u0644\u0623\u062D\u062F \u062A\u063A\u064A\u064A\u0631\u0647 \u0623\u0648 \u0627\u0644\u062A\u0644\u0627\u0639\u0628 \u0628\u0647  \n\u2022 \u062A\u0645 \u0627\u0644\u062A\u0646\u0627\u0632\u0644 \u0639\u0646 \u0645\u0644\u0643\u064A\u0629 \u0639\u0642\u062F TurboLoop \u2014 \u0645\u0641\u0627\u062A\u064A\u062D \u0627\u0644\u0625\u062F\u0627\u0631\u0629 \u0645\u062D\u0631\u0648\u0642\u0629 \u0625\u0644\u0649 \u0627\u0644\u0623\u0628\u062F  \n\u2022 \u0643\u0644 \u0645\u0639\u0627\u0645\u0644\u0629 \u0634\u0641\u0627\u0641\u0629 \u0648\u0642\u0627\u0628\u0644\u0629 \u0644\u0644\u062A\u062D\u0642\u0642 \u0639\u0644\u0649 BscScan  \n\u2022 \u0627\u0644\u0643\u0648\u062F \u0647\u0648 \u0627\u0644\u0642\u0627\u0646\u0648\u0646 \u2014 \u064A\u0646\u0641\u0630 \u062A\u0644\u0642\u0627\u0626\u064A\u064B\u0627 \u0628\u062F\u0642\u0629 \u0631\u064A\u0627\u0636\u064A\u0629\n\n\u{1F48E} \u0644\u0627 \u062A\u062B\u0642 \u0628\u0627\u0644\u0646\u0627\u0633. \u062B\u0642 \u0628\u0627\u0644\u0643\u0648\u062F. \u062A\u062D\u0642\u0642 \u0645\u0646\u0647 \u0628\u0646\u0641\u0633\u0643.\n\n\u{1F310} turboloop.io",
