      original: "08_Alaman.png",
      headline: "\u{1F537} \u0645\u064A\u0632\u0627\u062A \u0627\u0644\u0623\u0645\u0627\u0646",
      caption: "\u{1F537} \u0645\u064A\u0632\u0627\u062A \u0627\u0644\u0623\u0645\u0627\u0646\n\u2726 \u0635\u064F\u0645\u0645 \u0645\u0646 \u0623\u062C\u0644 \u0627\u0644\u062B\u0642\u0629 \u2014 \u0633\u062A \u0637\u0628\u0642\u0627\u062A \u0645\u0646 \u0627\u0644\u0623\u0645\u0627\u0646 \u0627\u0644\u0642\u0627\u0628\u0644 \u0644\u0644\u062A\u062D\u0642\u0642\n\n\u0627\u0644\u0623\u0645\u0627\u0646 \u0644\u064A\u0633 \u0645\u062C\u0631\u062F \u0645\u064A\u0632\u0629 \u0641\u064A TurboLoop \u2014 \u0628\u0644 \u0647\u0648 \u0627\u0644\u0623\u0633\u0627\u0633. \u062A\u0645 \u062A\u062F\u0642\u064A\u0642 \u0627\u0644\u0640 Smart Contract \u0628\u0634\u0643\u0644 \u0645\u0633\u062A\u0642\u0644 \u0628\u062F\u0631\u062C\u0629 \u062B\u0642\u0629 99%\u060C \u0645\u0645\u0627 \u064A\u0624\u0643\u062F \u0639\u062F\u0645 \u0648\u062C\u0648\u062F \u0623\u064A \u062B\u063A\u0631\u0627\u062A \u0623\u0645\u0646\u064A\u0629 \u062D\u0631\u062C\u0629. \u062A\u0645 \u0627\u0644\u062A\u0646\u0627\u0632\u0644 \u0639\u0646 \u0645\u0644\u0643\u064A\u0629 \u0627\u0644\u0639\u0642\u062F \u0628\u0634\u0643\u0644 \u062F\u0627\u0626\u0645 \u2014 \u062A\u0645 \u062D\u0631\u0642 \u0645\u0641\u0627\u062A\u064A\u062D \u0627\u0644\u0645\u0633\u0624\u0648\u0644 \u0648\u0625\u0631\u0633\u0627\u0644\u0647\u0627 \u0625\u0644\u0649 \u0627\u0644\u0639\u0646\u0648\u0627\u0646 \u0627\u0644\u0645\u064A\u062A (0x000...dead)\u060C \u0645\u0645\u0627 \u064A\u0639\u0646\u064A \u0623\u0646\u0647 \u0644\u0627 \u064A\u0645\u0643\u0646 \u0644\u0623\u064A \u0625\u0646\u0633\u0627\u0646 \u062A\u0639\u062F\u064A\u0644 \u0627\u0644\u0628\u0631\u0648\u062A\u0648\u0643\u0648\u0644 \u0623\u0648 \u0625\u064A\u0642\u0627\u0641\u0647 \u0645\u0624\u0642\u062A\u0627\u064B \u0623\u0648 \u0627\u0644\u062A\u062F\u062E\u0644 \u0641\u064A\u0647. \u0645\u062C\u0645\u0639 \u0627\u0644\u0633\u064A\u0648\u0644\u0629 (LP) \u0645\u0642\u0641\u0644 \u0625\u0644\u0649 \u0627\u0644\u0623\u0628\u062F\u060C \u0645\u0645\u0627 \u064A\u062C\u0639\u0644 \u0639\u0645\u0644\u064A\u0627\u062A \u0627\u0644\u0627\u062D\u062A\u064A\u0627\u0644 (rug pulls) \u0645\u0633\u062A\u062D\u064A\u0644\u0629 \u0631\u064A\u0627\u0636\u064A\u0627\u064B. \u0627\u0644\u0643\u0648\u062F \u0627\u0644\u0645\u0635\u062F\u0631\u064A \u062A\u0645 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646\u0647 \u0628\u0627\u0644\u0643\u0627\u0645\u0644 \u0639\u0644\u0649 BscScan\u060C \u0645\u0645\u0627 \u064A\u0633\u0645\u062D \u0644\u0623\u064A \u0634\u062E\u0635 \u0628\u0642\u0631\u0627\u0621\u0629 \u0648\u062A\u062F\u0642\u064A\u0642 \u0643\u0644 \u0633\u0637\u0631. \u0627\u0644\u0628\u0631\u0648\u062A\u0648\u0643\u0648\u0644 \u063A\u064A\u0631 \u0627\u062D\u062A\u062C\u0627\u0632\u064A \u0628\u0646\u0633\u0628\u0629 100% \u2014 TurboLoop \u0644\u0627 \u064A\u062D\u062A\u0641\u0638 \u0628\u0623\u0645\u0648\u0627\u0644\u0643 \u0623\u0628\u062F\u0627\u064B. \u0648\u064A\u0642\u0641 \u062A\u062D\u062F\u064A \u0627\u0644\u0640 Smart Contract \u0628\u0642\u064A\u0645\u0629 $100,000 \u0643\u062F\u0644\u064A\u0644 \u0642\u0627\u0637\u0639: \u0627\u0628\u062D\u062B \u0639\u0646 \u0639\u064A\u0628\u060C \u0648\u0637\u0627\u0644\u0628 \u0628\u0627\u0644\u0645\u0643\u0627\u0641\u0623\u0629. \u0644\u0645 \u064A\u062C\u062F \u0623\u062D\u062F \u0623\u064A \u0639\u064A\u0628.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u062A\u062F\u0642\u064A\u0642 \u0645\u0633\u062A\u0642\u0644 \u2014 \u062F\u0631\u062C\u0629 \u062B\u0642\u0629 99%\u060C \u0635\u0641\u0631 \u062B\u063A\u0631\u0627\u062A \u0623\u0645\u0646\u064A\u0629 \u062D\u0631\u062C\u0629\n\u2022 \u0627\u0644\u062A\u0646\u0627\u0632\u0644 \u0639\u0646 \u0627\u0644\u0645\u0644\u0643\u064A\u0629 \u2014 \u062A\u0645 \u062D\u0631\u0642 \u0645\u0641\u0627\u062A\u064A\u062D \u0627\u0644\u0645\u0633\u0624\u0648\u0644 \u0628\u0634\u0643\u0644 \u062F\u0627\u0626\u0645\n\u2022 \u0627\u0644\u0640 LP \u0645\u0642\u0641\u0644 \u0625\u0644\u0649 \u0627\u0644\u0623\u0628\u062F \u2014 \u0627\u0644\u0627\u062D\u062A\u064A\u0627\u0644 \u0645\u0633\u062A\u062D\u064A\u0644 \u0631\u064A\u0627\u0636\u064A\u0627\u064B\n\u2022 \u0643\u0648\u062F \u062A\u0645 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646\u0647 \u0639\u0644\u0649 BscScan \u2014 \u0634\u0641\u0627\u0641 \u0628\u0627\u0644\u0643\u0627\u0645\u0644 \u0648\u0645\u0641\u062A\u0648\u062D \u0627\u0644\u0645\u0635\u062F\u0631\n\u2022 \u062A\u062D\u062F\u064A \u0627\u0644\u0640 Smart Contract \u0628\u0642\u064A\u0645\u0629 $100,000 \u2014 \u0644\u0645 \u064A\u062C\u062F \u0623\u062D\u062F \u0623\u064A \u0639\u064A\u0628\n\n\u{1F48E} \u0635\u064F\u0645\u0645 \u0645\u0646 \u0623\u062C\u0644 \u0627\u0644\u062B\u0642\u0629. \u062A\u0645 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646 \u0623\u0645\u0627\u0646\u0647. \u0645\u062B\u0628\u062A \u0628\u0627\u0644\u0643\u0648\u062F.\n\n\u{1F310} turboloop.io",
