      headline: "\u{1F537} \u062F\u0644\u064A\u0644 \u0627\u0644\u0628\u062F\u0621",
      caption: "\u{1F537} \u062F\u0644\u064A\u0644 \u0627\u0644\u0628\u062F\u0621\n\u2726 \u0645\u0646 \u0627\u0644\u0635\u0641\u0631 \u0625\u0644\u0649 \u0627\u0644\u0623\u0631\u0628\u0627\u062D \u0641\u064A 7 \u062E\u0637\u0648\u0627\u062A \u0628\u0633\u064A\u0637\u0629\n\n\u062A\u0645 \u062A\u0635\u0645\u064A\u0645 \u0627\u0644\u0627\u0646\u0637\u0644\u0627\u0642 \u0645\u0639 TurboLoop \u0644\u064A\u0643\u0648\u0646 \u0641\u064A \u063A\u0627\u064A\u0629 \u0627\u0644\u0633\u0647\u0648\u0644\u0629 \u2014 \u0644\u0627 \u064A\u062A\u0637\u0644\u0628 \u0623\u064A \u062E\u0628\u0631\u0629 \u062A\u0642\u0646\u064A\u0629. \u0627\u0644\u062E\u0637\u0648\u0629 1: \u0642\u0645 \u0628\u0625\u0639\u062F\u0627\u062F \u0645\u062D\u0641\u0638\u0629 \u0639\u0645\u0644\u0627\u062A \u0631\u0642\u0645\u064A\u0629 (MetaMask \u0623\u0648 Trust Wallet). \u0627\u0644\u062E\u0637\u0648\u0629 2: \u0627\u0634\u062A\u0631\u0650 USDT \u0639\u0644\u0649 \u0634\u0628\u0643\u0629 BSC \u0639\u0628\u0631 \u0645\u0646\u0635\u0629 \u062A\u062F\u0627\u0648\u0644 \u0623\u0648 Turbo Buy. \u0627\u0644\u062E\u0637\u0648\u0629 3: \u062A\u0641\u0636\u0644 \u0628\u0632\u064A\u0627\u0631\u0629 turboloop.io. \u0627\u0644\u062E\u0637\u0648\u0629 4: \u0627\u0631\u0628\u0637 \u0645\u062D\u0641\u0638\u062A\u0643 \u0628\u0646\u0642\u0631\u0629 \u0648\u0627\u062D\u062F\u0629. \u0627\u0644\u062E\u0637\u0648\u0629 5: \u0627\u062E\u062A\u0631 \u062E\u0637\u062A\u0643 \u0627\u0644\u0627\u0633\u062A\u062B\u0645\u0627\u0631\u064A\u0629 \u2014 Sprint (3%/7d)\u060C \u0623\u0648 Boost (10%/14d)\u060C \u0623\u0648 Power (24%/30d)\u060C \u0623\u0648 Ultimate (54%/60d). \u0627\u0644\u062E\u0637\u0648\u0629 6: \u0623\u0648\u062F\u0639 \u0627\u0644\u0640 USDT \u0627\u0644\u062E\u0627\u0635 \u0628\u0643 (\u0627\u0644\u062D\u062F \u0627\u0644\u0623\u062F\u0646\u0649 $1\u060C \u0648\u0628\u062F\u0648\u0646 \u062D\u062F \u0623\u0642\u0635\u0649). \u0627\u0644\u062E\u0637\u0648\u0629 7: \u0631\u0627\u0642\u0628 \u0623\u0631\u0628\u0627\u062D\u0643 \u062A\u062A\u0631\u0627\u0643\u0645 \u064A\u0648\u0645\u064A\u0627\u064B. \u062A\u0633\u062A\u063A\u0631\u0642 \u0627\u0644\u0639\u0645\u0644\u064A\u0629 \u0628\u0623\u0643\u0645\u0644\u0647\u0627 \u0623\u0642\u0644 \u0645\u0646 10 \u062F\u0642\u0627\u0626\u0642\u060C \u0648\u0628\u0645\u062C\u0631\u062F \u062A\u0641\u0639\u064A\u0644 \u0625\u064A\u062F\u0627\u0639\u0643\u060C \u064A\u062A\u0648\u0644\u0649 \u0627\u0644\u0640 Smart Contract \u0625\u062F\u0627\u0631\u0629 \u0643\u0644 \u0634\u064A\u0621 \u062A\u0644\u0642\u0627\u0626\u064A\u0627\u064B. \u0644\u0627 \u062D\u0627\u062C\u0629 \u0644\u062A\u0633\u062C\u064A\u0644 \u0627\u0644\u062F\u062E\u0648\u0644 \u0627\u0644\u064A\u0648\u0645\u064A. \u0644\u0627 \u062D\u0627\u062C\u0629 \u0644\u0644\u0645\u0637\u0627\u0644\u0628\u0629 \u0627\u0644\u064A\u062F\u0648\u064A\u0629 \u0628\u0627\u0644\u0623\u0631\u0628\u0627\u062D. \u0641\u0642\u0637 \u0639\u0648\u0627\u0626\u062F \u064A\u0648\u0645\u064A\u0629 \u0645\u0624\u062A\u0645\u062A\u0629\u060C \u062A\u064F\u062D\u0633\u0628 \u0648\u062A\u064F\u0636\u0627\u0641 \u0625\u0644\u0649 \u0631\u0635\u064A\u062F\u0643 \u0643\u0644 24 \u0633\u0627\u0639\u0629.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0645\u0632\u0627\u064A\u0627:\n\u2022 7 \u062E\u0637\u0648\u0627\u062A \u0628\u0633\u064A\u0637\u0629 \u0645\u0646 \u0627\u0644\u0635\u0641\u0631 \u0625\u0644\u0649 \u0627\u0644\u0623\u0631\u0628\u0627\u062D \u2014 \u0644\u0627 \u062D\u0627\u062C\u0629 \u0644\u0623\u064A \u062E\u0628\u0631\u0629 \u062A\u0642\u0646\u064A\u0629\n\u2022 \u0627\u0644\u062D\u062F \u0627\u0644\u0623\u062F\u0646\u0649 \u0644\u0644\u0625\u064A\u062F\u0627\u0639: $1 \u0641\u0642\u0637 \u2014 \u0641\u064A \u0645\u062A\u0646\u0627\u0648\u0644 \u0627\u0644\u062C\u0645\u064A\u0639\n\u2022 \u0627\u062E\u062A\u0631 \u0645\u0646 \u0628\u064A\u0646 4 \u062E\u0637\u0637: Sprint\u060C \u0623\u0648 Boost\u060C \u0623\u0648 Power\u060C \u0623\u0648 Ultimate\n\u2022 \u064A\u062A\u0648\u0644\u0649 \u0627\u0644\u0640 Smart Contract \u0625\u062F\u0627\u0631\u0629 \u0643\u0644 \u0634\u064A\u0621 \u062A\u0644\u0642\u0627\u0626\u064A\u0627\u064B \u0628\u0639\u062F \u0627\u0644\u0625\u064A\u062F\u0627\u0639\n\u2022 \u064A\u0633\u062A\u063A\u0631\u0642 \u0627\u0644\u0625\u0639\u062F\u0627\u062F \u0628\u0627\u0644\u0643\u0627\u0645\u0644 \u0623\u0642\u0644 \u0645\u0646 10 \u062F\u0642\u0627\u0626\u0642\n\n\u{1F48E} \u0627\u0628\u062F\u0623 \u0628\u062C\u0646\u064A \u0627\u0644\u0623\u0631\u0628\u0627\u062D \u0641\u064A \u062F\u0642\u0627\u0626\u0642. \u0627\u0644\u062D\u0644\u0642\u0629 \u0628\u0627\u0646\u062A\u0638\u0627\u0631\u0643.\n\n\u{1F310} turboloop.io",
