      original: "12_Arbaa_Khitat.png",
      headline: "\u{1F537} \u0623\u0631\u0628\u0639 \u062E\u0637\u0637 \u0627\u0633\u062A\u062B\u0645\u0627\u0631\u064A\u0629",
      caption: "\u{1F537} \u0623\u0631\u0628\u0639 \u062E\u0637\u0637 \u0627\u0633\u062A\u062B\u0645\u0627\u0631\u064A\u0629\n\u2726 \u0645\u0646 \u0627\u0644\u0627\u0646\u0637\u0644\u0627\u0642\u0627\u062A \u0627\u0644\u0633\u0631\u064A\u0639\u0629 \u0625\u0644\u0649 \u0627\u0644\u0639\u0648\u0627\u0626\u062F \u0627\u0644\u0642\u0635\u0648\u0649 \u2014 \u0627\u062E\u062A\u0631 \u0645\u0633\u0627\u0631\u0643\n\n\u062A\u0642\u062F\u0645 TurboLoop \u0623\u0631\u0628\u0639 \u062E\u0637\u0637 \u0627\u0633\u062A\u062B\u0645\u0627\u0631\u064A\u0629 \u0645\u0635\u0645\u0645\u0629 \u0628\u062F\u0642\u0629\u060C \u0643\u0644 \u0645\u0646\u0647\u0627 \u062A\u0645\u062A \u0645\u0639\u0627\u064A\u0631\u062A\u0647\u0627 \u0644\u062A\u0646\u0627\u0633\u0628 \u0627\u0633\u062A\u0631\u0627\u062A\u064A\u062C\u064A\u0627\u062A \u0648\u0623\u0637\u0631 \u0632\u0645\u0646\u064A\u0629 \u0645\u062E\u062A\u0644\u0641\u0629. \u062A\u0642\u062F\u0645 Sprint Loop \u0639\u0627\u0626\u062F\u064B\u0627 \u0628\u0646\u0633\u0628\u0629 3% \u0641\u064A 7 \u0623\u064A\u0627\u0645 \u0641\u0642\u0637 \u2014 \u0645\u062B\u0627\u0644\u064A\u0629 \u0644\u0627\u062E\u062A\u0628\u0627\u0631 \u0627\u0644\u0623\u062C\u0648\u0627\u0621. \u062A\u062A\u0633\u0627\u0631\u0639 Boost Loop \u0625\u0644\u0649 10% \u0639\u0644\u0649 \u0645\u062F\u0627\u0631 14 \u064A\u0648\u0645\u064B\u0627 \u0644\u0623\u0648\u0644\u0626\u0643 \u0627\u0644\u0645\u0633\u062A\u0639\u062F\u064A\u0646 \u0644\u0644\u0627\u0644\u062A\u0632\u0627\u0645. \u062A\u0637\u0644\u0642 Power Loop \u0627\u0644\u0639\u0646\u0627\u0646 \u0644\u0639\u0627\u0626\u062F \u0628\u0646\u0633\u0628\u0629 24% \u0641\u064A 30 \u064A\u0648\u0645\u064B\u0627 \u2014 \u0627\u0644\u0646\u0642\u0637\u0629 \u0627\u0644\u0645\u062B\u0627\u0644\u064A\u0629 \u0644\u0644\u0645\u0633\u062A\u062B\u0645\u0631\u064A\u0646 \u0627\u0644\u062C\u0627\u062F\u064A\u0646. \u0648 Ultimate Loop\u060C \u062F\u0631\u0629 \u0627\u0644\u062A\u0627\u062C\u060C \u062A\u0642\u062F\u0645 \u0639\u0627\u0626\u062F\u064B\u0627 \u0647\u0627\u0626\u0644\u0627\u064B \u0628\u0646\u0633\u0628\u0629 54% \u0639\u0644\u0649 \u0645\u062F\u0627\u0631 60 \u064A\u0648\u0645\u064B\u0627. \u062A\u0628\u062F\u0623 \u0643\u0644 \u062E\u0637\u0629 \u0645\u0646 $1 \u0641\u0642\u0637 \u0628\u062F\u0648\u0646 \u062D\u062F \u0623\u0642\u0635\u0649. \u064A\u062A\u0645 \u062D\u0633\u0627\u0628 \u0627\u0644\u0639\u0648\u0627\u0626\u062F \u0648\u062A\u0648\u0632\u064A\u0639\u0647\u0627 \u064A\u0648\u0645\u064A\u064B\u0627 \u0628\u0648\u0627\u0633\u0637\u0629 Smart Contract. \u0641\u064A \u0646\u0647\u0627\u064A\u0629 \u0643\u0644 \u062F\u0648\u0631\u0629\u060C \u064A\u062A\u0645 \u0625\u0631\u062C\u0627\u0639 \u0631\u0623\u0633 \u0645\u0627\u0644\u0643 \u0628\u0627\u0644\u0643\u0627\u0645\u0644 \u0645\u0639 \u0627\u0644\u0639\u0627\u0626\u062F \u0627\u0644\u0645\u062A\u0631\u0627\u0643\u0645. \u0633\u0648\u0627\u0621 \u0643\u0646\u062A \u0645\u0628\u062A\u062F\u0626\u064B\u0627 \u062D\u0630\u0631\u064B\u0627 \u0623\u0648 \u0628\u0627\u062D\u062B\u064B\u0627 \u062C\u0631\u064A\u0626\u064B\u0627 \u0639\u0646 \u0627\u0644\u0639\u0648\u0627\u0626\u062F\u060C \u0641\u0647\u0646\u0627\u0643 \u062D\u0644\u0642\u0629 \u0645\u0635\u0645\u0645\u0629 \u062E\u0635\u064A\u0635\u064B\u0627 \u0644\u0643.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 Sprint Loop: \u0639\u0627\u0626\u062F 3% \u0641\u064A 7 \u0623\u064A\u0627\u0645 (~0.43% \u064A\u0648\u0645\u064A\u064B\u0627)\n\u2022 Boost Loop: \u0639\u0627\u0626\u062F 10% \u0641\u064A 14 \u064A\u0648\u0645\u064B\u0627 (~0.71% \u064A\u0648\u0645\u064A\u064B\u0627)\n\u2022 Power Loop: \u0639\u0627\u0626\u062F 24% \u0641\u064A 30 \u064A\u0648\u0645\u064B\u0627 (~0.8% \u064A\u0648\u0645\u064A\u064B\u0627)\n\u2022 Ultimate Loop: \u0639\u0627\u0626\u062F 54% \u0641\u064A 60 \u064A\u0648\u0645\u064B\u0627 (~0.9% \u064A\u0648\u0645\u064A\u064B\u0627)\n\u2022 \u062C\u0645\u064A\u0639 \u0627\u0644\u062E\u0637\u0637: \u062D\u062F \u0623\u062F\u0646\u0649 $1\u060C \u0628\u062F\u0648\u0646 \u062D\u062F \u0623\u0642\u0635\u0649\u060C \u0639\u0648\u0627\u0626\u062F \u064A\u0648\u0645\u064A\u0629 \u062A\u0644\u0642\u0627\u0626\u064A\u0629\n\n\u{1F48E} \u0623\u0631\u0628\u0639 \u062E\u0637\u0637. \u0647\u062F\u0641 \u0648\u0627\u062D\u062F: \u0646\u0645\u0648\u0643 \u0627\u0644\u0645\u0627\u0644\u064A. \u0627\u062E\u062A\u0631 \u062D\u0644\u0642\u062A\u0643.\n\n\u{1F310} turboloop.io",
