      headline: "\u{1F537} \u062F\u0631\u0627\u0633\u0629 \u062D\u0627\u0644\u0629 100$",
      caption: "\u{1F537} \u062F\u0631\u0627\u0633\u0629 \u062D\u0627\u0644\u0629 100$\n\u2726 \u0645\u0627\u0630\u0627 \u064A\u062D\u062F\u062B \u0639\u0646\u062F\u0645\u0627 \u062A\u0648\u062F\u0639 100$ \u0641\u064A \u0643\u0644 \u062E\u0637\u0629\u061F\n\n\u062F\u0639\u0648\u0646\u0627 \u0646\u0641\u0635\u0644 \u0628\u0627\u0644\u0636\u0628\u0637 \u0645\u0627 \u062A\u0643\u0633\u0628\u0647 100$ \u0639\u0628\u0631 \u062E\u0637\u0637 TurboLoop \u0627\u0644\u0623\u0631\u0628\u0639. \u0641\u064A Sprint Loop\u060C \u062A\u0635\u0628\u062D \u0627\u0644\u0640 100$ \u0627\u0644\u062E\u0627\u0635\u0629 \u0628\u0643 103$ \u0641\u064A 7 \u0623\u064A\u0627\u0645 \u0641\u0642\u0637 \u2014 \u0627\u062E\u062A\u0628\u0627\u0631 \u0633\u0631\u064A\u0639 \u0648\u0645\u0646\u062E\u0641\u0636 \u0627\u0644\u0645\u062E\u0627\u0637\u0631. \u0641\u064A Boost Loop\u060C \u062A\u0646\u0645\u0648 \u0646\u0641\u0633 \u0627\u0644\u0640 100$ \u0625\u0644\u0649 110$ \u0639\u0644\u0649 \u0645\u062F\u0627\u0631 14 \u064A\u0648\u0645\u064B\u0627 \u2014 \u0623\u0643\u062B\u0631 \u0645\u0646 \u062B\u0644\u0627\u062B\u0629 \u0623\u0636\u0639\u0627\u0641 \u0627\u0644\u0639\u0627\u0626\u062F \u0641\u064A \u0636\u0639\u0641 \u0627\u0644\u0648\u0642\u062A. \u064A\u062D\u0648\u0644 Power Loop \u0627\u0644\u0640 100$ \u0625\u0644\u0649 124$ \u0641\u064A 30 \u064A\u0648\u0645\u064B\u0627 \u2014 \u0645\u0643\u0633\u0628 \u0628\u0646\u0633\u0628\u0629 24% \u064A\u062A\u0641\u0648\u0642 \u0639\u0644\u0649 \u0645\u0639\u0638\u0645 \u0645\u0639\u062F\u0644\u0627\u062A \u0627\u0644\u062A\u0648\u0641\u064A\u0631 \u0627\u0644\u0645\u0635\u0631\u0641\u064A\u0629 \u0627\u0644\u0633\u0646\u0648\u064A\u0629 \u0641\u064A \u0634\u0647\u0631 \u0648\u0627\u062D\u062F. \u0648\u0645\u0627\u0630\u0627 \u0639\u0646 Ultimate Loop\u061F \u062A\u0635\u0628\u062D \u0627\u0644\u0640 100$ \u0627\u0644\u062E\u0627\u0635\u0629 \u0628\u0643 154$ \u0641\u064A 60 \u064A\u0648\u0645\u064B\u0627 \u2014 \u062A\u0645\u062A \u0625\u0636\u0627\u0641\u0629 \u0623\u0643\u062B\u0631 \u0645\u0646 \u0646\u0635\u0641 \u0625\u064A\u062F\u0627\u0639\u0643 \u0643\u0639\u0627\u0626\u062F \u0635\u0627\u0641\u064D. \u0647\u0630\u0647 \u0644\u064A\u0633\u062A \u062A\u0648\u0642\u0639\u0627\u062A \u0623\u0648 \u062A\u0642\u062F\u064A\u0631\u0627\u062A. \u0647\u0630\u0647 \u0647\u064A \u0627\u0644\u0639\u0648\u0627\u0626\u062F \u0627\u0644\u062F\u0642\u064A\u0642\u0629 \u0627\u0644\u0645\u0628\u0631\u0645\u062C\u0629 \u0641\u064A Smart Contract\u060C \u0648\u0627\u0644\u062A\u064A \u064A\u062A\u0645 \u062D\u0633\u0627\u0628\u0647\u0627 \u064A\u0648\u0645\u064A\u064B\u0627 \u0648\u062A\u0648\u0632\u064A\u0639\u0647\u0627 \u062A\u0644\u0642\u0627\u0626\u064A\u064B\u0627. 100$ \u0647\u064A \u0643\u0644 \u0645\u0627 \u064A\u062A\u0637\u0644\u0628\u0647 \u0627\u0644\u0623\u0645\u0631 \u0644\u062A\u062C\u0631\u0628\u0629 \u0642\u0648\u0629 TurboLoop \u0628\u0634\u0643\u0644 \u0645\u0628\u0627\u0634\u0631.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 Sprint Loop: 100$ \u2192 103$ \u0641\u064A 7 \u0623\u064A\u0627\u0645 (\u0639\u0627\u0626\u062F 3%)\n\u2022 Boost Loop: 100$ \u2192 110$ \u0641\u064A 14 \u064A\u0648\u0645\u064B\u0627 (\u0639\u0627\u0626\u062F 10%)\n\u2022 Power Loop: 100$ \u2192 124$ \u0641\u064A 30 \u064A\u0648\u0645\u064B\u0627 (\u0639\u0627\u0626\u062F 24%)\n\u2022 Ultimate Loop: 100$ \u2192 154$ \u0641\u064A 60 \u064A\u0648\u0645\u064B\u0627 (\u0639\u0627\u0626\u062F 54%)\n\u2022 \u062C\u0645\u064A\u0639 \u0627\u0644\u0639\u0648\u0627\u0626\u062F \u062F\u0642\u064A\u0642\u0629\u060C \u0648\u0645\u0628\u0631\u0645\u062C\u0629 \u0641\u064A Smart Contract\n\n\u{1F48E} 100$ \u0627\u0644\u064A\u0648\u0645. \u0643\u0645 \u063A\u062F\u064B\u0627\u061F \u0627\u0644\u0631\u064A\u0627\u0636\u064A\u0627\u062A \u062A\u062A\u062D\u062F\u062B \u0639\u0646 \u0646\u0641\u0633\u0647\u0627.\n\n\u{1F310} turboloop.io",
