      original: "20_Thalath_Masadir.png",
      headline: "\u{1F537} \u062B\u0644\u0627\u062B\u0629 \u0645\u0635\u0627\u062F\u0631 \u0644\u0644\u062F\u062E\u0644",
      caption: "\u{1F537} \u062B\u0644\u0627\u062B\u0629 \u0645\u0635\u0627\u062F\u0631 \u0644\u0644\u062F\u062E\u0644\n\u2726 \u0639\u0627\u0626\u062F \u0627\u0644\u062E\u0637\u0629 + \u0634\u0628\u0643\u0629 \u0627\u0644\u0625\u062D\u0627\u0644\u0629 + \u0645\u0643\u0627\u0641\u0623\u0629 \u0627\u0644\u0642\u064A\u0627\u062F\u0629 = \u0623\u0642\u0635\u0649 \u0627\u0644\u0623\u0631\u0628\u0627\u062D\n\n\u0644\u0627 \u064A\u0642\u064A\u062F\u0643 TurboLoop \u0628\u0645\u0635\u062F\u0631 \u062F\u062E\u0644 \u0648\u0627\u062D\u062F \u2014 \u0628\u0644 \u064A\u0645\u0646\u062D\u0643 \u062B\u0644\u0627\u062B\u0629 \u0645\u062D\u0631\u0643\u0627\u062A \u0642\u0648\u064A\u0629 \u062A\u0639\u0645\u0644 \u0641\u064A \u0648\u0642\u062A \u0648\u0627\u062D\u062F. \u0627\u0644\u0645\u062D\u0631\u0643 \u0627\u0644\u0623\u0648\u0644: \u064A\u0642\u062F\u0645 \u0639\u0627\u0626\u062F \u0627\u0644\u062E\u0637\u0629 \u0639\u0648\u0627\u0626\u062F \u062A\u062A\u0631\u0627\u0648\u062D \u0645\u0646 3% \u0625\u0644\u0649 54% \u0628\u0646\u0627\u0621\u064B \u0639\u0644\u0649 \u062E\u0637\u062A\u0643 \u0627\u0644\u0645\u062E\u062A\u0627\u0631\u0629\u060C \u0648\u064A\u062A\u0645 \u062D\u0633\u0627\u0628\u0647\u0627 \u0648\u062A\u0648\u0632\u064A\u0639\u0647\u0627 \u064A\u0648\u0645\u064A\u0627\u064B \u0628\u0648\u0627\u0633\u0637\u0629 \u0627\u0644\u0640 Smart Contract. \u0627\u0644\u0645\u062D\u0631\u0643 \u0627\u0644\u062B\u0627\u0646\u064A: \u062A\u0648\u0632\u0639 \u0634\u0628\u0643\u0629 \u0627\u0644\u0625\u062D\u0627\u0644\u0629 \u0627\u0644\u0645\u0643\u0648\u0646\u0629 \u0645\u0646 20 \u0645\u0633\u062A\u0648\u0649 51% \u0645\u0646 \u0625\u064A\u062F\u0627\u0639\u0627\u062A \u0627\u0644\u0645\u062D\u0627\u0644\u064A\u0646 \u0639\u0628\u0631 \u0634\u0628\u0643\u062A\u0643 \u0628\u0627\u0644\u0643\u0627\u0645\u0644 \u2014 \u0634\u0627\u0631\u0643 \u0631\u0627\u0628\u0637\u0643 \u0648\u0627\u0631\u0628\u062D \u0645\u0646 \u0643\u0644 \u0639\u0636\u0648 \u064A\u0646\u0636\u0645 \u0645\u0646 \u062E\u0644\u0627\u0644 \u0634\u0628\u0643\u062A\u0643\u060C \u062D\u062A\u0649 \u0639\u0645\u0642 20 \u0645\u0633\u062A\u0648\u0649. \u0627\u0644\u0645\u062D\u0631\u0643 \u0627\u0644\u062B\u0627\u0644\u062B: \u062A\u0643\u0627\u0641\u0626 \u0645\u0643\u0627\u0641\u0622\u062A \u0627\u0644\u0642\u064A\u0627\u062F\u0629 \u0628\u0646\u0627\u0629 \u0627\u0644\u0645\u062C\u062A\u0645\u0639 \u0628\u0646\u0633\u0628\u0629 \u0625\u0636\u0627\u0641\u064A\u0629 \u062A\u062A\u0631\u0627\u0648\u062D \u0645\u0646 1% \u0625\u0644\u0649 10% \u0628\u0646\u0627\u0621\u064B \u0639\u0644\u0649 \u0631\u062A\u0628\u062A\u0643 \u2014 \u0645\u0646 \u0634\u0631\u064A\u0643 \u0625\u0644\u0649 \u0645\u0633\u062A\u0648\u0649 TURBO LEGEND \u0627\u0644\u0623\u0633\u0637\u0648\u0631\u064A. \u064A\u0639\u0645\u0644 \u0643\u0644 \u0645\u062D\u0631\u0643 \u0628\u0634\u0643\u0644 \u0645\u0633\u062A\u0642\u0644\u060C \u0645\u0645\u0627 \u064A\u0639\u0646\u064A \u0623\u0646 \u0625\u062C\u0645\u0627\u0644\u064A \u0623\u0631\u0628\u0627\u062D\u0643 \u0647\u0648 \u0645\u062C\u0645\u0648\u0639 \u0627\u0644\u062B\u0644\u0627\u062B\u0629. \u0642\u0645 \u0628\u0628\u0646\u0627\u0621 \u0627\u0644\u062B\u0644\u0627\u062B\u0629\u060C \u0648\u0633\u062A\u0641\u062A\u062D \u0625\u0645\u0643\u0627\u0646\u0627\u062A \u0627\u0644\u0643\u0633\u0628 \u0627\u0644\u0643\u0627\u0645\u0644\u0629 \u0644\u0640 TurboLoop.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u0627\u0644\u0645\u062D\u0631\u0643 \u0627\u0644\u0623\u0648\u0644: \u0639\u0627\u0626\u062F \u0627\u0644\u062E\u0637\u0629 \u2014 \u0645\u0646 3% \u0625\u0644\u0649 54% \u062D\u0633\u0628 \u0627\u0644\u062E\u0637\u0629\u060C \u062A\u0644\u0642\u0627\u0626\u064A \u064A\u0648\u0645\u064A\u0627\u064B\n\u2022 \u0627\u0644\u0645\u062D\u0631\u0643 \u0627\u0644\u062B\u0627\u0646\u064A: \u0634\u0628\u0643\u0629 \u0627\u0644\u0625\u062D\u0627\u0644\u0629 \u2014 \u0628\u0639\u0645\u0642 20 \u0645\u0633\u062A\u0648\u0649\u060C \u0625\u062C\u0645\u0627\u0644\u064A \u0627\u0644\u062A\u0648\u0632\u064A\u0639 51%\n\u2022 \u0627\u0644\u0645\u062D\u0631\u0643 \u0627\u0644\u062B\u0627\u0644\u062B: \u0645\u0643\u0627\u0641\u0623\u0629 \u0627\u0644\u0642\u064A\u0627\u062F\u0629 \u2014 7 \u0631\u062A\u0628\u060C \u0623\u0631\u0628\u0627\u062D \u0625\u0636\u0627\u0641\u064A\u0629 \u0645\u0646 1% \u0625\u0644\u0649 10%\n\u2022 \u062A\u0639\u0645\u0644 \u0627\u0644\u0645\u062D\u0631\u0643\u0627\u062A \u0627\u0644\u062B\u0644\u0627\u062B\u0629 \u0641\u064A \u0648\u0642\u062A \u0648\u0627\u062D\u062F \u0648\u0628\u0634\u0643\u0644 \u0645\u0633\u062A\u0642\u0644\n\u2022 \u0625\u062C\u0645\u0627\u0644\u064A \u0627\u0644\u0623\u0631\u0628\u0627\u062D = \u0639\u0627\u0626\u062F \u0627\u0644\u062E\u0637\u0629 + \u0639\u0645\u0648\u0644\u0627\u062A \u0627\u0644\u0625\u062D\u0627\u0644\u0629 + \u0645\u0643\u0627\u0641\u0623\u0629 \u0627\u0644\u0642\u064A\u0627\u062F\u0629\n\n\u{1F48E} \u062B\u0644\u0627\u062B\u0629 \u0645\u062D\u0631\u0643\u0627\u062A. \u0647\u062F\u0641 \u0648\u0627\u062D\u062F: \u062B\u0631\u0648\u062A\u0643. \u0642\u0645 \u0628\u062A\u0641\u0639\u064A\u0644 \u0627\u0644\u062B\u0644\u0627\u062B\u0629.\n\n\u{1F310} turboloop.io",
