      headline: "\u{1F537} \u0628\u0631\u0646\u0627\u0645\u062C \u0645\u0643\u0627\u0641\u0622\u062A \u0627\u0644\u0627\u0646\u0636\u0645\u0627\u0645",
      caption: "\u{1F537} \u0628\u0631\u0646\u0627\u0645\u062C \u0645\u0643\u0627\u0641\u0622\u062A \u0627\u0644\u0627\u0646\u0636\u0645\u0627\u0645\n\u2726 \u0645\u0643\u0627\u0641\u0622\u062A \u062A\u0635\u0644 \u0625\u0644\u0649 $10,000 \u2014 \u0644\u0645\u0646 \u064A\u0628\u0646\u064A \u0628\u0633\u0631\u0639\u0629\n\n\u0645\u0643\u0627\u0641\u0623\u0629 \u0627\u0644\u0627\u0646\u0636\u0645\u0627\u0645 \u0645\u0646 TurboLoop \u0647\u064A \u0628\u0631\u0646\u0627\u0645\u062C \u062A\u0633\u0631\u064A\u0639 \u0645\u062D\u062F\u0648\u062F \u0627\u0644\u0648\u0642\u062A \u064A\u0643\u0627\u0641\u0626 \u0628\u0646\u0627\u0629 \u0627\u0644\u0645\u062C\u062A\u0645\u0639 \u0627\u0644\u0633\u0631\u064A\u0639\u064A\u0646 \u0628\u0645\u0643\u0627\u0641\u0622\u062A \u0646\u0642\u062F\u064A\u0629 \u0636\u062E\u0645\u0629. \u062E\u0644\u0627\u0644 \u0646\u0627\u0641\u0630\u0629 \u0645\u062F\u062A\u0647\u0627 60 \u064A\u0648\u0645\u0627\u064B\u060C \u062D\u0642\u0642 \u0625\u0646\u062C\u0627\u0632\u0627\u062A \u0645\u062D\u062F\u062F\u0629 \u0648\u0627\u0641\u062A\u062D \u0645\u0643\u0627\u0641\u0622\u062A \u0645\u062A\u0635\u0627\u0639\u062F\u0629: \u0627\u062C\u0644\u0628 50 \u0639\u0636\u0648\u0627\u064B \u062C\u062F\u064A\u062F\u0627\u064B \u0648\u0627\u0643\u0633\u0628 $50. \u0635\u0644 \u0625\u0644\u0649 100 \u0639\u0636\u0648 \u0645\u0642\u0627\u0628\u0644 $200. \u062D\u0642\u0642 250 \u0645\u0642\u0627\u0628\u0644 $750. \u062A\u062C\u0627\u0648\u0632 500 \u0645\u0642\u0627\u0628\u0644 $2,000. \u062D\u0642\u0642 750 \u0645\u0642\u0627\u0628\u0644 $4,000. \u0648\u0627\u0644\u0625\u0646\u062C\u0627\u0632 \u0627\u0644\u0646\u0647\u0627\u0626\u064A \u2014 1,000 \u0639\u0636\u0648 \u062C\u062F\u064A\u062F \u062E\u0644\u0627\u0644 60 \u064A\u0648\u0645\u0627\u064B \u2014 \u064A\u0641\u062A\u062D \u0645\u0643\u0627\u0641\u0623\u0629 \u0647\u0627\u0626\u0644\u0629 \u0628\u0642\u064A\u0645\u0629 $10,000. \u062A\u064F\u062F\u0641\u0639 \u0647\u0630\u0647 \u0627\u0644\u0645\u0643\u0627\u0641\u0622\u062A \u0639\u0644\u0627\u0648\u0629 \u0639\u0644\u0649 \u0639\u0645\u0648\u0644\u0627\u062A \u0627\u0644\u0625\u062D\u0627\u0644\u0629 \u0627\u0644\u0639\u0627\u062F\u064A\u0629 \u0648\u0645\u0643\u0627\u0641\u0622\u062A \u0627\u0644\u0642\u064A\u0627\u062F\u0629 \u0627\u0644\u062E\u0627\u0635\u0629 \u0628\u0643\u060C \u0645\u0645\u0627 \u064A\u062C\u0639\u0644 \u0623\u0648\u0644 60 \u064A\u0648\u0645\u0627\u064B \u0627\u0644\u0641\u062A\u0631\u0629 \u0627\u0644\u0623\u0643\u062B\u0631 \u0631\u0628\u062D\u064A\u0629 \u0644\u0628\u0646\u0627\u0629 \u0627\u0644\u0634\u0628\u0643\u0627\u062A. \u064A\u0628\u062F\u0623 \u0627\u0644\u0639\u062F \u0627\u0644\u062A\u0646\u0627\u0632\u0644\u064A \u0628\u0645\u062C\u0631\u062F \u0625\u062C\u0631\u0627\u0621 \u0623\u0648\u0644 \u0625\u062D\u0627\u0644\u0629 \u0644\u0643.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 50 \u0639\u0636\u0648\u0627\u064B \u0641\u064A 60 \u064A\u0648\u0645\u0627\u064B \u2192 \u0645\u0643\u0627\u0641\u0623\u0629 $50\n\u2022 100 \u0639\u0636\u0648 \u2192 $200 | 250 \u0639\u0636\u0648\u0627\u064B \u2192 $750\n\u2022 500 \u0639\u0636\u0648 \u2192 $2,000 | 750 \u0639\u0636\u0648\u0627\u064B \u2192 $4,000\n\u2022 1,000 \u0639\u0636\u0648 \u2192 $10,000 \u2014 \u0627\u0644\u0625\u0646\u062C\u0627\u0632 \u0627\u0644\u0646\u0647\u0627\u0626\u064A\n\u2022 \u0627\u0644\u0645\u0643\u0627\u0641\u0622\u062A \u0625\u0636\u0627\u0641\u064A\u0629 \u0644\u0639\u0645\u0648\u0644\u0627\u062A \u0627\u0644\u0625\u062D\u0627\u0644\u0629 \u0648\u0645\u0643\u0627\u0641\u0622\u062A \u0627\u0644\u0642\u064A\u0627\u062F\u0629\n\n\u{1F48E} \u0627\u062F\u0639\u064F. \u0627\u0643\u0633\u0628. \u0643\u0631\u0631. \u0623\u0648\u0644 60 \u064A\u0648\u0645\u0627\u064B \u0647\u064A \u0627\u0644\u0623\u0647\u0645.\n\n\u{1F310} turboloop.io",
