      original: "24_Sania_Muhtawa.png",
      headline: "\u{1F537} \u0628\u0631\u0646\u0627\u0645\u062C \u0646\u062C\u0648\u0645 \u0635\u0646\u0627\u0639 \u0627\u0644\u0645\u062D\u062A\u0648\u0649",
      caption: "\u{1F537} \u0628\u0631\u0646\u0627\u0645\u062C \u0646\u062C\u0648\u0645 \u0635\u0646\u0627\u0639 \u0627\u0644\u0645\u062D\u062A\u0648\u0649\n\u2726 \u0627\u0635\u0646\u0639 \u0645\u062D\u062A\u0648\u0649\u060C \u0648\u0627\u0631\u0628\u062D \u0645\u0627 \u064A\u0635\u0644 \u0625\u0644\u0649 $1,000 \u0644\u0643\u0644 \u0641\u064A\u062F\u064A\u0648\n\n\u0625\u0630\u0627 \u0643\u0627\u0646 \u0644\u062F\u064A\u0643 \u0643\u0627\u0645\u064A\u0631\u0627 \u0648\u062C\u0645\u0647\u0648\u0631\u060C \u0641\u0625\u0646 \u0628\u0631\u0646\u0627\u0645\u062C \u0646\u062C\u0648\u0645 \u0635\u0646\u0627\u0639 \u0627\u0644\u0645\u062D\u062A\u0648\u0649 \u0645\u0646 TurboLoop \u064A\u062D\u0648\u0644 \u0625\u0628\u062F\u0627\u0639\u0643 \u0625\u0644\u0649 \u0623\u0645\u0648\u0627\u0644 \u0646\u0642\u062F\u064A\u0629. \u0642\u0645 \u0628\u0625\u0646\u0634\u0627\u0621 \u0641\u064A\u062F\u064A\u0648 \u062D\u0648\u0644 TurboLoop \u2014 \u0633\u0648\u0627\u0621 \u0643\u0627\u0646 \u0641\u064A\u062F\u064A\u0648 \u062A\u0648\u0636\u064A\u062D\u064A\u060C \u0623\u0648 \u0645\u0631\u0627\u062C\u0639\u0629\u060C \u0623\u0648 \u0628\u0631\u0646\u0627\u0645\u062C \u062A\u0639\u0644\u064A\u0645\u064A\u060C \u0623\u0648 \u0634\u0647\u0627\u062F\u0629 \u2014 \u0648\u0627\u0646\u0634\u0631\u0647 \u0639\u0644\u0649 YouTube\u060C \u0623\u0648 Instagram\u060C \u0623\u0648 Facebook\u060C \u0623\u0648 TikTok. \u0623\u0631\u0633\u0644 \u0627\u0644\u0631\u0627\u0628\u0637 \u0625\u0644\u0649 \u0641\u0631\u064A\u0642 TurboLoop\u060C \u0648\u0627\u0631\u0628\u062D \u0645\u0643\u0627\u0641\u0622\u062A \u0628\u0646\u0627\u0621\u064B \u0639\u0644\u0649 \u0639\u062F\u062F \u0627\u0644\u0645\u0634\u0627\u0647\u062F\u0627\u062A. \u0645\u0633\u062A\u0648\u064A\u0627\u062A \u0627\u0644\u0645\u0643\u0627\u0641\u0622\u062A \u0633\u062E\u064A\u0629: 10,000 \u0645\u0634\u0627\u0647\u062F\u0629 \u062A\u0643\u0633\u0628\u0643 $10\u060C \u0648 50,000 \u0645\u0634\u0627\u0647\u062F\u0629 \u062A\u0643\u0633\u0628\u0643 $50\u060C \u0648 100,000 \u0645\u0634\u0627\u0647\u062F\u0629 \u062A\u0643\u0633\u0628\u0643 $100\u060C \u0648 500,000 \u0645\u0634\u0627\u0647\u062F\u0629 \u062A\u0643\u0633\u0628\u0643 $500\u060C \u0648\u0627\u0644\u0648\u0635\u0648\u0644 \u0625\u0644\u0649 \u0639\u0644\u0627\u0645\u0629 1 \u0645\u0644\u064A\u0648\u0646 \u0645\u0634\u0627\u0647\u062F\u0629 \u064A\u0641\u062A\u062D \u0627\u0644\u062D\u062F \u0627\u0644\u0623\u0642\u0635\u0649 \u0644\u0644\u0645\u0643\u0627\u0641\u0623\u0629 \u0648\u0647\u0648 $1,000 \u0644\u0643\u0644 \u0641\u064A\u062F\u064A\u0648. \u0644\u0627 \u064A\u0648\u062C\u062F \u062D\u062F \u0644\u0639\u062F\u062F \u0645\u0642\u0627\u0637\u0639 \u0627\u0644\u0641\u064A\u062F\u064A\u0648 \u0627\u0644\u062A\u064A \u064A\u0645\u0643\u0646\u0643 \u0625\u0646\u0634\u0627\u0624\u0647\u0627\u060C \u0645\u0645\u0627 \u064A\u062C\u0639\u0644 \u0647\u0630\u0627 \u0641\u0631\u0635\u0629 \u062F\u062E\u0644 \u0645\u062A\u0643\u0631\u0631\u0629 \u0644\u0635\u0646\u0627\u0639 \u0627\u0644\u0645\u062D\u062A\u0648\u0649 \u0627\u0644\u0645\u062A\u0641\u0627\u0646\u064A\u0646.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 10,000 \u0645\u0634\u0627\u0647\u062F\u0629 \u2192 $10 | 50,000 \u0645\u0634\u0627\u0647\u062F\u0629 \u2192 $50\n\u2022 100,000 \u0645\u0634\u0627\u0647\u062F\u0629 \u2192 $100 | 500,000 \u0645\u0634\u0627\u0647\u062F\u0629 \u2192 $500\n\u2022 1,000,000 \u0645\u0634\u0627\u0647\u062F\u0629 \u2192 $1,000 \u2014 \u0627\u0644\u062D\u062F \u0627\u0644\u0623\u0642\u0635\u0649 \u0644\u0643\u0644 \u0641\u064A\u062F\u064A\u0648\n\u2022 \u0627\u0644\u0645\u0646\u0635\u0627\u062A: YouTube\u060C Instagram\u060C Facebook\u060C TikTok\n\u2022 \u0644\u0627 \u064A\u0648\u062C\u062F \u062D\u062F \u0644\u0639\u062F\u062F \u0645\u0642\u0627\u0637\u0639 \u0627\u0644\u0641\u064A\u062F\u064A\u0648 \u2014 \u0627\u0635\u0646\u0639 \u0627\u0644\u0639\u062F\u062F \u0627\u0644\u0630\u064A \u062A\u0631\u064A\u062F\u0647\n\n\u{1F48E} \u0627\u0635\u0646\u0639. \u0627\u0646\u0634\u0631. \u0627\u0631\u0628\u062D. \u0645\u062D\u062A\u0648\u0627\u0643 \u0647\u0648 \u062F\u062E\u0644\u0643.\n\n\u{1F310} turboloop.io",
