      original: "32_Bidun_KYC.png",
      headline: "\u{1F537} \u0644\u0627 \u064A\u062A\u0637\u0644\u0628 KYC",
      caption: "\u{1F537} \u0644\u0627 \u064A\u062A\u0637\u0644\u0628 KYC\n\u2726 \u062E\u0635\u0648\u0635\u064A\u062A\u0643 \u0645\u062D\u0645\u064A\u0629 \u2014 \u0645\u062D\u0641\u0638\u062A\u0643 \u0647\u064A \u0647\u0648\u064A\u062A\u0643\n\n\u062A\u0639\u0645\u0644 TurboLoop \u0639\u0644\u0649 \u0645\u0628\u062F\u0623 DeFi \u0623\u0633\u0627\u0633\u064A: \u0645\u062D\u0641\u0638\u062A\u0643 \u0647\u064A \u0647\u0648\u064A\u062A\u0643. \u0644\u0627 \u062A\u0648\u062C\u062F \u0639\u0645\u0644\u064A\u0629 KYC\u060C \u0648\u0644\u0627 \u062A\u062D\u0642\u0642 \u0645\u0646 \u0627\u0644\u0647\u0648\u064A\u0629\u060C \u0648\u0644\u0627 \u0631\u0641\u0639 \u0644\u0644\u0645\u0633\u062A\u0646\u062F\u0627\u062A\u060C \u0648\u0644\u0627 \u0635\u0648\u0631 \u0634\u062E\u0635\u064A\u0629\u060C \u0648\u0644\u0627 \u062C\u0645\u0639 \u0644\u0644\u0628\u064A\u0627\u0646\u0627\u062A \u0627\u0644\u0634\u062E\u0635\u064A\u0629 \u0645\u0646 \u0623\u064A \u0646\u0648\u0639. \u0628\u0645\u062C\u0631\u062F \u0631\u0628\u0637 \u0645\u062D\u0641\u0638\u062A\u0643\u060C \u062A\u0635\u0628\u062D \u062C\u0627\u0647\u0632\u0627\u064B \u0644\u0644\u0628\u062F\u0621. \u0644\u0627 \u064A\u0642\u062A\u0635\u0631 \u0627\u0644\u0623\u0645\u0631 \u0639\u0644\u0649 \u0627\u0644\u0633\u0647\u0648\u0644\u0629 \u0641\u062D\u0633\u0628 \u2014 \u0628\u0644 \u064A\u062A\u0639\u0644\u0642 \u0628\u062D\u0645\u0627\u064A\u0629 \u062D\u0642\u0643 \u0627\u0644\u0623\u0633\u0627\u0633\u064A \u0641\u064A \u0627\u0644\u062E\u0635\u0648\u0635\u064A\u0629 \u0627\u0644\u0645\u0627\u0644\u064A\u0629. \u0641\u064A \u0639\u0627\u0644\u0645 \u062A\u0641\u0636\u062D \u0641\u064A\u0647 \u0627\u062E\u062A\u0631\u0627\u0642\u0627\u062A \u0627\u0644\u0628\u064A\u0627\u0646\u0627\u062A \u0627\u0644\u0645\u0639\u0644\u0648\u0645\u0627\u062A \u0627\u0644\u0634\u062E\u0635\u064A\u0629 \u0644\u0645\u0644\u0627\u064A\u064A\u0646 \u0627\u0644\u0645\u0633\u062A\u062E\u062F\u0645\u064A\u0646\u060C \u0641\u0625\u0646 \u0646\u0647\u062C TurboLoop \u0627\u0644\u062E\u0627\u0644\u064A \u0645\u0646 \u0627\u0644\u0628\u064A\u0627\u0646\u0627\u062A \u064A\u0639\u0646\u064A \u0623\u0646\u0647 \u0644\u0627 \u064A\u0648\u062C\u062F \u0634\u064A\u0621 \u064A\u0645\u0643\u0646 \u0627\u062E\u062A\u0631\u0627\u0642\u0647\u060C \u0648\u0644\u0627 \u0634\u064A\u0621 \u064A\u0645\u0643\u0646 \u062A\u0633\u0631\u064A\u0628\u0647\u060C \u0648\u0644\u0627 \u0634\u064A\u0621 \u064A\u0645\u0643\u0646 \u0627\u0644\u0645\u0633\u0627\u0648\u0645\u0629 \u0639\u0644\u064A\u0647. \u0639\u0646\u0648\u0627\u0646 \u0645\u062D\u0641\u0638\u062A\u0643 \u0647\u0648 \u0647\u0648\u064A\u062A\u0643 \u0627\u0644\u0645\u0633\u062A\u0639\u0627\u0631\u0629\u060C \u0648\u0645\u0639\u0627\u0645\u0644\u0627\u062A\u0643 \u062A\u062A\u0645 \u0639\u0644\u0649 \u0627\u0644\u0634\u0628\u0643\u0629\u060C \u0648\u0647\u0648\u064A\u062A\u0643 \u062A\u0638\u0644 \u0645\u0644\u0643\u0627\u064B \u0644\u0643 \u0648\u062D\u062F\u0643.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u0635\u0641\u0631 KYC \u2014 \u0644\u0627 \u064A\u0648\u062C\u062F \u062A\u062D\u0642\u0642 \u0645\u0646 \u0627\u0644\u0647\u0648\u064A\u0629 \u0645\u0646 \u0623\u064A \u0646\u0648\u0639\n\u2022 \u0644\u0627 \u0645\u0633\u062A\u0646\u062F\u0627\u062A\u060C \u0644\u0627 \u0635\u0648\u0631\u060C \u0648\u0644\u0627 \u064A\u062A\u0645 \u062C\u0645\u0639 \u0623\u064A \u0628\u064A\u0627\u0646\u0627\u062A \u0634\u062E\u0635\u064A\u0629\n\u2022 \u0627\u0631\u0628\u0637 \u0645\u062D\u0641\u0638\u062A\u0643 \u0648\u0627\u0628\u062F\u0623 \u0641\u0648\u0631\u0627\u064B \u2014 30 \u062B\u0627\u0646\u064A\u0629\n\u2022 \u0646\u0647\u062C \u062E\u0627\u0644\u064D \u0645\u0646 \u0627\u0644\u0628\u064A\u0627\u0646\u0627\u062A \u2014 \u0644\u0627 \u0634\u064A\u0621 \u064A\u0645\u0643\u0646 \u0627\u062E\u062A\u0631\u0627\u0642\u0647 \u0623\u0648 \u062A\u0633\u0631\u064A\u0628\u0647\n\u2022 \u0639\u0646\u0648\u0627\u0646 \u0645\u062D\u0641\u0638\u062A\u0643 \u0647\u0648 \u0647\u0648\u064A\u062A\u0643 \u0627\u0644\u0645\u0633\u062A\u0639\u0627\u0631\u0629\n\n\u{1F48E} \u0645\u062D\u0641\u0638\u062A\u0643 \u0647\u064A \u0647\u0648\u064A\u062A\u0643. \u062E\u0635\u0648\u0635\u064A\u062A\u0643 \u063A\u064A\u0631 \u0642\u0627\u0628\u0644\u0629 \u0644\u0644\u062A\u0641\u0627\u0648\u0636.\n\n\u{1F310} turboloop.io",
