      original: "33_Kod_Muwathaq.png",
      headline: "\u{1F537} \u062A\u0645 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646 \u0627\u0644\u0643\u0648\u062F \u0639\u0644\u0649 BscScan",
      caption: "\u{1F537} \u062A\u0645 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646 \u0627\u0644\u0643\u0648\u062F \u0639\u0644\u0649 BscScan\n\u2726 \u0645\u0641\u062A\u0648\u062D \u0627\u0644\u0645\u0635\u062F\u0631\u060C \u0634\u0641\u0627\u0641\u060C \u0648\u064A\u0645\u0643\u0646 \u0644\u0623\u064A \u0634\u062E\u0635 \u0642\u0631\u0627\u0621\u062A\u0647\n\n\u0627\u0644\u0634\u0641\u0627\u0641\u064A\u0629 \u0647\u064A \u062D\u062C\u0631 \u0627\u0644\u0632\u0627\u0648\u064A\u0629 \u0644\u0644\u062B\u0642\u0629 \u0641\u064A DeFi\u060C \u0648 TurboLoop \u062A\u0642\u062F\u0645\u0647\u0627 \u0628\u0627\u0644\u0643\u0627\u0645\u0644. \u062A\u0645 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646 \u0627\u0644\u0643\u0648\u062F \u0627\u0644\u0645\u0635\u062F\u0631\u064A \u0627\u0644\u0643\u0627\u0645\u0644 \u0644\u0640 Smart Contract \u0639\u0644\u0649 BscScan \u2014 \u0645\u0633\u062A\u0643\u0634\u0641 \u0627\u0644\u0643\u062A\u0644 \u0627\u0644\u0631\u0633\u0645\u064A \u0644\u0640 Binance Smart Chain. \u0647\u0630\u0627 \u064A\u0639\u0646\u064A \u0623\u0646 \u0623\u064A \u0634\u062E\u0635\u060C \u0641\u064A \u0623\u064A \u0645\u0643\u0627\u0646 \u0641\u064A \u0627\u0644\u0639\u0627\u0644\u0645\u060C \u064A\u0645\u0643\u0646\u0647 \u0642\u0631\u0627\u0621\u0629 \u0643\u0644 \u0633\u0637\u0631 \u0645\u0646 \u0627\u0644\u0643\u0648\u062F \u0627\u0644\u0630\u064A \u064A\u062D\u0643\u0645 \u0627\u0644\u0628\u0631\u0648\u062A\u0648\u0643\u0648\u0644. \u0644\u0627 \u062A\u0648\u062C\u062F \u0648\u0638\u0627\u0626\u0641 \u0645\u062E\u0641\u064A\u0629\u060C \u0648\u0644\u0627 \u0645\u0646\u0637\u0642 \u063A\u0627\u0645\u0636\u060C \u0648\u0644\u0627 \u0622\u0644\u064A\u0627\u062A \u0633\u0631\u064A\u0629. \u0645\u0627 \u062A\u0631\u0627\u0647 \u0647\u0648 \u0628\u0627\u0644\u0636\u0628\u0637 \u0645\u0627 \u064A\u062A\u0645 \u062A\u0646\u0641\u064A\u0630\u0647. \u064A\u0645\u0643\u0646 \u0644\u0644\u0645\u0637\u0648\u0631\u064A\u0646 \u062A\u062F\u0642\u064A\u0642\u0647. \u064A\u0645\u0643\u0646 \u0644\u0644\u0628\u0627\u062D\u062B\u064A\u0646 \u0641\u064A \u0645\u062C\u0627\u0644 \u0627\u0644\u0623\u0645\u0646 \u062A\u062D\u0644\u064A\u0644\u0647. \u064A\u0645\u0643\u0646 \u0644\u0644\u0645\u0633\u062A\u062E\u062F\u0645\u064A\u0646 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646 \u0623\u0646 \u0627\u0644\u0639\u0642\u062F \u064A\u0641\u0639\u0644 \u0628\u0627\u0644\u0636\u0628\u0637 \u0645\u0627 \u064A\u062F\u0639\u064A\u0647. \u0647\u0630\u0627 \u0627\u0644\u0645\u0633\u062A\u0648\u0649 \u0645\u0646 \u0627\u0644\u0634\u0641\u0627\u0641\u064A\u0629 \u0645\u0633\u062A\u062D\u064A\u0644 \u0641\u064A \u0627\u0644\u062A\u0645\u0648\u064A\u0644 \u0627\u0644\u062A\u0642\u0644\u064A\u062F\u064A\u060C \u062D\u064A\u062B \u062A\u064F\u0643\u062A\u0628 \u0627\u0644\u0642\u0648\u0627\u0639\u062F \u062E\u0644\u0641 \u0623\u0628\u0648\u0627\u0628 \u0645\u063A\u0644\u0642\u0629. \u0641\u064A TurboLoop\u060C \u062A\u064F\u0643\u062A\u0628 \u0627\u0644\u0642\u0648\u0627\u0639\u062F \u0639\u0644\u0646\u0627\u064B\u060C \u0644\u064A\u0631\u0627\u0647\u0627 \u0627\u0644\u062C\u0645\u064A\u0639.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u062A\u0645 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646 \u0627\u0644\u0643\u0648\u062F \u0627\u0644\u0645\u0635\u062F\u0631\u064A \u0628\u0627\u0644\u0643\u0627\u0645\u0644 \u0639\u0644\u0649 BscScan \u2014 \u0627\u0644\u0645\u0633\u062A\u0643\u0634\u0641 \u0627\u0644\u0631\u0633\u0645\u064A \u0644\u0640 BSC\n\u2022 \u0645\u0641\u062A\u0648\u062D \u0627\u0644\u0645\u0635\u062F\u0631 \u2014 \u064A\u0645\u0643\u0646 \u0644\u0623\u064A \u0634\u062E\u0635 \u0642\u0631\u0627\u0621\u0629 \u0643\u0644 \u0633\u0637\u0631 \u0645\u0646 \u0627\u0644\u0643\u0648\u062F\n\u2022 \u0644\u0627 \u062A\u0648\u062C\u062F \u0648\u0638\u0627\u0626\u0641 \u0645\u062E\u0641\u064A\u0629\u060C \u0648\u0644\u0627 \u0645\u0646\u0637\u0642 \u063A\u0627\u0645\u0636\u060C \u0648\u0644\u0627 \u0623\u0633\u0631\u0627\u0631\n\u2022 \u064A\u0645\u0643\u0646 \u0644\u0644\u0645\u0637\u0648\u0631\u064A\u0646 \u0648\u0627\u0644\u0628\u0627\u062D\u062B\u064A\u0646 \u0641\u064A \u0645\u062C\u0627\u0644 \u0627\u0644\u0623\u0645\u0646 \u062A\u062F\u0642\u064A\u0642 \u0627\u0644\u0643\u0648\u062F \u0628\u062D\u0631\u064A\u0629\n\u2022 \u0645\u0633\u062A\u062D\u064A\u0644 \u0641\u064A \u0627\u0644\u062A\u0645\u0648\u064A\u0644 \u0627\u0644\u062A\u0642\u0644\u064A\u062F\u064A \u2014 TurboLoop \u062A\u0636\u0639 \u0627\u0644\u0645\u0639\u064A\u0627\u0631\n\n\u{1F48E} \u0627\u0642\u0631\u0623\u0647 \u0628\u0646\u0641\u0633\u0643. \u062A\u062D\u0642\u0642 \u0645\u0646\u0647 \u0628\u0646\u0641\u0633\u0643. \u0627\u0644\u0643\u0648\u062F \u0644\u0627 \u064A\u062E\u0641\u064A \u0634\u064A\u0626\u0627\u064B.\n\n\u{1F310} turboloop.io",
