      caption: "\u{1F537} \u0623\u0631\u0628\u0627\u062D \u064A\u0648\u0645\u064A\u0629\n\u2726 \u062A\u064F\u062D\u0633\u0628 \u0643\u0644 24 \u0633\u0627\u0639\u0629 \u2014 \u062A\u064F\u0636\u0627\u0641 \u062A\u0644\u0642\u0627\u0626\u064A\u0627\u064B \u0625\u0644\u0649 \u0631\u0635\u064A\u062F\u0643\n\n\u064A\u0639\u0645\u0644 Smart Contract \u0627\u0644\u062E\u0627\u0635 \u0628\u0640 TurboLoop \u0639\u0644\u0649 \u062F\u0648\u0631\u0629 \u062F\u0642\u064A\u0642\u0629 \u0645\u062F\u062A\u0647\u0627 24 \u0633\u0627\u0639\u0629. \u0643\u0644 \u064A\u0648\u0645 \u0641\u064A \u0645\u0646\u062A\u0635\u0641 \u0627\u0644\u0644\u064A\u0644 \u0628\u0627\u0644\u062A\u0648\u0642\u064A\u062A \u0627\u0644\u0639\u0627\u0644\u0645\u064A \u0627\u0644\u0645\u0646\u0633\u0642 (UTC)\u060C \u064A\u062D\u0633\u0628 \u0627\u0644\u0639\u0642\u062F \u0639\u0627\u0626\u062F\u0643 \u0627\u0644\u064A\u0648\u0645\u064A \u0628\u0646\u0627\u0621\u064B \u0639\u0644\u0649 \u062E\u0637\u062A\u0643 \u0627\u0644\u0646\u0634\u0637\u0629 \u0648\u0645\u0628\u0644\u063A \u0627\u0644\u0625\u064A\u062F\u0627\u0639\u060C \u062B\u0645 \u064A\u0636\u064A\u0641\u0647 \u0645\u0628\u0627\u0634\u0631\u0629 \u0625\u0644\u0649 \u0631\u0635\u064A\u062F\u0643 \u2014 \u062A\u0644\u0642\u0627\u0626\u064A\u0627\u064B\u060C \u062F\u0648\u0646 \u0627\u0644\u062D\u0627\u062C\u0629 \u0625\u0644\u0649 \u0623\u064A \u062A\u062F\u062E\u0644 \u0645\u0646\u0643. \u0644\u0627 \u064A\u0648\u062C\u062F \u0632\u0631 \u0644\u0644\u0646\u0642\u0631 \u0639\u0644\u064A\u0647\u060C \u0648\u0644\u0627 \u0645\u0643\u0627\u0641\u0622\u062A \u0644\u0644\u0645\u0637\u0627\u0644\u0628\u0629 \u0628\u0647\u0627\u060C \u0648\u0644\u0627 \u0631\u0633\u0648\u0645 \u063A\u0627\u0632 \u0644\u062F\u0641\u0639\u0647\u0627 \u0645\u0642\u0627\u0628\u0644 \u0627\u0644\u062D\u0635\u0627\u062F. \u0627\u0644\u0639\u0645\u0644\u064A\u0629 \u0633\u0644\u0628\u064A\u0629 \u0628\u0627\u0644\u0643\u0627\u0645\u0644. \u064A\u0645\u0643\u0646\u0643 \u062A\u062A\u0628\u0639 \u0631\u0635\u064A\u062F\u0643 \u0627\u0644\u0645\u062A\u0646\u0627\u0645\u064A \u0641\u064A \u0627\u0644\u0648\u0642\u062A \u0627\u0644\u0641\u0639\u0644\u064A \u0645\u0646 \u062E\u0644\u0627\u0644 \u0644\u0648\u062D\u0629 \u062A\u062D\u0643\u0645 TurboLoop\u060C \u0648\u0645\u0634\u0627\u0647\u062F\u0629 \u0623\u0631\u0628\u0627\u062D\u0643 \u062A\u062A\u0631\u0627\u0643\u0645 \u064A\u0648\u0645\u0627\u064B \u0628\u0639\u062F \u064A\u0648\u0645. \u0628\u0627\u0644\u0646\u0633\u0628\u0629 \u0644\u0623\u0648\u0644\u0626\u0643 \u0627\u0644\u0630\u064A\u0646 \u064A\u062E\u062A\u0627\u0631\u0648\u0646 \u0627\u0644\u0645\u0636\u0627\u0639\u0641\u0629\u060C \u064A\u0645\u0643\u0646 \u0625\u0639\u0627\u062F\u0629 \u0627\u0633\u062A\u062B\u0645\u0627\u0631 \u0639\u0648\u0627\u0626\u062F \u0643\u0644 \u062F\u0648\u0631\u0629 \u0641\u064A \u062E\u0637\u0629 \u062C\u062F\u064A\u062F\u0629\u060C \u0645\u0645\u0627 \u064A\u062E\u0644\u0642 \u0645\u0646\u062D\u0646\u0649 \u0646\u0645\u0648 \u0623\u0633\u064A \u064A\u062A\u0633\u0627\u0631\u0639 \u0628\u0645\u0631\u0648\u0631 \u0627\u0644\u0648\u0642\u062A.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u062A\u064F\u062D\u0633\u0628 \u0627\u0644\u0639\u0648\u0627\u0626\u062F \u0643\u0644 24 \u0633\u0627\u0639\u0629 \u0641\u064A \u0645\u0646\u062A\u0635\u0641 \u0627\u0644\u0644\u064A\u0644 \u0628\u0627\u0644\u062A\u0648\u0642\u064A\u062A \u0627\u0644\u0639\u0627\u0644\u0645\u064A \u0627\u0644\u0645\u0646\u0633\u0642 (UTC) \u0628\u062F\u0642\u0629\n\u2022 \u062A\u064F\u0636\u0627\u0641 \u062A\u0644\u0642\u0627\u0626\u064A\u0627\u064B \u0625\u0644\u0649 \u0631\u0635\u064A\u062F\u0643 \u2014 \u0644\u0627 \u064A\u0644\u0632\u0645 \u0623\u064A \u0625\u062C\u0631\u0627\u0621 \u064A\u062F\u0648\u064A\n\u2022 \u0644\u0627 \u062A\u0648\u062C\u062F \u0645\u0637\u0627\u0644\u0628\u0627\u062A\u060C \u0648\u0644\u0627 \u062D\u0635\u0627\u062F\u060C \u0648\u0644\u0627 \u0631\u0633\u0648\u0645 \u063A\u0627\u0632 \u0625\u0636\u0627\u0641\u064A\u0629\n\u2022 \u062A\u062A\u0628\u0639 \u0641\u064A \u0627\u0644\u0648\u0642\u062A \u0627\u0644\u0641\u0639\u0644\u064A \u0645\u0646 \u062E\u0644\u0627\u0644 \u0644\u0648\u062D\u0629 \u062A\u062D\u0643\u0645 TurboLoop\n\u2022 \u0627\u0644\u0645\u0636\u0627\u0639\u0641\u0629 \u0645\u062A\u0627\u062D\u0629 \u2014 \u0623\u0639\u062F \u0627\u0633\u062A\u062B\u0645\u0627\u0631 \u0627\u0644\u0639\u0648\u0627\u0626\u062F \u0644\u062A\u062D\u0642\u064A\u0642 \u0646\u0645\u0648 \u0623\u0633\u064A\n\n\u{1F48E} \u0627\u0633\u062A\u064A\u0642\u0638 \u0645\u0639 \u0627\u0644\u0645\u0632\u064A\u062F \u0645\u0646 \u0627\u0644\u0623\u0645\u0648\u0627\u0644 \u0643\u0644 \u064A\u0648\u0645. \u0627\u0644\u0639\u0642\u062F \u0644\u0627 \u064A\u0646\u0627\u0645 \u0623\u0628\u062F\u0627\u064B.\n\n\u{1F310} turboloop.io",
