      original: "40_Mustawayat_6_20.png",
      headline: "\u{1F537} \u0645\u0633\u062A\u0648\u064A\u0627\u062A \u0627\u0644\u0625\u062D\u0627\u0644\u0629 6-20",
      caption: "\u{1F537} \u0645\u0633\u062A\u0648\u064A\u0627\u062A \u0627\u0644\u0625\u062D\u0627\u0644\u0629 6-20\n\u2726 \u0627\u0644\u0639\u0645\u0642 \u2014 \u062D\u064A\u062B \u062A\u062A\u062D\u0648\u0644 \u0627\u0644\u0634\u0628\u0643\u0627\u062A \u0625\u0644\u0649 \u0625\u0645\u0628\u0631\u0627\u0637\u0648\u0631\u064A\u0627\u062A\n\n\u0628\u064A\u0646\u0645\u0627 \u062A\u0628\u0646\u064A \u0627\u0644\u0645\u0633\u062A\u0648\u064A\u0627\u062A \u0627\u0644\u062E\u0645\u0633\u0629 \u0627\u0644\u0623\u0648\u0644\u0649 \u0623\u0633\u0627\u0633\u0643\u060C \u0641\u0625\u0646 \u0627\u0644\u0645\u0633\u062A\u0648\u064A\u0627\u062A \u0645\u0646 6 \u0625\u0644\u0649 20 \u0647\u064A \u062D\u064A\u062B \u062A\u062A\u062D\u0648\u0644 \u0634\u0628\u0643\u062A\u0643 \u0625\u0644\u0649 \u0625\u0645\u0628\u0631\u0627\u0637\u0648\u0631\u064A\u0629. \u062A\u0648\u0632\u0639 \u0627\u0644\u0645\u0633\u062A\u0648\u064A\u0627\u062A 6-10 \u0646\u0633\u0628\u0629 2% \u0644\u0643\u0644 \u0645\u0646\u0647\u0627\u060C \u0628\u0625\u062C\u0645\u0627\u0644\u064A 10% \u0645\u0646 \u0634\u0628\u0643\u062A\u0643 \u0645\u062A\u0648\u0633\u0637\u0629 \u0627\u0644\u0639\u0645\u0642. \u062A\u0633\u0627\u0647\u0645 \u0627\u0644\u0645\u0633\u062A\u0648\u064A\u0627\u062A 11-20 \u0628\u0646\u0633\u0628\u0629 1% \u0644\u0643\u0644 \u0645\u0646\u0647\u0627\u060C \u0645\u0645\u0627 \u064A\u0636\u064A\u0641 10% \u0623\u062E\u0631\u0649 \u0645\u0646 \u0623\u0639\u0645\u0642 \u0627\u062A\u0635\u0627\u0644\u0627\u062A\u0643. \u0645\u062C\u062A\u0645\u0639\u0629\u060C \u062A\u0642\u062F\u0645 \u0627\u0644\u0645\u0633\u062A\u0648\u064A\u0627\u062A 6-20 \u0646\u0633\u0628\u0629 20% \u0645\u0646 \u0625\u062C\u0645\u0627\u0644\u064A \u062A\u0648\u0632\u064A\u0639 \u0627\u0644\u0625\u062D\u0627\u0644\u0629 \u2014 \u062A\u062F\u0641\u0642 \u062F\u062E\u0644 \u0633\u0644\u0628\u064A \u0647\u0627\u0626\u0644 \u064A\u0646\u0645\u0648 \u0628\u0634\u0643\u0644 \u0643\u0628\u064A\u0631 \u0645\u0639 \u062A\u0639\u0645\u0642 \u0634\u0628\u0643\u062A\u0643. \u064A\u0643\u0645\u0646 \u062C\u0645\u0627\u0644 \u0645\u0633\u062A\u0648\u064A\u0627\u062A \u0627\u0644\u0625\u062D\u0627\u0644\u0629 \u0627\u0644\u0639\u0645\u064A\u0642\u0629 \u0641\u064A \u0623\u0646\u0647\u0627 \u062A\u062A\u0636\u0627\u0639\u0641 \u0628\u0634\u0643\u0644 \u0639\u0636\u0648\u064A: \u0641\u0628\u064A\u0646\u0645\u0627 \u064A\u0628\u0646\u064A \u0627\u0644\u0645\u062D\u0627\u0644\u0648\u0646 \u0634\u0628\u0643\u0627\u062A\u0647\u0645 \u0627\u0644\u062E\u0627\u0635\u0629\u060C \u062A\u0645\u062A\u0644\u0626 \u0645\u0633\u062A\u0648\u064A\u0627\u062A\u0643 \u0627\u0644\u0639\u0645\u064A\u0642\u0629 \u062A\u0644\u0642\u0627\u0626\u064A\u0627\u064B \u062F\u0648\u0646 \u0623\u064A \u062C\u0647\u062F \u0625\u0636\u0627\u0641\u064A \u0645\u0646\u0643. \u0647\u0630\u0627 \u0647\u0648 \u0627\u0644\u0645\u0643\u0627\u0646 \u0627\u0644\u0630\u064A \u064A\u0631\u0649 \u0641\u064A\u0647 \u0628\u0646\u0627\u0629 \u0627\u0644\u0634\u0628\u0643\u0627\u062A \u0627\u0644\u0635\u0628\u0648\u0631\u0648\u0646 \u0623\u0631\u0628\u0627\u062D\u0647\u0645 \u062A\u062A\u0636\u0627\u0639\u0641.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u0627\u0644\u0645\u0633\u062A\u0648\u064A\u0627\u062A 6-10: 2% \u0644\u0643\u0644 \u0645\u0646\u0647\u0627 \u2014 \u0625\u062C\u0645\u0627\u0644\u064A 10% \u0645\u0646 \u0627\u0644\u0634\u0628\u0643\u0629 \u0645\u062A\u0648\u0633\u0637\u0629 \u0627\u0644\u0639\u0645\u0642\n\u2022 \u0627\u0644\u0645\u0633\u062A\u0648\u064A\u0627\u062A 11-20: 1% \u0644\u0643\u0644 \u0645\u0646\u0647\u0627 \u2014 \u0625\u062C\u0645\u0627\u0644\u064A 10% \u0645\u0646 \u0627\u0644\u0634\u0628\u0643\u0629 \u0627\u0644\u0639\u0645\u064A\u0642\u0629\n\u2022 \u0627\u0644\u0645\u0633\u062A\u0648\u064A\u0627\u062A 6-20 \u0645\u062C\u062A\u0645\u0639\u0629: 20% \u0625\u062C\u0645\u0627\u0644\u064A \u0627\u0644\u062A\u0648\u0632\u064A\u0639\n\u2022 \u062A\u0645\u062A\u0644\u0626 \u0627\u0644\u0645\u0633\u062A\u0648\u064A\u0627\u062A \u0627\u0644\u0639\u0645\u064A\u0642\u0629 \u0639\u0636\u0648\u064A\u0627\u064B \u0645\u0639 \u0646\u0645\u0648 \u0634\u0628\u0643\u062A\u0643\n\u2022 \u0627\u0644\u0625\u062C\u0645\u0627\u0644\u064A \u0627\u0644\u0643\u0644\u064A \u0644\u062C\u0645\u064A\u0639 \u0627\u0644\u0645\u0633\u062A\u0648\u064A\u0627\u062A \u0627\u0644\u0639\u0634\u0631\u064A\u0646: 51% \u2014 \u0645\u0646 \u0623\u0639\u0644\u0649 \u0627\u0644\u0645\u0639\u062F\u0644\u0627\u062A \u0641\u064A DeFi\n\n\u{1F48E} \u0627\u0644\u0639\u0645\u0642 \u064A\u0635\u0646\u0639 \u0627\u0644\u062B\u0631\u0648\u0629. \u0627\u0628\u0646\u0650 \u0639\u0644\u0649 \u0646\u0637\u0627\u0642 \u0648\u0627\u0633\u0639\u060C \u0627\u0646\u0645\u0648 \u0628\u0639\u0645\u0642\u060C \u0648\u0627\u0643\u0633\u0628 \u0625\u0644\u0649 \u0627\u0644\u0623\u0628\u062F.\n\n\u{1F310} turboloop.io",
