      original: "54_Audit_Tafasil.png",
      headline: "\u{1F537} \u0645\u062F\u0642\u0642 \u0648\u0645\u0648\u062B\u0642 \u2014 \u0628\u0627\u0644\u062A\u0641\u0635\u064A\u0644",
      caption: "\u{1F537} \u0645\u062F\u0642\u0642 \u0648\u0645\u0648\u062B\u0642 \u2014 \u0628\u0627\u0644\u062A\u0641\u0635\u064A\u0644\n\u2726 \u062F\u0627\u062E\u0644 \u0627\u0644\u062A\u062F\u0642\u064A\u0642 \u2014 \u0645\u0627\u0630\u0627 \u062A\u0639\u0646\u064A \u062F\u0631\u062C\u0629 99% \u062D\u0642\u0627\u064B\n\n\u0625\u0646 \u062F\u0631\u062C\u0629 \u0627\u0644\u062B\u0642\u0629 \u0627\u0644\u0628\u0627\u0644\u063A\u0629 99% \u0641\u064A \u062A\u062F\u0642\u064A\u0642 TurboLoop \u0644\u064A\u0633\u062A \u0645\u062C\u0631\u062F \u0631\u0642\u0645 \u2014 \u0628\u0644 \u062A\u0645\u062B\u0644 \u062A\u0642\u064A\u064A\u0645\u0627\u064B \u0623\u0645\u0646\u064A\u0627\u064B \u0634\u0627\u0645\u0644\u0627\u064B \u0644\u0643\u0644 \u062C\u0627\u0646\u0628 \u0645\u0646 \u062C\u0648\u0627\u0646\u0628 \u0627\u0644\u0640 Smart Contract. \u0641\u062D\u0635 \u0627\u0644\u062A\u062F\u0642\u064A\u0642 \u0627\u0644\u0645\u0633\u062A\u0642\u0644: \u0645\u0646\u0637\u0642 \u0627\u0644\u0639\u0642\u062F \u0648\u0627\u0644\u062F\u0642\u0629 \u0627\u0644\u0631\u064A\u0627\u0636\u064A\u0629\u060C \u0622\u0644\u064A\u0627\u062A \u0627\u0644\u062A\u062D\u0643\u0645 \u0641\u064A \u0627\u0644\u0648\u0635\u0648\u0644\u060C \u0627\u0644\u062D\u0645\u0627\u064A\u0629 \u0645\u0646 \u0625\u0639\u0627\u062F\u0629 \u0627\u0644\u062F\u062E\u0648\u0644\u060C \u0636\u0645\u0627\u0646\u0627\u062A \u0627\u0644\u062A\u062C\u0627\u0648\u0632/\u0627\u0644\u0646\u0642\u0635\u0627\u0646\u060C \u062A\u062D\u0633\u064A\u0646 \u0627\u0644\u063A\u0627\u0632\u060C \u0648\u0645\u0633\u0627\u0631\u0627\u062A \u0627\u0644\u0647\u062C\u0648\u0645 \u0627\u0644\u0645\u062D\u062A\u0645\u0644\u0629. \u0627\u0644\u0646\u062A\u064A\u062C\u0629: \u0635\u0641\u0631 \u062B\u063A\u0631\u0627\u062A \u062D\u0631\u062C\u0629\u060C \u0635\u0641\u0631 \u0645\u0634\u0643\u0644\u0627\u062A \u0639\u0627\u0644\u064A\u0629 \u0627\u0644\u0645\u062E\u0627\u0637\u0631\u060C \u0648\u0628\u0646\u064A\u0629 \u0639\u0642\u062F \u0645\u0635\u0646\u0641\u0629 \u0645\u0646 \u0628\u064A\u0646 \u0627\u0644\u0623\u0643\u062B\u0631 \u0623\u0645\u0627\u0646\u0627\u064B \u0639\u0644\u0649 BSC. \u062A\u0642\u0631\u064A\u0631 \u0627\u0644\u062A\u062F\u0642\u064A\u0642 \u0627\u0644\u0643\u0627\u0645\u0644 \u0645\u062A\u0627\u062D \u0644\u0644\u062C\u0645\u0647\u0648\u0631\u060C \u0648\u064A\u0641\u0635\u0644 \u0643\u0644 \u0627\u062E\u062A\u0628\u0627\u0631 \u062A\u0645 \u0625\u062C\u0631\u0627\u0624\u0647 \u0648\u0643\u0644 \u0646\u062A\u064A\u062C\u0629 \u062A\u0645 \u062A\u0648\u062B\u064A\u0642\u0647\u0627. \u0628\u0627\u0644\u0627\u0642\u062A\u0631\u0627\u0646 \u0645\u0639 \u0627\u0644\u0643\u0648\u062F \u0627\u0644\u0645\u0635\u062F\u0631\u064A \u0627\u0644\u0645\u0648\u062B\u0642 \u0639\u0644\u0649 BscScan\u060C \u0648\u0627\u0644\u062A\u0646\u0627\u0632\u0644 \u0639\u0646 \u0627\u0644\u0645\u0644\u0643\u064A\u0629\u060C \u0648 LP \u0627\u0644\u0645\u0642\u0641\u0644 \u0628\u0634\u0643\u0644 \u062F\u0627\u0626\u0645\u060C \u0641\u0625\u0646 \u062D\u0632\u0645\u0629 \u0623\u0645\u0627\u0646 TurboLoop \u0634\u0627\u0645\u0644\u0629\u060C \u0642\u0627\u0628\u0644\u0629 \u0644\u0644\u062A\u062D\u0642\u0642\u060C \u0648\u0644\u0627 \u062A\u0642\u0628\u0644 \u0627\u0644\u0645\u0633\u0627\u0648\u0645\u0629.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u062F\u0631\u062C\u0629 \u062B\u0642\u0629 99% \u0645\u0646 \u062A\u062F\u0642\u064A\u0642 \u0623\u0645\u0646\u064A \u0645\u0633\u062A\u0642\u0644 \u0648\u0634\u0627\u0645\u0644\n\u2022 \u0635\u0641\u0631 \u062B\u063A\u0631\u0627\u062A \u062D\u0631\u062C\u0629\u060C \u0635\u0641\u0631 \u0645\u0634\u0643\u0644\u0627\u062A \u0639\u0627\u0644\u064A\u0629 \u0627\u0644\u0645\u062E\u0627\u0637\u0631 \u062A\u0645 \u0627\u0644\u0639\u062B\u0648\u0631 \u0639\u0644\u064A\u0647\u0627\n\u2022 \u0634\u0645\u0644 \u0627\u0644\u062A\u062F\u0642\u064A\u0642: \u0627\u0644\u0645\u0646\u0637\u0642\u060C \u0627\u0644\u062A\u062D\u0643\u0645 \u0641\u064A \u0627\u0644\u0648\u0635\u0648\u0644\u060C \u0625\u0639\u0627\u062F\u0629 \u0627\u0644\u062F\u062E\u0648\u0644\u060C \u0627\u0644\u062D\u0645\u0627\u064A\u0629 \u0645\u0646 \u0627\u0644\u062A\u062C\u0627\u0648\u0632\n\u2022 \u062A\u0642\u0631\u064A\u0631 \u0627\u0644\u062A\u062F\u0642\u064A\u0642 \u0627\u0644\u0643\u0627\u0645\u0644 \u0645\u062A\u0627\u062D \u0644\u0644\u062C\u0645\u0647\u0648\u0631 \u0644\u064A\u0631\u0627\u062C\u0639\u0647 \u0623\u064A \u0634\u062E\u0635\n\u2022 \u0645\u0642\u062A\u0631\u0646 \u0628\u0643\u0648\u062F \u0645\u0648\u062B\u0642\u060C \u062A\u0646\u0627\u0632\u0644 \u0639\u0646 \u0627\u0644\u0645\u0644\u0643\u064A\u0629\u060C \u0648 LP \u0645\u0642\u0641\u0644\n\n\u{1F48E} \u0645\u0648\u062B\u0642. \u0645\u062F\u0642\u0642. \u0645\u0624\u0645\u0646. \u062A\u0645 \u0641\u062D\u0635 \u0648\u062A\u0623\u0643\u064A\u062F \u0643\u0644 \u0637\u0628\u0642\u0629.\n\n\u{1F310} turboloop.io",
