      original: "56_LP_Muqfal_Tafasil.png",
      headline: "\u{1F537} LP \u0645\u0642\u0641\u0644 \u2014 \u0628\u0627\u0644\u062A\u0641\u0635\u064A\u0644",
      caption: "\u{1F537} LP \u0645\u0642\u0641\u0644 \u2014 \u0628\u0627\u0644\u062A\u0641\u0635\u064A\u0644\n\u2726 \u062D\u0645\u0627\u064A\u0629 \u0627\u0644\u0633\u064A\u0648\u0644\u0629 \u0627\u0644\u062F\u0627\u0626\u0645\u0629 \u2014 \u0627\u0644\u0648\u0627\u0642\u0639 \u0627\u0644\u062A\u0642\u0646\u064A\n\n\u0642\u0641\u0644 \u0645\u062C\u0645\u0639 \u0627\u0644\u0633\u064A\u0648\u0644\u0629 \u0627\u0644\u062E\u0627\u0635 \u0628\u0640 TurboLoop \u0644\u064A\u0633 \u0625\u062C\u0631\u0627\u0621\u064B \u0645\u062D\u062F\u062F\u064B\u0627 \u0628\u0648\u0642\u062A \u2014 \u0628\u0644 \u0647\u0648 \u062F\u0627\u0626\u0645. \u062A\u0645 \u0625\u0631\u0633\u0627\u0644 \u0631\u0645\u0648\u0632 LP \u0627\u0644\u062A\u064A \u062A\u0645\u062B\u0644 \u0633\u064A\u0648\u0644\u0629 \u0627\u0644\u0628\u0631\u0648\u062A\u0648\u0643\u0648\u0644 \u0625\u0644\u0649 \u0639\u0642\u062F \u0642\u0641\u0644 \u0628\u062F\u0648\u0646 \u062A\u0627\u0631\u064A\u062E \u0627\u0646\u062A\u0647\u0627\u0621 \u0635\u0644\u0627\u062D\u064A\u0629 \u0648\u0628\u062F\u0648\u0646 \u0648\u0638\u064A\u0641\u0629 \u0633\u062D\u0628. \u0647\u0630\u0627 \u064A\u0639\u0646\u064A: \u0644\u0627 \u064A\u0645\u0643\u0646 \u0644\u0623\u064A \u0634\u062E\u0635 \u0625\u0632\u0627\u0644\u0629 \u0627\u0644\u0633\u064A\u0648\u0644\u0629 \u0627\u0644\u062A\u064A \u062A\u062F\u0639\u0645 TurboLoop\u060C \u062A\u062D\u062A \u0623\u064A \u0638\u0631\u0641 \u0645\u0646 \u0627\u0644\u0638\u0631\u0648\u0641\u060C \u0639\u0644\u0649 \u0627\u0644\u0625\u0637\u0644\u0627\u0642. \u0645\u0646 \u0627\u0644\u0646\u0627\u062D\u064A\u0629 \u0627\u0644\u0639\u0645\u0644\u064A\u0629\u060C \u0647\u0630\u0627 \u064A\u0642\u0636\u064A \u0639\u0644\u0649 \u0627\u0644\u0647\u062C\u0648\u0645 \u0627\u0644\u0623\u0643\u062B\u0631 \u062A\u062F\u0645\u064A\u0631\u0627\u064B \u0641\u064A DeFi \u2014 \u0633\u062D\u0628 \u0627\u0644\u0628\u0633\u0627\u0637 \u2014 \u062D\u064A\u062B \u064A\u0642\u0648\u0645 \u0627\u0644\u0645\u0637\u0648\u0631\u0648\u0646 \u0628\u0627\u0633\u062A\u0646\u0632\u0627\u0641 \u0627\u0644\u0633\u064A\u0648\u0644\u0629 \u0648\u062A\u0631\u0643 \u0627\u0644\u0645\u0633\u062A\u062B\u0645\u0631\u064A\u0646 \u0628\u0631\u0645\u0648\u0632 \u0639\u062F\u064A\u0645\u0629 \u0627\u0644\u0642\u064A\u0645\u0629. \u0645\u0639 TurboLoop\u060C \u0647\u0630\u0627 \u0627\u0644\u0633\u064A\u0646\u0627\u0631\u064A\u0648 \u0645\u0633\u062A\u062D\u064A\u0644 \u0645\u0639\u0645\u0627\u0631\u064A\u0627\u064B. \u064A\u062A\u0645 \u0641\u0631\u0636 \u0627\u0644\u0642\u0641\u0644 \u0628\u0648\u0627\u0633\u0637\u0629 \u0643\u0648\u062F Smart Contract\u060C \u0648\u0644\u064A\u0633 \u0645\u0646 \u062E\u0644\u0627\u0644 \u0627\u0644\u062B\u0642\u0629 \u0641\u064A \u0623\u064A \u0641\u0631\u062F. \u064A\u0645\u0643\u0646 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646\u0647 \u0639\u0644\u0649 BscScan\u060C \u0648\u0647\u0648 \u062F\u0627\u0626\u0645 \u0645\u062B\u0644 \u0627\u0644\u0628\u0644\u0648\u0643\u0634\u064A\u0646 \u0646\u0641\u0633\u0647.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 LP \u0645\u0642\u0641\u0644 \u0628\u0634\u0643\u0644 \u062F\u0627\u0626\u0645 \u2014 \u0644\u0627 \u064A\u0648\u062C\u062F \u062A\u0627\u0631\u064A\u062E \u0627\u0646\u062A\u0647\u0627\u0621 \u0635\u0644\u0627\u062D\u064A\u0629\u060C \u0648\u0644\u0627 \u0648\u0638\u064A\u0641\u0629 \u0633\u062D\u0628\n\u2022 \u0644\u0627 \u064A\u0645\u0643\u0646 \u0644\u0623\u064A \u0634\u062E\u0635 \u0625\u0632\u0627\u0644\u0629 \u0627\u0644\u0633\u064A\u0648\u0644\u0629 \u062A\u062D\u062A \u0623\u064A \u0638\u0631\u0641 \u0645\u0646 \u0627\u0644\u0638\u0631\u0648\u0641\n\u2022 \u0633\u062D\u0628 \u0627\u0644\u0628\u0633\u0627\u0637 \u0645\u0633\u062A\u062D\u064A\u0644 \u0645\u0639\u0645\u0627\u0631\u064A\u0627\u064B \u2014 \u062A\u0645 \u0627\u0644\u0642\u0636\u0627\u0621 \u0639\u0644\u064A\u0647 \u0645\u0646 \u062E\u0644\u0627\u0644 \u0627\u0644\u062A\u0635\u0645\u064A\u0645\n\u2022 \u0642\u0641\u0644 \u0645\u0641\u0631\u0648\u0636 \u0628\u0648\u0627\u0633\u0637\u0629 \u0643\u0648\u062F Smart Contract \u2014 \u0648\u0644\u064A\u0633 \u0648\u0639\u0648\u062F\u0627\u064B \u0628\u0634\u0631\u064A\u0629\n\u2022 \u064A\u0645\u0643\u0646 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646\u0647 \u0639\u0644\u0649 BscScan \u2014 \u062F\u0627\u0626\u0645 \u0645\u062B\u0644 \u0627\u0644\u0628\u0644\u0648\u0643\u0634\u064A\u0646 \u0646\u0641\u0633\u0647\n\n\u{1F48E} \u0627\u0644\u0633\u064A\u0648\u0644\u0629 \u0645\u0642\u0641\u0644\u0629. \u0633\u062D\u0628 \u0627\u0644\u0628\u0633\u0627\u0637 \u0645\u0633\u062A\u062D\u064A\u0644. \u0645\u062D\u0645\u064A \u0644\u0644\u0623\u0628\u062F.\n\n\u{1F310} turboloop.io",
