      headline: "\u{1F537} \u0628\u062F\u0648\u0646 KYC \u2014 \u0628\u0627\u0644\u062A\u0641\u0635\u064A\u0644",
      caption: "\u{1F537} \u0628\u062F\u0648\u0646 KYC \u2014 \u0628\u0627\u0644\u062A\u0641\u0635\u064A\u0644\n\u2726 \u062E\u0635\u0648\u0635\u064A\u0629 \u0643\u0627\u0645\u0644\u0629 \u0628\u0627\u0644\u062A\u0635\u0645\u064A\u0645 \u2014 \u0648\u0644\u064A\u0633 \u0628\u0627\u0644\u0648\u0639\u0648\u062F\n\n\u0633\u064A\u0627\u0633\u0629 \u0635\u0641\u0631-KYC \u0627\u0644\u062E\u0627\u0635\u0629 \u0628\u0640 TurboLoop \u0644\u064A\u0633\u062A \u0637\u0631\u064A\u0642\u0627\u064B \u0645\u062E\u062A\u0635\u0631\u0627\u064B \u0623\u0648 \u0633\u0647\u0648\u0627\u064B \u2014 \u0628\u0644 \u0647\u064A \u0642\u0631\u0627\u0631 \u0645\u0639\u0645\u0627\u0631\u064A \u0645\u062A\u0639\u0645\u062F \u0645\u062A\u062C\u0630\u0631 \u0641\u064A \u0627\u0644\u0641\u0644\u0633\u0641\u0629 \u0627\u0644\u0623\u0633\u0627\u0633\u064A\u0629 \u0644\u0640 DeFi. \u0625\u0644\u064A\u0643 \u0645\u0627 \u064A\u0639\u0646\u064A\u0647 \u0630\u0644\u0643 \u0639\u0645\u0644\u064A\u0627\u064B: \u0644\u0627 \u062A\u064F\u0637\u0644\u0628 \u0623\u0628\u062F\u0627\u064B \u0623\u064A \u0645\u0633\u062A\u0646\u062F\u0627\u062A \u0647\u0648\u064A\u0629. \u0644\u0627 \u064A\u064F\u0634\u062A\u0631\u0637 \u062A\u0642\u062F\u064A\u0645 \u0635\u0648\u0631 \u0641\u0648\u062A\u0648\u063A\u0631\u0627\u0641\u064A\u0629 \u0623\u0648 \u0635\u0648\u0631 \u0634\u062E\u0635\u064A\u0629. \u0644\u0627 \u064A\u062A\u0645 \u062C\u0645\u0639 \u0623\u0648 \u062A\u062E\u0632\u064A\u0646 \u0623\u0648 \u0645\u0639\u0627\u0644\u062C\u0629 \u0623\u064A \u0645\u0639\u0644\u0648\u0645\u0627\u062A \u0634\u062E\u0635\u064A\u0629 \u2014 \u0627\u0644\u0627\u0633\u0645\u060C \u0627\u0644\u0639\u0646\u0648\u0627\u0646\u060C \u0631\u0642\u0645 \u0627\u0644\u0647\u0627\u062A\u0641\u060C \u0627\u0644\u0628\u0631\u064A\u062F \u0627\u0644\u0625\u0644\u0643\u062A\u0631\u0648\u0646\u064A. \u0644\u0627 \u062A\u064F\u0633\u062A\u062E\u062F\u0645 \u0623\u064A \u062E\u062F\u0645\u0627\u062A \u062A\u062D\u0642\u0642 \u0645\u0646 \u0627\u0644\u0647\u0648\u064A\u0629 \u062A\u0627\u0628\u0639\u0629 \u0644\u062C\u0647\u0627\u062A \u062E\u0627\u0631\u062C\u064A\u0629. \u0639\u0646\u0648\u0627\u0646 \u0645\u062D\u0641\u0638\u062A\u0643 \u0647\u0648 \u0627\u0644\u0645\u0639\u0631\u0641 \u0627\u0644\u0648\u062D\u064A\u062F \u0627\u0644\u062E\u0627\u0635 \u0628\u0643\u060C \u0648\u0647\u0648 \u0645\u0633\u062A\u0639\u0627\u0631 \u0627\u0644\u0647\u0648\u064A\u0629 \u0628\u0637\u0628\u064A\u0639\u062A\u0647. \u064A\u0642\u0636\u064A \u0647\u0630\u0627 \u0627\u0644\u0646\u0647\u062C \u0639\u0644\u0649 \u0645\u062E\u0627\u0637\u0631 \u0627\u062E\u062A\u0631\u0627\u0642 \u0627\u0644\u0628\u064A\u0627\u0646\u0627\u062A\u060C \u0648\u0633\u0631\u0642\u0629 \u0627\u0644\u0647\u0648\u064A\u0629\u060C \u0648\u0627\u0644\u0645\u0631\u0627\u0642\u0628\u0629 \u063A\u064A\u0631 \u0627\u0644\u0645\u0635\u0631\u062D \u0628\u0647\u0627. \u0641\u064A \u0639\u0627\u0644\u0645 \u062D\u064A\u062B \u062A\u0643\u0634\u0641 \u0627\u0644\u0645\u0646\u0635\u0627\u062A \u0627\u0644\u0645\u0631\u0643\u0632\u064A\u0629 \u0628\u0627\u0646\u062A\u0638\u0627\u0645 \u0639\u0646 \u0627\u0644\u0628\u064A\u0627\u0646\u0627\u062A \u0627\u0644\u0634\u062E\u0635\u064A\u0629 \u0644\u0645\u0644\u0627\u064A\u064A\u0646 \u0627\u0644\u0645\u0633\u062A\u062E\u062F\u0645\u064A\u0646\u060C \u0641\u0625\u0646 \u0628\u0646\u064A\u0629 \u0627\u0644\u0628\u064A\u0627\u0646\u0627\u062A \u0627\u0644\u0635\u0641\u0631\u064A\u0629 \u0627\u0644\u062E\u0627\u0635\u0629 \u0628\u0640 TurboLoop \u0647\u064A \u0627\u0644\u062D\u0645\u0627\u064A\u0629 \u0627\u0644\u0642\u0635\u0648\u0649 \u0644\u0644\u062E\u0635\u0648\u0635\u064A\u0629.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u0635\u0641\u0631 \u0645\u0633\u062A\u0646\u062F\u0627\u062A \u2014 \u0644\u0627 \u062A\u064F\u0637\u0644\u0628 \u0623\u0628\u062F\u0627\u064B \u0623\u064A \u0647\u0648\u064A\u0629 \u0623\u0648 \u062C\u0648\u0627\u0632 \u0633\u0641\u0631 \u0623\u0648 \u0631\u062E\u0635\u0629 \u0642\u064A\u0627\u062F\u0629\n\u2022 \u0635\u0641\u0631 \u0628\u064A\u0627\u0646\u0627\u062A \u0634\u062E\u0635\u064A\u0629 \u2014 \u0644\u0627 \u064A\u062A\u0645 \u062C\u0645\u0639 \u0623\u064A \u0627\u0633\u0645 \u0623\u0648 \u0639\u0646\u0648\u0627\u0646 \u0623\u0648 \u0647\u0627\u062A\u0641 \u0623\u0648 \u0628\u0631\u064A\u062F \u0625\u0644\u0643\u062A\u0631\u0648\u0646\u064A\n\u2022 \u0635\u0641\u0631 \u062A\u062D\u0642\u0642 \u0645\u0646 \u062C\u0647\u0627\u062A \u062E\u0627\u0631\u062C\u064A\u0629 \u2014 \u0644\u0627 \u062A\u0648\u062C\u062F \u062E\u062F\u0645\u0627\u062A \u0647\u0648\u064A\u0629 \u0645\u062A\u0636\u0645\u0646\u0629\n\u2022 \u0645\u0633\u062A\u0639\u0627\u0631 \u0627\u0644\u0647\u0648\u064A\u0629 \u0628\u0627\u0644\u062A\u0635\u0645\u064A\u0645 \u2014 \u0639\u0646\u0648\u0627\u0646 \u0645\u062D\u0641\u0638\u062A\u0643 \u0647\u0648 \u0647\u0648\u064A\u062A\u0643 \u0627\u0644\u0648\u062D\u064A\u062F\u0629\n\u2022 \u0635\u0641\u0631 \u0628\u064A\u0627\u0646\u0627\u062A = \u0635\u0641\u0631 \u0645\u062E\u0627\u0637\u0631 \u0627\u062E\u062A\u0631\u0627\u0642 \u2014 \u0627\u0644\u062D\u0645\u0627\u064A\u0629 \u0627\u0644\u0642\u0635\u0648\u0649 \u0644\u0644\u062E\u0635\u0648\u0635\u064A\u0629\n\n\u{1F48E} \u0647\u0648\u064A\u062A\u0643 \u0645\u0644\u0643 \u0644\u0643 \u0648\u062D\u062F\u0643. TurboLoop \u0644\u0627 \u062A\u062C\u0645\u0639 \u0634\u064A\u0626\u0627\u064B.\n\n\u{1F310} turboloop.io",
