      headline: "\u{1F537} \u0627\u0644\u0643\u0648\u062F \u0645\u0648\u062B\u0642 \u2014 \u0628\u0627\u0644\u062A\u0641\u0635\u064A\u0644",
      caption: '\u{1F537} \u0627\u0644\u0643\u0648\u062F \u0645\u0648\u062B\u0642 \u2014 \u0628\u0627\u0644\u062A\u0641\u0635\u064A\u0644\n\u2726 \u0645\u0627\u0630\u0627 \u064A\u0639\u0646\u064A \u0627\u0644\u0643\u0648\u062F \u0627\u0644\u0645\u0635\u062F\u0631\u064A \u0627\u0644\u0645\u0648\u062B\u0642 \u0628\u0627\u0644\u0646\u0633\u0628\u0629 \u0644\u0643\n\n\u0639\u0646\u062F\u0645\u0627 \u0646\u0642\u0648\u0644 \u0625\u0646 \u0643\u0648\u062F TurboLoop "\u0645\u0648\u062B\u0642 \u0639\u0644\u0649 BscScan"\u060C \u0641\u0647\u0630\u0627 \u064A\u0639\u0646\u064A \u0628\u0627\u0644\u0636\u0628\u0637: \u062A\u0645 \u062A\u0642\u062F\u064A\u0645 \u0627\u0644\u0643\u0648\u062F \u0627\u0644\u0645\u0635\u062F\u0631\u064A \u0627\u0644\u0643\u0627\u0645\u0644 \u0628\u0644\u063A\u0629 Solidity \u0627\u0644\u062E\u0627\u0635 \u0628\u0640 Smart Contract \u0648\u062A\u0623\u0643\u064A\u062F\u0647 \u0645\u0646 \u0642\u0628\u0644 BscScan \u2014 \u0645\u0633\u062A\u0643\u0634\u0641 \u0627\u0644\u0643\u062A\u0644 \u0627\u0644\u0631\u0633\u0645\u064A \u0644\u0634\u0628\u0643\u0629 Binance Smart Chain. \u0644\u0642\u062F \u062A\u062D\u0642\u0642 BscScan \u0645\u0646 \u0623\u0646 \u0627\u0644\u0631\u0645\u0632 \u0627\u0644\u0628\u0631\u0645\u062C\u064A (bytecode) \u0627\u0644\u0645\u0646\u0634\u0648\u0631 \u064A\u062A\u0637\u0627\u0628\u0642 \u062A\u0645\u0627\u0645\u0627\u064B \u0645\u0639 \u0627\u0644\u0643\u0648\u062F \u0627\u0644\u0645\u0635\u062F\u0631\u064A \u0627\u0644\u0645\u0642\u062F\u0645\u060C \u0645\u0645\u0627 \u064A\u0639\u0646\u064A \u0623\u0646 \u0645\u0627 \u062A\u0642\u0631\u0623\u0647 \u0647\u0648 \u0645\u0627 \u064A\u062A\u0645 \u062A\u0646\u0641\u064A\u0630\u0647. \u064A\u0645\u0643\u0646 \u0644\u0623\u064A \u0634\u062E\u0635 \u0632\u064A\u0627\u0631\u0629 \u0639\u0646\u0648\u0627\u0646 \u0627\u0644\u0639\u0642\u062F \u0639\u0644\u0649 BscScan\u060C \u0648\u0627\u0644\u0646\u0642\u0631 \u0639\u0644\u0649 "Contract"\u060C \u062B\u0645 "Read Contract" \u0623\u0648 "Code"\u060C \u0648\u0641\u062D\u0635 \u0643\u0644 \u0648\u0638\u064A\u0641\u0629\u060C \u0648\u0643\u0644 \u0645\u062A\u063A\u064A\u0631\u060C \u0648\u0643\u0644 \u0633\u0637\u0631 \u0645\u0646 \u0627\u0644\u0645\u0646\u0637\u0642. \u0644\u0627 \u062A\u0648\u062C\u062F \u0648\u0638\u0627\u0626\u0641 \u0645\u062E\u0641\u064A\u0629\u060C \u0648\u0644\u0627 \u0639\u0642\u0648\u062F \u0648\u0643\u064A\u0644\u0629 (proxy contracts) \u062A\u062E\u0641\u064A \u0627\u0644\u0643\u0648\u062F \u0627\u0644\u062D\u0642\u064A\u0642\u064A\u060C \u0648\u0644\u0627 \u062A\u0642\u0646\u064A\u0627\u062A \u062A\u0634\u0648\u064A\u0634. \u064A\u062A\u064A\u062D \u0647\u0630\u0627 \u0627\u0644\u0645\u0633\u062A\u0648\u0649 \u0645\u0646 \u0627\u0644\u0634\u0641\u0627\u0641\u064A\u0629 \u0644\u0644\u0645\u0637\u0648\u0631\u064A\u0646 \u0648\u0627\u0644\u0645\u062F\u0642\u0642\u064A\u0646 \u0648\u0627\u0644\u0645\u0633\u062A\u062E\u062F\u0645\u064A\u0646 \u0627\u0644\u062A\u062D\u0642\u0642 \u0628\u0634\u0643\u0644 \u0645\u0633\u062A\u0642\u0644 \u0645\u0646 \u0623\u0646 TurboLoop \u064A\u0639\u0645\u0644 \u062A\u0645\u0627\u0645\u0627\u064B \u0643\u0645\u0627 \u0647\u0648 \u0645\u0639\u0644\u0646.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u062A\u0645 \u062A\u0642\u062F\u064A\u0645 \u0627\u0644\u0643\u0648\u062F \u0627\u0644\u0645\u0635\u062F\u0631\u064A \u0648\u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646\u0647 \u0631\u0633\u0645\u064A\u0627\u064B \u0628\u0648\u0627\u0633\u0637\u0629 BscScan\n\u2022 \u0627\u0644\u0631\u0645\u0632 \u0627\u0644\u0628\u0631\u0645\u062C\u064A (bytecode) \u0627\u0644\u0645\u0646\u0634\u0648\u0631 \u064A\u062A\u0637\u0627\u0628\u0642 \u062A\u0645\u0627\u0645\u0627\u064B \u0645\u0639 \u0627\u0644\u0643\u0648\u062F \u0627\u0644\u0645\u0635\u062F\u0631\u064A \u2014 \u0645\u0624\u0643\u062F\n\u2022 \u0643\u0644 \u0648\u0638\u064A\u0641\u0629 \u0648\u0645\u062A\u063A\u064A\u0631 \u0648\u0633\u0637\u0631 \u0645\u0646\u0637\u0642\u064A \u0642\u0627\u0628\u0644 \u0644\u0644\u0642\u0631\u0627\u0621\u0629 \u0639\u0644\u0646\u0627\u064B\n\u2022 \u0644\u0627 \u062A\u0648\u062C\u062F \u0648\u0638\u0627\u0626\u0641 \u0645\u062E\u0641\u064A\u0629\u060C \u0648\u0644\u0627 \u0639\u0642\u0648\u062F \u0648\u0643\u064A\u0644\u0629\u060C \u0648\u0644\u0627 \u062A\u0634\u0648\u064A\u0634\n\u2022 \u064A\u0645\u0643\u0646 \u0644\u0623\u064A \u0634\u062E\u0635 \u0627\u0644\u062A\u062D\u0642\u0642 \u0628\u0634\u0643\u0644 \u0645\u0633\u062A\u0642\u0644 \u0645\u0646 \u0623\u0646 \u0627\u0644\u0639\u0642\u062F \u064A\u0639\u0645\u0644 \u0643\u0645\u0627 \u0647\u0648 \u0645\u0639\u0644\u0646\n\n\u{1F48E} \u0627\u0642\u0631\u0623 \u0627\u0644\u0643\u0648\u062F. \u062A\u062D\u0642\u0642 \u0645\u0646 \u0627\u0644\u0645\u0646\u0637\u0642. \u062B\u0642 \u0628\u0627\u0644\u0631\u064A\u0627\u0636\u064A\u0627\u062A\u060C \u0648\u0644\u064A\u0633 \u0628\u0627\u0644\u0643\u0644\u0645\u0627\u062A.\n\n\u{1F310} turboloop.io',
