      original: "62_Shabakat_Tafasil.png",
      headline: "\u{1F537} \u0634\u0628\u0643\u0629 \u0627\u0644\u0625\u062D\u0627\u0644\u0629 \u2014 \u0627\u0644\u062A\u0641\u0627\u0635\u064A\u0644",
      caption: "\u{1F537} \u0634\u0628\u0643\u0629 \u0627\u0644\u0625\u062D\u0627\u0644\u0629 \u2014 \u0627\u0644\u062A\u0641\u0627\u0635\u064A\u0644\n\u2726 \u0627\u0644\u0628\u0646\u064A\u0629 \u0627\u0644\u0643\u0627\u0645\u0644\u0629 \u0644\u0623\u0631\u0628\u0627\u062D \u0627\u0644\u0640 20 \u0645\u0633\u062A\u0648\u0649\n\n\u0634\u0628\u0643\u0629 \u0625\u062D\u0627\u0644\u0629 TurboLoop \u0647\u064A \u0628\u0646\u064A\u0629 \u0623\u0631\u0628\u0627\u062D \u0628\u0639\u0645\u0642 20 \u0645\u0633\u062A\u0648\u0649 \u0648\u0639\u0631\u0636 \u063A\u064A\u0631 \u0645\u062D\u062F\u0648\u062F \u062A\u0648\u0632\u0639 51% \u0645\u0646 \u0625\u064A\u062F\u0627\u0639\u0627\u062A \u0627\u0644\u0645\u064F\u062D\u0627\u0644\u064A\u0646 \u0639\u0644\u0649 \u0628\u0646\u0627\u0629 \u0627\u0644\u0634\u0628\u0643\u0629. \u0625\u0644\u064A\u0643 \u0627\u0644\u0628\u0646\u064A\u0629 \u0627\u0644\u0643\u0627\u0645\u0644\u0629: \u064A\u062A\u0645 \u0625\u0646\u0634\u0627\u0621 \u0631\u0627\u0628\u0637 \u0627\u0644\u0625\u062D\u0627\u0644\u0629 \u0627\u0644\u0641\u0631\u064A\u062F \u0627\u0644\u062E\u0627\u0635 \u0628\u0643 \u062A\u0644\u0642\u0627\u0626\u064A\u064B\u0627 \u0639\u0646\u062F \u0631\u0628\u0637 \u0645\u062D\u0641\u0638\u062A\u0643. \u0639\u0646\u062F\u0645\u0627 \u064A\u0646\u0636\u0645 \u0634\u062E\u0635 \u0645\u0627 \u0645\u0646 \u062E\u0644\u0627\u0644 \u0631\u0627\u0628\u0637\u0643 \u0648\u064A\u0642\u0648\u0645 \u0628\u0627\u0644\u0625\u064A\u062F\u0627\u0639\u060C \u062A\u0643\u0633\u0628 \u0639\u0645\u0648\u0644\u0629 \u0627\u0644\u0645\u0633\u062A\u0648\u0649 1 (12%) \u0639\u0644\u0649 \u0625\u064A\u062F\u0627\u0639\u0647. \u0639\u0646\u062F\u0645\u0627 \u064A\u0642\u0648\u0645\u0648\u0646 \u0628\u0625\u062D\u0627\u0644\u0629 \u0634\u062E\u0635 \u0645\u0627\u060C \u062A\u0643\u0633\u0628 \u0627\u0644\u0645\u0633\u062A\u0648\u0649 2 (8%). \u064A\u062A\u0633\u0644\u0633\u0644 \u0647\u0630\u0627 \u0639\u0628\u0631 \u062C\u0645\u064A\u0639 \u0627\u0644\u0645\u0633\u062A\u0648\u064A\u0627\u062A \u0627\u0644\u0640 20: L3 (5%)\u060C L4-5 (3% \u0644\u0643\u0644 \u0645\u0646\u0647\u0645\u0627)\u060C L6-10 (2% \u0644\u0643\u0644 \u0645\u0646\u0647\u0645\u0627)\u060C L11-20 (1% \u0644\u0643\u0644 \u0645\u0646\u0647\u0645\u0627). \u064A\u062A\u0645 \u062D\u0633\u0627\u0628 \u0627\u0644\u0639\u0645\u0648\u0644\u0627\u062A \u0648\u062A\u0648\u0632\u064A\u0639\u0647\u0627 \u064A\u0648\u0645\u064A\u064B\u0627 \u0628\u0648\u0627\u0633\u0637\u0629 Smart Contract \u2014 \u0644\u0627 \u064A\u0648\u062C\u062F \u062A\u062A\u0628\u0639 \u064A\u062F\u0648\u064A\u060C \u0648\u0644\u0627 \u0645\u062F\u0641\u0648\u0639\u0627\u062A \u0645\u062A\u0623\u062E\u0631\u0629. \u0644\u0627 \u064A\u0648\u062C\u062F \u062D\u062F \u0644\u0639\u062F\u062F \u0627\u0644\u0623\u0634\u062E\u0627\u0635 \u0627\u0644\u0630\u064A\u0646 \u064A\u0645\u0643\u0646\u0643 \u0625\u062D\u0627\u0644\u062A\u0647\u0645 \u0641\u064A \u0623\u064A \u0645\u0633\u062A\u0648\u0649\u060C \u0648\u062A\u0646\u0645\u0648 \u0627\u0644\u0634\u0628\u0643\u0629 \u0628\u0634\u0643\u0644 \u0639\u0636\u0648\u064A \u062D\u064A\u062B \u064A\u0628\u0646\u064A \u0643\u0644 \u0639\u0636\u0648 \u0634\u062C\u0631\u062A\u0647 \u0627\u0644\u062E\u0627\u0635\u0629.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 L1: 12% | L2: 8% | L3: 5% | L4-5: 3% \u0644\u0643\u0644 \u0645\u0646\u0647\u0645\u0627 = 31% (\u0623\u0639\u0644\u0649 5)\n\u2022 L6-10: 2% \u0644\u0643\u0644 \u0645\u0646\u0647\u0645\u0627 = 10% | L11-20: 1% \u0644\u0643\u0644 \u0645\u0646\u0647\u0645\u0627 = 10% (\u0639\u0645\u0642 15)\n\u2022 \u0627\u0644\u0625\u062C\u0645\u0627\u0644\u064A \u0627\u0644\u0643\u0644\u064A: 51% \u0639\u0628\u0631 \u062C\u0645\u064A\u0639 \u0627\u0644\u0645\u0633\u062A\u0648\u064A\u0627\u062A \u0627\u0644\u0640 20\n\u2022 \u0639\u0631\u0636 \u063A\u064A\u0631 \u0645\u062D\u062F\u0648\u062F \u0641\u064A \u0643\u0644 \u0645\u0633\u062A\u0648\u0649 \u2014 \u0644\u0627 \u062A\u0648\u062C\u062F \u062D\u062F\u0648\u062F \u0644\u0644\u0625\u062D\u0627\u0644\u0629\n\u2022 \u0645\u062F\u0641\u0648\u0639\u0627\u062A \u0639\u0645\u0648\u0644\u0629 \u064A\u0648\u0645\u064A\u0629 \u062A\u0644\u0642\u0627\u0626\u064A\u0629 \u0628\u0648\u0627\u0633\u0637\u0629 Smart Contract\n\n\u{1F48E} \u0631\u0627\u0628\u0637 \u0648\u0627\u062D\u062F. 20 \u0645\u0633\u062A\u0648\u0649. \u062A\u0648\u0632\u064A\u0639 51%. \u0627\u0628\u0646\u0650 \u0625\u0645\u0628\u0631\u0627\u0637\u0648\u0631\u064A\u062A\u0643.\n\n\u{1F310} turboloop.io",
